GAMIT_SOURCE = '#!/usr/bin/env python3\n"""\n=============================================================================\nAUTOM-GAMIT BEST V4 PER-DAY RINEX SAFE PROCESSOR - FINAL FRAME-CONSISTENT\n=============================================================================\n\nAll fixes applied:\n- Conditional tool checking (sh_get_rinex only when needed)\n- Support for .gz, .GZ, .Z, and long-name RINEX3\n- Safe .Z fallback (gzip -cd -> uncompress)\n- Lowercase normalization of local and global short-name RINEX filenames\n- Robust h-file station parser (uppercase, _GPS/_6PS/_5PS/_4PS)\n- Safer APR update line in process.defaults\n- Improved OTL grid resume logic\n- Reliable SOLVE Normal stop + h-file success check\n- Fast station.info easy manager + per-day clean RINEX sandbox\n- Correct GLOBK next-steps\n- Copy failure visible, IGS20 candidates reordered, APR conflict removal case-insensitive\n- Frame-consistent APR handling: selected family only in project tables\n- Consistent menu order: IGS20/ITRF2020, IGS14/ITRF2014, IGS08/ITRF2008\n- Productive-run orbit logic: online pre-download + sh_gamit -noftp default\n- Safe day-folder rerun: timestamped backup instead of destructive deletion\n- QC parser searches both DDD and DDDG day-folder styles\n- Explicit local RINEX3 sh_rename_rinex3 support with Python/manual fallback\n- EOP checks for pole.usno and ut1.usno before -noftp runs\n- Antenna-height zero decision menu for production safety\n- Method/implication stage gate before every processing section\n=============================================================================\n"""\n\nfrom __future__ import annotations\n\nimport gzip\nimport json\nimport os\nimport re\nimport shlex\nimport signal\nimport subprocess\nimport sys\nfrom datetime import datetime\nfrom pathlib import Path\nfrom typing import Dict, List, Tuple\n\n# =============================================================================\n# COLORS AND PRINT HELPERS\n# =============================================================================\nclass Colors:\n    RED = "\\033[91m"\n    GREEN = "\\033[92m"\n    YELLOW = "\\033[93m"\n    BLUE = "\\033[94m"\n    MAGENTA = "\\033[95m"\n    CYAN = "\\033[96m"\n    BOLD = "\\033[1m"\n    END = "\\033[0m"\n\ndef ctext(text: str, color: str) -> str:\n    return f"{color}{text}{Colors.END}"\n\ndef print_header(text: str) -> None:\n    print()\n    print(ctext("=" * 90, Colors.CYAN))\n    print(ctext(f"{text:^90}", Colors.CYAN + Colors.BOLD))\n    print(ctext("=" * 90, Colors.CYAN))\n\ndef print_info(text: str) -> None:\n    print(ctext(f"i  {text}", Colors.BLUE))\n\ndef print_success(text: str) -> None:\n    print(ctext(f"OK {text}", Colors.GREEN))\n\ndef print_warning(text: str) -> None:\n    print(ctext(f"WARNING {text}", Colors.YELLOW))\n\ndef print_error(text: str) -> None:\n    print(ctext(f"ERROR {text}", Colors.RED))\n\ndef print_progress(text: str) -> None:\n    print(ctext(f">> {text}", Colors.MAGENTA))\n\n\n# =============================================================================\n# METHOD / IMPLICATION STAGE GATES\n# =============================================================================\nSTAGE_DETAILS = {\n    "01_check_tools": {\n        "method": "Check that GAMIT/GLOBK commands and Linux helper tools are visible in PATH.",\n        "implication": "If a command is missing, later processing will fail even if the RINEX data are correct.",\n        "next": "Proceed only when sh_gamit, sh_setup, sh_upd_stnfo, crx2rnx, curl, tcsh/csh, and plotting helpers are present."\n    },\n    "02_auth": {\n        "method": "Verify Earthdata/CDDIS authentication files: ~/.netrc and ~/.urs_cookies.",\n        "implication": "Online downloads of SP3, IONEX, BRDC, and reference RINEX depend on valid authentication.",\n        "next": "Proceed only when .netrc is found and has permission 600."\n    },\n    "03_create_project": {\n        "method": "Create or refresh the project directory and required subfolders: rinex, brdc, igs, ionex, raw, mkrinex, control.",\n        "implication": "A fresh project backs up the previous folder; no old products or day folders should silently mix with the new run.",\n        "next": "Proceed after confirming the project folder name and backup behavior are correct."\n    },\n    "04_copy_rinex": {\n        "method": "Copy local CORS RINEX, normalize names, decompress .gz/.Z, convert Hatanaka .d to .o, and handle local RINEX3.",\n        "implication": "Only readable short-name observation files can be linked by GAMIT reliably.",\n        "next": "Proceed when the day-wise file count matches the selected local stations."\n    },\n    "05_exclude_unselected_source_stations": {\n        "method": "Move excluded or partial stations out of the active rinex folder.",\n        "implication": "Partial stations can reduce solution quality or fail MAKEXP/AUTCLN; they are preserved in backup folders, not deleted.",\n        "next": "Proceed when the active local station list is exactly what you want to process."\n    },\n    "06_rename_selected_source_stations": {\n        "method": "Optionally rename station codes and update MARKER NAME in RINEX headers.",\n        "implication": "Use this only when the source station code is truly wrong; never rename a station to itself.",\n        "next": "Proceed when station codes in RINEX, sites.defaults, station.info, and lfile will be consistent."\n    },\n    "07_sh_setup": {\n        "method": "Run sh_setup to create the GAMIT tables folder and copy standard control files.",\n        "implication": "This establishes the processing template. A wrong frame/APR here can contaminate later results.",\n        "next": "Proceed when tables/ exists and the selected APR family is present."\n    },\n    "08_apr": {\n        "method": "Create the custom APR, remove conflicting local entries, and patch process.defaults paths and APR settings.",\n        "implication": "The custom APR is the source of truth for initial coordinates; process.defaults tells GAMIT where products and RINEX are.",\n        "next": "Proceed when process.defaults points to the project folders and custom APR."\n    },\n    "09_sites_defaults": {\n        "method": "Write sites.defaults with reference stations as ftprnx and local CORS as localrx.",\n        "implication": "This controls which RINEX GAMIT expects and whether a station is reference/global or local/solved.",\n        "next": "Proceed when all selected local RINEX files are confirmed present."\n    },\n    "10_lfile": {\n        "method": "Append local station approximate XYZ from RINEX headers into lfile.",\n        "implication": "These are starting coordinates only. They are not final coordinates and their velocity columns are kept zero.",\n        "next": "Proceed when every local station appears in lfile."\n    },\n    "11_station_info": {\n        "method": "Build station.info from selected reference list and selected local RINEX headers using sh_upd_stnfo.",\n        "implication": "Receiver, antenna, marker, interval, and antenna-height metadata enter the GAMIT modeling here.",\n        "next": "Proceed only after reviewing marker mismatch and antenna-height warnings."\n    },\n    "12_otl": {\n        "method": "Verify ocean tide loading grid/list/cmc files and patch sestbl. to use otl.grid.",\n        "implication": "Without readable OTL files, sh_gamit can stop with ocean-loading fatal errors.",\n        "next": "Proceed when otl.grid, otl.list, and otlcmc.dat links resolve correctly."\n    },\n    "13_products": {\n        "method": "Download or verify final SP3 orbit, IONEX GIM, BRDC navigation, pole.usno, and ut1.usno for this DOY.",\n        "implication": "In the recommended mode Python downloads these first, then sh_gamit runs with -noftp to avoid internal FTP/CDDIS loops.",\n        "next": "Proceed when gzip tests and end-of-file checks pass for SP3/IONEX/BRDC."\n    },\n    "14_global_rinex": {\n        "method": "Download/check reference IGS RINEX for this DOY, convert RINEX3 CRX/RNX to short-name .o, and update active reference sites.",\n        "implication": "Only actually available reference stations are kept in sites.defaults for that day.",\n        "next": "Proceed when at least three reference stations are ready; more is better."\n    },\n    "15_gamit": {\n        "method": "Run sh_gamit for the current DOY using -pres ELEV and, in recommended mode, -orbit igsf -noftp.",\n        "implication": "The command preview must show -noftp in recommended mode; otherwise GAMIT may start internal downloads for DOY-1 and appear stuck.",\n        "next": "Proceed when SOLVE Normal stop and a real h-file h*.YYDOY are created."\n    },\n    "16_qc": {\n        "method": "Read summary, autcln, q-file/h-file clues, RMS, postfit NRMS, local station presence, and lfile update warnings.",\n        "implication": "A run can finish but still be scientifically weak; QC decides whether to continue to the next day or rerun/correct inputs.",\n        "next": "Proceed to the next DOY only when QC is acceptable or the issue is intentionally accepted for demo."\n    },\n}\n\n\ndef stage_key(step_name: str) -> str:\n    for key in sorted(STAGE_DETAILS, key=len, reverse=True):\n        if step_name.startswith(key):\n            return key\n    return step_name\n\n\ndef print_stage_method(step_name: str, settings: Dict[str, str] | None = None) -> None:\n    key = stage_key(step_name)\n    info = STAGE_DETAILS.get(key, {\n        "method": "Run this processing section and save its log.",\n        "implication": "Review warnings before moving ahead.",\n        "next": "Proceed when the section completes without critical error."\n    })\n    print_header(f"METHOD AND IMPLICATION BEFORE STAGE: {step_name}")\n    print_info("Method: " + info["method"])\n    print_info("Implication: " + info["implication"])\n    print_info("Proceed condition: " + info["next"])\n    if settings:\n        mode = settings.get("GAMIT_ORBIT_MODE", "")\n        if mode:\n            print_info("Current orbit/product mode: " + mode)\n        if step_name.startswith("15_gamit") and mode == "PREFETCH_IGSF_NOFTP":\n            print_success("Expected sh_gamit preview must include: -orbit igsf -noftp -pres ELEV")\n\n\ndef stage_control_before(step_name: str, settings: Dict[str, str] | None = None) -> None:\n    if os.environ.get("AUTOM_GAMIT_AUTO_STAGE", "0") == "1":\n        print_stage_method(step_name, settings)\n        return\n    while True:\n        print_stage_method(step_name, settings)\n        ans = input(ctext("Stage control: p = proceed, e = explain again, q = quit [p]: ", Colors.CYAN)).strip().lower()\n        if ans == "":\n            ans = "p"\n        if ans == "p":\n            return\n        if ans == "e":\n            continue\n        if ans == "q":\n            print_warning("Stopped by user before starting this stage.")\n            sys.exit(0)\n        print("Please enter p, e, or q.")\n\n\ndef stage_control_after(step_name: str, settings: Dict[str, str] | None = None) -> None:\n    if os.environ.get("AUTOM_GAMIT_AUTO_STAGE", "0") == "1":\n        return\n    key = stage_key(step_name)\n    info = STAGE_DETAILS.get(key)\n    while True:\n        if info:\n            print_header(f"STAGE COMPLETE: {step_name}")\n            print_success("Completed stage: " + step_name)\n            print_info("Before next stage: " + info["next"])\n        ans = input(ctext("Next control: n = next stage, e = explain this stage again, q = stop here [n]: ", Colors.CYAN)).strip().lower()\n        if ans == "":\n            ans = "n"\n        if ans == "n":\n            return\n        if ans == "e":\n            print_stage_method(step_name, settings)\n            continue\n        if ans == "q":\n            print_warning("Stopped by user after this stage. You can restart later and reuse/downloaded files if project is preserved.")\n            sys.exit(0)\n        print("Please enter n, e, or q.")\n\n\ndef print_overall_method() -> None:\n    print_header("OVERALL METHOD BEFORE PROCESSING")\n    print_info("1. Inspect local RINEX first, then decide stations; the program should not guess silently.")\n    print_info("2. Prepare products and reference RINEX before GAMIT; recommended mode then runs sh_gamit with -noftp.")\n    print_info("3. Run one day first, check h-file, SOLVE Normal stop, RMS/NRMS, then continue to more days.")\n    print_info("4. Every section now explains method, implication, and proceed condition before execution.")\n    print_info("Set AUTOM_GAMIT_AUTO_STAGE=1 if you want to skip the stage-by-stage pause after you trust the run.")\n\n\n# =============================================================================\n# OPTIONAL CONFIG / NON-INTERACTIVE PROFILE SUPPORT\n# =============================================================================\nCONFIG_DEFAULTS: Dict[str, object] = {}\n\n\ndef _cfg_key(text: str) -> str:\n    return re.sub(r"[^a-z0-9]+", "_", text.lower()).strip("_")\n\n\ndef load_runtime_config_from_argv() -> None:\n    """Load optional JSON config using --config FILE.\n\n    Keys may be exact prompt strings or normalized forms. Choice values may be\n    1-based integers or text contained in the option. Set auto_stage=true to\n    skip stage pauses; set non_interactive=true to accept defaults for prompts\n    not supplied in the config.\n    """\n    global CONFIG_DEFAULTS\n    args = sys.argv[1:]\n    cfg_path = None\n    if "--config" in args:\n        i = args.index("--config")\n        if i + 1 < len(args):\n            cfg_path = args[i + 1]\n    for a in args:\n        if a.startswith("--config="):\n            cfg_path = a.split("=", 1)[1]\n    if not cfg_path:\n        return\n    p = Path(os.path.expandvars(cfg_path)).expanduser()\n    if not p.is_file():\n        print_error(f"Config file not found: {p}")\n        sys.exit(1)\n    try:\n        raw = json.loads(p.read_text(encoding="utf-8"))\n    except Exception as e:\n        print_error(f"Could not read JSON config {p}: {e}")\n        sys.exit(1)\n    CONFIG_DEFAULTS = dict(raw)\n    for k, v in list(raw.items()):\n        CONFIG_DEFAULTS.setdefault(_cfg_key(k), v)\n    if str(CONFIG_DEFAULTS.get("auto_stage", "")).lower() in ("1", "true", "yes", "y"):\n        os.environ["AUTOM_GAMIT_AUTO_STAGE"] = "1"\n    if str(CONFIG_DEFAULTS.get("dry_run", "")).lower() in ("1", "true", "yes", "y"):\n        os.environ["AUTOM_GAMIT_DRY_RUN"] = "1"\n    print_success(f"Loaded JSON config profile: {p}")\n\n\ndef get_config_value(prompt: str, default: object | None = None) -> object | None:\n    if not CONFIG_DEFAULTS:\n        return None\n    for key in (prompt, _cfg_key(prompt)):\n        if key in CONFIG_DEFAULTS:\n            return CONFIG_DEFAULTS[key]\n    return None\n\n\ndef is_non_interactive_config() -> bool:\n    val = CONFIG_DEFAULTS.get("non_interactive", os.environ.get("AUTOM_GAMIT_NONINTERACTIVE", "0"))\n    return str(val).lower() in ("1", "true", "yes", "y")\n\n\ndef write_template_config(path: str = "gamit_config_template.json") -> None:\n    template = {\n        "Path to local/source RINEX files": "/home/geodesy/Documents/cors-rinex",\n        "Year": "2026",\n        "Start DOY to inspect/process": "091",\n        "Number of days to inspect in RINEX table": "5",\n        "GAMIT experiment code, 4 characters": "cors",\n        "Project folder name": "cors2026",\n        "IGS/reference stations": "badg bhr4 daej dgar djig iisc mal2 ntus pol2 reun xmis",\n        "Process only ONE day first for testing?": True,\n        "Fresh project? YES backs up old project folder": False,\n        "Download/check IGS RINEX automatically?": True,\n        "Choose sh_gamit orbit/product mode": 1,\n        "Pause before/after every processing stage for explanation?": True,\n        "auto_stage": False,\n        "non_interactive": False,\n        "dry_run": False,\n        "notes": "Choice values are 1-based. Orbit mode 1 is recommended: pre-download products/RINEX, then sh_gamit -noftp."\n    }\n    p = Path(path).expanduser()\n    p.write_text(json.dumps(template, indent=2), encoding="utf-8")\n    print_success(f"Template config written: {p}")\n\n# =============================================================================\n# INPUT HELPERS\n# =============================================================================\ndef ask_yes_no(question: str, default: str = "yes") -> bool:\n    cfg = get_config_value(question)\n    if cfg is not None:\n        ans = str(cfg).strip().lower()\n        val = ans in ("1", "true", "yes", "y")\n        print(ctext(f"{question} [config]: {\'yes\' if val else \'no\'}", Colors.CYAN))\n        return val\n    default = default.lower().strip()\n    prompt = "[Y/n]" if default == "yes" else "[y/N]"\n    if is_non_interactive_config():\n        val = default == "yes"\n        print(ctext(f"{question} {prompt}: {\'yes\' if val else \'no\'}  [non-interactive default]", Colors.CYAN))\n        return val\n    while True:\n        ans = input(ctext(f"{question} {prompt}: ", Colors.CYAN)).strip().lower()\n        if ans == "":\n            return default == "yes"\n        if ans in ("y", "yes"):\n            return True\n        if ans in ("n", "no"):\n            return False\n        print("Please answer yes or no.")\n\n\ndef ask_input(prompt: str, default: str = "") -> str:\n    cfg = get_config_value(prompt)\n    if cfg is not None:\n        val = str(cfg)\n        print(ctext(f"{prompt} [config]: {val}", Colors.CYAN))\n        return val\n    if is_non_interactive_config():\n        print(ctext(f"{prompt} [{default}]: {default}  [non-interactive default]", Colors.CYAN))\n        return default\n    if default != "":\n        ans = input(ctext(f"{prompt} [{default}]: ", Colors.CYAN)).strip()\n        return ans if ans != "" else default\n    return input(ctext(f"{prompt}: ", Colors.CYAN)).strip()\n\n\ndef ask_choice_index(question: str, options: List[str], default_index: int = 0) -> int:\n    print(ctext(question, Colors.CYAN))\n    for i, option in enumerate(options, 1):\n        marker = " [default]" if i - 1 == default_index else ""\n        print(f"  {ctext(str(i)+\'.\', Colors.YELLOW)} {option}{marker}")\n    cfg = get_config_value(question)\n    if cfg is not None:\n        raw = str(cfg).strip()\n        if raw.isdigit() and 1 <= int(raw) <= len(options):\n            idx = int(raw) - 1\n            print(ctext(f"Selected by config: {idx+1}", Colors.CYAN))\n            return idx\n        raw_l = raw.lower()\n        for i, option in enumerate(options):\n            if raw_l in option.lower():\n                print(ctext(f"Selected by config: {i+1}", Colors.CYAN))\n                return i\n        print_warning(f"Config choice for \'{question}\' not recognized; using default.")\n        return default_index\n    if is_non_interactive_config():\n        print(ctext(f"Enter choice (1-{len(options)}) [{default_index+1}]: {default_index+1}  [non-interactive default]", Colors.CYAN))\n        return default_index\n    while True:\n        ans = input(ctext(f"Enter choice (1-{len(options)}) [{default_index+1}]: ", Colors.CYAN)).strip()\n        if ans == "":\n            return default_index\n        if ans.isdigit() and 1 <= int(ans) <= len(options):\n            return int(ans) - 1\n        print(f"Please enter a number from 1 to {len(options)}.")\n\n\ndef ask_retry_continue_quit() -> str:\n    while True:\n        if is_non_interactive_config():\n            return "q"\n        ans = input(ctext("Choose: r = retry, c = continue anyway, q = quit [q]: ", Colors.CYAN)).strip().lower()\n        if ans == "":\n            ans = "q"\n        if ans in ("r", "c", "q"):\n            return ans\n        print("Please enter r, c, or q.")\n\n\ndef q(value: object) -> str:\n    return shlex.quote(str(value))\n\ndef norm_sites(text: str) -> str:\n    return " ".join(text.lower().split())\n\ndef norm_doy(text: str) -> str:\n    return text.strip().zfill(3)\n\ndef station_list(text: str) -> List[str]:\n    return [s for s in norm_sites(text).split() if s]\n\ndef parse_rename_pairs(text: str) -> List[Tuple[str, str]]:\n    pairs: List[Tuple[str, str]] = []\n    for item in norm_sites(text).split():\n        if ":" not in item:\n            continue\n        old, new = item.split(":", 1)\n        if old and new:\n            pairs.append((old, new))\n    return pairs\n\ndef validate_station_code(site: str) -> bool:\n    return len(site) == 4 and site == site.lower() and site.isalnum()\n\n# =============================================================================\n# Path Normalizer\n# =============================================================================\ndef normalize_input_path(text: str) -> str:\n    text = text.strip().strip(\'"\').strip("\'")\n    if text.startswith("home/"):\n        text = "/" + text\n    return str(Path(os.path.expandvars(text)).expanduser())\n\n\ndef canonical_frame_family(name: str) -> str:\n    """Normalize legacy aliases to one menu family name."""\n    n = (name or "").upper()\n    if n in ("IGS20", "ITRF20", "ITRF2020"):\n        return "IGS20"\n    if n in ("IGS14", "ITRF14", "ITRF2014"):\n        return "IGS14"\n    if n in ("IGS08", "ITRF08", "ITRF2008"):\n        return "IGS08"\n    return n or "UNKNOWN"\n\n\ndef apr_family_from_name(apr_file: str) -> str:\n    """Return IGS20, IGS14, or IGS08 from APR filename."""\n    name = Path(apr_file).name.lower()\n    if any(tok in name for tok in ["igs20", "igb20", "igc20", "itrf20", "custom_igs20"]):\n        return "IGS20"\n    if any(tok in name for tok in ["igs14", "igb14", "itrf14", "all_pbo_igs14", "all_pbo_nam14", "custom_igs14"]):\n        return "IGS14"\n    if any(tok in name for tok in ["igs08", "igb08", "itrf08", "all_pbo_igs08", "all_pbo_nam08", "custom_igs08", "custom_itrf08"]):\n        return "IGS08"\n    return "UNKNOWN"\n\n\ndef apr_matches_frame_name(ref_frame: str, apr_file: str) -> bool:\n    fam = apr_family_from_name(apr_file)\n    return canonical_frame_family(fam) == canonical_frame_family(ref_frame)\n\ndef validate_settings(settings: Dict[str, str]) -> bool:\n    errors: List[str] = []\n    year = settings["YEAR"]\n    yy = settings["YY"]\n    if not (year.isdigit() and len(year) == 4):\n        errors.append("YEAR must be 4 digits")\n    if not (yy.isdigit() and len(yy) == 2):\n        errors.append("YY must be 2 digits")\n    if year[-2:] != yy:\n        errors.append("YEAR and YY do not match")\n    expt = settings["EXPT"]\n    if not (len(expt) == 4 and expt.isalnum()):\n        errors.append("EXPT must be exactly 4 alphanumeric characters")\n    try:\n        s = int(settings["START_DOY"])\n        n = int(settings["NDAYS"])\n        if s < 1 or s > 366:\n            errors.append("START_DOY must be between 001 and 366")\n        if n < 1:\n            errors.append("NDAYS must be at least 1")\n        if s + n - 1 > 366:\n            errors.append("START_DOY + NDAYS exceeds 366")\n    except ValueError:\n        errors.append("START_DOY and NDAYS must be numeric")\n    for key in ["LOCAL_SITES", "IGS_SITES", "EXCLUDE_SITES"]:\n        for site in station_list(settings.get(key, "")):\n            if not validate_station_code(site):\n                errors.append(f"{key} has invalid station code: {site}")\n    local = set(station_list(settings["LOCAL_SITES"]))\n    igs = set(station_list(settings["IGS_SITES"]))\n    overlap = local & igs\n    if overlap:\n        errors.append("Station appears in both LOCAL_SITES and IGS_SITES: " + " ".join(sorted(overlap)))\n    for old, new in parse_rename_pairs(settings.get("RENAME_PAIRS", "")):\n        if not validate_station_code(old) or not validate_station_code(new):\n            errors.append(f"Invalid rename pair: {old}:{new}")\n        if old == new:\n            errors.append(f"Invalid rename pair, old and new same: {old}:{new}")\n        if new in igs:\n            errors.append(f"New station name conflicts with IGS list: {new}")\n    apr_file = settings.get("APR_FILE", "")\n    if not apr_file.endswith(".apr"):\n        errors.append("APR_FILE should end with .apr")\n    if "/" in apr_file:\n        errors.append("APR_FILE should be file name only")\n    if apr_file and not (Path.home() / "gg" / "tables" / apr_file).is_file():\n        errors.append(f"APR file not found in ~/gg/tables/: {apr_file}")\n    ref_frame = settings.get("REF_FRAME", "")\n    if apr_file and ref_frame and not apr_matches_frame_name(ref_frame, apr_file):\n        errors.append(f"APR file/frame mismatch: REF_FRAME={ref_frame}, APR_FILE={apr_file}. Choose matching APR family.")\n    custom = settings.get("CUSTOM_APR_FILE", "")\n    if not custom.endswith(".apr"):\n        errors.append("CUSTOM_APR_FILE should end with .apr")\n    if "/" in custom:\n        errors.append("CUSTOM_APR_FILE should be file name only")\n    if apr_file == custom:\n        errors.append("APR_FILE and CUSTOM_APR_FILE must not be same")\n    if settings.get("NOFTP_FLAG", "") not in ("", "-noftp"):\n        errors.append(\'NOFTP_FLAG must be blank or "-noftp"\')\n    for key in ["FRESH_START", "DOWNLOAD_GLOBAL_RINEX", "STRICT_NOFTP_CHECK", "RENAME_SITE"]:\n        if settings.get(key, "NO") not in ("YES", "NO"):\n            errors.append(f"{key} must be YES or NO")\n    if errors:\n        print_header("SETTING ERRORS")\n        for e in errors:\n            print_error(e)\n        return False\n    return True\n\n# =============================================================================\n# RINEX SCAN AND METADATA - Supports uppercase .GZ\n# =============================================================================\ndef strip_rinex_suffix(name: str, yy: str) -> str | None:\n    suffixes = [\n        f".{yy}o.gz", f".{yy}o.GZ", f".{yy}o.Z", f".{yy}o",\n        f".{yy}d.gz", f".{yy}d.GZ", f".{yy}d.Z", f".{yy}d",\n    ]\n    for suf in suffixes:\n        if name.endswith(suf):\n            return name[:-len(suf)]\n    return None\n\ndef scan_rinex_files(rinex_dir: str, yy: str) -> Tuple[List[str], Dict[str, dict]]:\n    """Scan short RINEX2 and long RINEX3/RNX/CRX filenames before any conversion.\n\n    This fixes a practical issue in earlier versions: the data-first menu could say\n    "No RINEX files found" when the folder contained only RINEX3 long filenames.\n    """\n    path = Path(rinex_dir).expanduser()\n    if not path.is_dir():\n        return [], {}\n\n    files: List[Path] = []\n    # Short RINEX2 observation/Hatanaka names.\n    for pat in [\n        f"*.{yy}o", f"*.{yy}o.gz", f"*.{yy}o.GZ", f"*.{yy}o.Z",\n        f"*.{yy}d", f"*.{yy}d.gz", f"*.{yy}d.GZ", f"*.{yy}d.Z",\n    ]:\n        files.extend(path.glob(pat))\n\n    # Long RINEX3 names, compressed and uncompressed. This is only for scanning;\n    # get_copy_rinex_step later renames/converts them safely.\n    year_guess = ""\n    # Try to infer full year from YY in current century.\n    try:\n        year_guess = f"20{int(yy):02d}"\n    except Exception:\n        year_guess = ""\n    rinex3_patterns = [\n        "*.rnx", "*.RNX", "*.rnx.gz", "*.RNX.gz", "*.rnx.GZ", "*.RNX.GZ",\n        "*.crx", "*.CRX", "*.crx.gz", "*.CRX.gz", "*.crx.GZ", "*.CRX.GZ",\n    ]\n    for pat in rinex3_patterns:\n        files.extend(path.glob(pat))\n\n    station_info: Dict[str, dict] = {}\n\n    def add_file(station: str, doy: str, f: Path) -> None:\n        station = station.lower()\n        if not validate_station_code(station):\n            return\n        if not (doy.isdigit() and len(doy) == 3):\n            return\n        station_info.setdefault(station, {"files": [], "doys": set(), "sample_file": None})\n        station_info[station]["files"].append(str(f))\n        station_info[station]["doys"].add(doy)\n        if station_info[station]["sample_file"] is None or f.name.endswith(f".{yy}o") or f.suffix.lower() in (".rnx", ".crx"):\n            station_info[station]["sample_file"] = str(f)\n\n    for f in sorted(set(files)):\n        name = f.name\n\n        # Short RINEX2 style: abcdDDD0.YYo / abcdDDD0.YYd\n        core = strip_rinex_suffix(name, yy)\n        if core is not None and len(core) >= 7:\n            add_file(core[:4], core[4:7], f)\n            continue\n\n        # Long RINEX3 style: ABCD00XXX_R_YYYYDDD0000_...\n        m = re.search(r"^([A-Za-z0-9]{4}).*?_(20\\d{2})(\\d{3})\\d{4}_", name)\n        if not m:\n            # More forgiving fallback: first four chars plus any YYYYDDD token.\n            m2 = re.search(r"(20\\d{2})(\\d{3})", name)\n            if m2 and len(name) >= 4:\n                add_file(name[:4], m2.group(2), f)\n            continue\n        add_file(m.group(1), m.group(3), f)\n\n    for st in station_info:\n        station_info[st]["files"] = sorted(set(station_info[st]["files"]))\n        station_info[st]["doy_count"] = len(station_info[st]["doys"])\n    return sorted(station_info.keys()), station_info\n\ndef open_text_maybe_gzip(file_path: str):\n    if file_path.endswith(".gz") or file_path.endswith(".GZ"):\n        return gzip.open(file_path, "rt", errors="ignore")\n    return open(file_path, "r", errors="ignore")\n\nRINEX_METADATA_CACHE: Dict[Tuple[str, int, int], Dict[str, object]] = {}\n\ndef read_rinex_metadata(file_path: str) -> Dict[str, object]:\n    """Read RINEX metadata once per file and reuse it inside the same run."""\n    try:\n        p = Path(file_path)\n        st = p.stat()\n        cache_key = (str(p), int(st.st_mtime), int(st.st_size))\n        if cache_key in RINEX_METADATA_CACHE:\n            return dict(RINEX_METADATA_CACHE[cache_key])\n    except Exception:\n        cache_key = None\n\n    metadata: Dict[str, object] = {\n        "marker": "Unknown",\n        "receiver": "Unknown",\n        "antenna": "Unknown",\n        "ant_height": "Unknown",\n        "interval": "Unknown",\n        "num_epochs": 0,\n        "approx_xyz": None,\n        "first_epoch": None,\n        "last_epoch": None,\n        "data_complete": False,\n        "readable": False,\n    }\n    if re.search(r"\\.\\d\\dd(\\.gz|\\.GZ|\\.Z)?$", file_path):\n        metadata["marker"] = "Hatanaka file - will convert later"\n        if cache_key is not None:\n            RINEX_METADATA_CACHE[cache_key] = dict(metadata)\n        return metadata\n    if file_path.endswith(".Z"):\n        metadata["marker"] = "Compressed .Z file - will uncompress later"\n        if cache_key is not None:\n            RINEX_METADATA_CACHE[cache_key] = dict(metadata)\n        return metadata\n    try:\n        with open_text_maybe_gzip(file_path) as f:\n            in_header = True\n            for line in f:\n                if in_header:\n                    if "MARKER NAME" in line:\n                        metadata["marker"] = line[:60].strip()\n                    elif "REC # / TYPE / VERS" in line:\n                        metadata["receiver"] = line[:60].strip()\n                    elif "ANT # / TYPE" in line:\n                        metadata["antenna"] = line[:60].strip()\n                    elif "ANTENNA: DELTA H/E/N" in line:\n                        parts = line[:60].split()\n                        if parts:\n                            metadata["ant_height"] = parts[0]\n                    elif "INTERVAL" in line:\n                        metadata["interval"] = line[:20].strip()\n                    elif "APPROX POSITION XYZ" in line:\n                        parts = line[:60].split()\n                        if len(parts) >= 3:\n                            metadata["approx_xyz"] = parts[:3]\n                    elif "END OF HEADER" in line:\n                        in_header = False\n                    continue\n                m3 = re.match(r"^>\\s*(\\d{4})\\s+(\\d{1,2})\\s+(\\d{1,2})\\s+(\\d{1,2})\\s+(\\d{1,2})\\s+(\\d{1,2}(?:\\.\\d+)?)", line)\n                m2 = re.match(r"\\s*(\\d{2})\\s+(\\d{1,2})\\s+(\\d{1,2})\\s+(\\d{1,2})\\s+(\\d{1,2})\\s+(\\d{1,2}(?:\\.\\d+)?)", line)\n                if m3:\n                    y, mo, dd, hh, mi, _ss = m3.groups()\n                    epoch = f"{int(y):04d}-{int(mo):02d}-{int(dd):02d} {int(hh):02d}:{int(mi):02d}"\n                elif m2:\n                    yy2, mo, dd, hh, mi, _ss = m2.groups()\n                    epoch = f"{2000+int(yy2):04d}-{int(mo):02d}-{int(dd):02d} {int(hh):02d}:{int(mi):02d}"\n                else:\n                    continue\n                metadata["num_epochs"] = int(metadata["num_epochs"]) + 1\n                if metadata["first_epoch"] is None:\n                    metadata["first_epoch"] = epoch\n                metadata["last_epoch"] = epoch\n        metadata["readable"] = True\n        metadata["data_complete"] = int(metadata["num_epochs"]) >= 2500\n    except Exception as e:\n        metadata["marker"] = f"Could not read: {e}"\n    if cache_key is not None:\n        RINEX_METADATA_CACHE[cache_key] = dict(metadata)\n    return metadata\n\ndef show_station_summary(station_info: Dict[str, dict]) -> None:\n    print_header("STATION DATA SUMMARY")\n    print(f"{\'Station\':<8} {\'Files\':>5} {\'DOYs\':>5} {\'Epochs(sample)\':>15} {\'Quality\':>10} {\'First epoch\':<18} {\'Last epoch\':<18} {\'Receiver\':<25}")\n    print(ctext("-" * 115, Colors.CYAN))\n    for station in sorted(station_info):\n        info = station_info[station]\n        sample = info.get("sample_file")\n        md = read_rinex_metadata(sample) if sample else {}\n        epochs = md.get("num_epochs", 0)\n        quality = "OK" if md.get("data_complete") else "CHECK"\n        color = Colors.GREEN if quality == "OK" else Colors.YELLOW\n        first = str(md.get("first_epoch") or "N/A")[:16]\n        last = str(md.get("last_epoch") or "N/A")[:16]\n        receiver = str(md.get("receiver") or "Unknown")[:24]\n        print(f"{station:<8} {len(info[\'files\']):>5} {info[\'doy_count\']:>5} {epochs:>15} {ctext(f\'{quality:>10}\', color)} {first:<18} {last:<18} {receiver:<25}")\n    print(ctext("-" * 115, Colors.CYAN))\n    print_success(f"Total stations found: {len(station_info)}")\n\ndef show_station_details(station: str, station_info: Dict[str, dict]) -> None:\n    station = station.lower().strip()\n    if station not in station_info:\n        print_warning(f"Station not found: {station}")\n        return\n    info = station_info[station]\n    print_header(f"DETAILS FOR {station.upper()}")\n    for f in info["files"]:\n        md = read_rinex_metadata(f)\n        print(f"File       : {Path(f).name}")\n        print(f"Marker     : {md.get(\'marker\')}")\n        print(f"Receiver   : {md.get(\'receiver\')}")\n        print(f"Antenna    : {md.get(\'antenna\')}")\n        print(f"Interval   : {md.get(\'interval\')}")\n        print(f"Epochs     : {md.get(\'num_epochs\')}")\n        print(f"First/Last : {md.get(\'first_epoch\')}  ->  {md.get(\'last_epoch\')}")\n        print(f"Approx XYZ : {md.get(\'approx_xyz\')}")\n        print("-" * 80)\n\n# =============================================================================\n# APR HELPERS - Expanded candidates for all frames\n# =============================================================================\nAPR_CANDIDATES_BY_FRAME = {\n    "IGS20": [\n        "igb20_comb.apr",   # more common choice, placed first\n        "igs20_comb.apr",\n        "igs20.apr",\n        "igb20.apr",\n        "igc20.apr",\n        "itrf20f.apr",\n        "itrf20m.apr",\n        "itrf20u23f.apr",\n        "itrf20u23m.apr",\n        "itrf20u24f.apr",\n        "itrf20u24m.apr",\n    ],\n    "IGS14": [\n        "igs14_comb.apr",\n        "igb14_comb.apr",\n        "igb14.apr",\n        "itrf14.apr",\n        "itrf14_indi.apr",\n        "itrf14_noam.apr",\n        "itrf14_eura.apr",\n    ],\n    "IGS08": [\n        "igs08_comb.apr",\n        "igb08_comb.apr",\n        "itrf08_comb.apr",\n        "igs08.apr",\n        "igb08.apr",\n        "itrf08.apr",\n        "All_PBO_igs08.apr",\n    ],\n}\n\ndef auto_select_apr_file(ref_frame: str) -> str:\n    tables_dir = Path.home() / "gg" / "tables"\n    for fname in APR_CANDIDATES_BY_FRAME.get(ref_frame, []):\n        if (tables_dir / fname).is_file():\n            return fname\n    cand = APR_CANDIDATES_BY_FRAME.get(ref_frame, [])\n    return cand[0] if cand else ""\n\ndef show_available_apr_files() -> List[str]:\n    tables_dir = Path.home() / "gg" / "tables"\n    apr_files = sorted(tables_dir.glob("*.apr")) if tables_dir.is_dir() else []\n    print_header("AVAILABLE APR FILES")\n    if not apr_files:\n        print_warning("No APR files found in ~/gg/tables/")\n        return []\n    for f in apr_files:\n        print(f"  {f.name}")\n    return [f.name for f in apr_files]\n\ndef apr_has_station(apr_file: str, site: str) -> bool:\n    path = Path.home() / "gg" / "tables" / apr_file\n    site_u = site.upper()\n    if not path.is_file():\n        return False\n    try:\n        with open(path, "r", errors="ignore") as f:\n            for line in f:\n                # Case-insensitive comparison\n                first = (line.split()[0] if line.split() else "").upper()\n                if first in (site_u, f"{site_u}_GPS"):\n                    return True\n    except Exception:\n        return False\n    return False\n\ndef normalize_conflict_sites(conflict_text: str) -> str:\n    out = []\n    for c in conflict_text.upper().split():\n        c = c.strip()\n        if len(c) == 4 and c.isalnum():\n            c = f"{c}_GPS"\n        elif c.endswith("_GPS") and len(c) == 8 and c[:4].isalnum():\n            pass\n        else:\n            clean = c.replace("_GPS", "")\n            if len(clean) == 4 and clean.isalnum():\n                c = f"{clean}_GPS"\n            else:\n                continue\n        if c not in out:\n            out.append(c)\n    return " ".join(out)\n\n# =============================================================================\n# Conditional tool checking (sh_get_rinex only when needed) - includes \'file\'\n# and optional \'uncompress\' if .Z files present\n# =============================================================================\ndef get_check_tools_step() -> str:\n    return r\'\'\'\necho "Checking required commands..."\nmissing=0\nfor cmd in sh_gamit sh_setup sh_upd_stnfo curl gzip gunzip awk sed date python3 file\ndo\n  if command -v "$cmd" >/dev/null 2>&1; then\n    echo "[OK] $cmd found at $(command -v $cmd)"\n  else\n    echo "[MISSING] $cmd"\n    missing=1\n  fi\ndone\n\necho "Checking productive GAMIT/GLOBK helper commands..."\nfor cmd in solve autcln htoglb sh_glred globk glorg sh_exglk sh_org2vel\ndo\n  if command -v "$cmd" >/dev/null 2>&1; then\n    echo "[OK] $cmd found at $(command -v $cmd)"\n  else\n    echo "[WARNING] $cmd not found now; it is needed for full productive GAMIT/GLOBK or velocity workflow"\n  fi\ndone\n\necho "Checking Linux/WSL support and plotting helper commands..."\nfor cmd in make csh tcsh bc ps2pdf gs gmt timeout\ndo\n  if command -v "$cmd" >/dev/null 2>&1; then\n    echo "[OK] $cmd found at $(command -v $cmd)"\n  else\n    echo "[INFO] $cmd not found; install if your workflow needs compilation, shell support, timeouts, or plot/PDF viewing"\n  fi\ndone\n\nif find "$SOURCE_RINEX_DIR" -maxdepth 1 \\( -name "*.${YY}o.Z" -o -name "*.${YY}d.Z" \\) | grep -q .; then\n  if command -v uncompress >/dev/null 2>&1; then\n    echo "[OK] uncompress found at $(command -v uncompress)"\n  else\n    echo "[WARNING] uncompress not found; gzip -cd fallback will be used for .Z files"\n  fi\nfi\n\nif [ "$DOWNLOAD_GLOBAL_RINEX" = "YES" ] || [ "$GAMIT_ORBIT_MODE" = "INTERNET_IGSF" ]; then\n  if command -v sh_get_rinex >/dev/null 2>&1; then\n    echo "[OK] sh_get_rinex found at $(command -v sh_get_rinex)"\n  else\n    echo "[MISSING] sh_get_rinex is needed for automatic IGS RINEX download/prefetch"\n    missing=1\n  fi\nelse\n  echo "[INFO] sh_get_rinex not required for this run mode"\nfi\n\nif find "$SOURCE_RINEX_DIR" -maxdepth 1 \\( -name "*.${YY}d" -o -name "*.${YY}d.gz" -o -name "*.${YY}d.GZ" -o -name "*.${YY}d.Z" \\) | grep -q .; then\n  if command -v crx2rnx >/dev/null 2>&1; then\n    echo "[OK] crx2rnx found at $(command -v crx2rnx)"\n  else\n    echo "[MISSING] crx2rnx is needed because local Hatanaka files were found"\n    missing=1\n  fi\nfi\n\nif [ "$DOWNLOAD_GLOBAL_RINEX" = "YES" ]; then\n  if command -v crx2rnx >/dev/null 2>&1; then\n    echo "[OK] crx2rnx found at $(command -v crx2rnx)"\n  else\n    echo "[MISSING] crx2rnx may be needed if downloaded IGS files are Hatanaka compressed"\n    missing=1\n  fi\nfi\n\nif [ "$missing" -eq 1 ]; then\n  echo "Missing required tools. Check GAMIT/GLOBK PATH in ~/.bashrc and run: source ~/.bashrc"\n  exit 1\nfi\necho "All required tools are available for this run mode."\n\'\'\'\n\n\ndef get_auth_step() -> str:\n    return r\'\'\'\necho "Checking Earthdata/CDDIS authentication..."\nif [ -f "$HOME/.netrc" ]; then\n  chmod 600 "$HOME/.netrc"\n  echo "[OK] .netrc exists and permission set to 600"\n  echo "Machine entries:"\n  awk \'{for(i=1;i<=NF;i++) if($i=="machine") print "  "$(i+1)}\' "$HOME/.netrc" 2>/dev/null || true\n  for machine in urs.earthdata.nasa.gov gdc.cddis.eosdis.nasa.gov cddis.nasa.gov; do\n    if grep -Eq "^[[:space:]]*machine[[:space:]]+$machine([[:space:]]|$)" "$HOME/.netrc"; then\n      echo "[OK] .netrc has machine entry: $machine"\n    else\n      echo "[WARNING] .netrc missing machine entry: $machine"\n      echo "          Add if downloads/authentication fail: machine $machine login USER password PASS"\n    fi\n  done\nelse\n  echo "[WARNING] ~/.netrc not found. Downloads may fail."\n  if [ "$GAMIT_ORBIT_MODE" != "OFFLINE_IGSF" ] && [ "$GAMIT_ORBIT_MODE" != "OFFLINE_IGSG" ]; then\n    echo "Online/pre-download mode is selected, so ~/.netrc is required."\n    exit 1\n  fi\nfi\ntouch "$HOME/.urs_cookies"\nchmod 600 "$HOME/.urs_cookies"\necho "[OK] .urs_cookies ready"\nls -l "$HOME/.urs_cookies"\n\'\'\'\n\n\ndef get_create_project_step() -> str:\n    return r\'\'\'\necho "Creating/preparing project folder..."\ncd "$HOME" || exit 1\nif [ "$FRESH_START" = "YES" ] && [ -d "$PROJECT" ]; then\n  backup="${PROJECT}_old_$(date +%Y%m%d_%H%M%S)"\n  mv "$PROJECT" "$backup" || exit 1\n  echo "Existing project backed up as: $backup"\nfi\nmkdir -p "$PROJECT" || exit 1\ncd "$PROJECT" || exit 1\nmkdir -p rinex brdc igs ionex raw mkrinex control\necho "Project ready: $(pwd)"\nls -ld rinex brdc igs ionex raw mkrinex control\n\'\'\'\n\n# =============================================================================\n# FIXED: get_copy_rinex_step - safe .Z fallback + lowercase normalization\n# =============================================================================\ndef get_copy_rinex_step() -> str:\n    return r\'\'\'\necho "Copying local RINEX files from: $SOURCE_RINEX_DIR"\ncd "$HOME/$PROJECT" || exit 1\n\nif [ ! -d "$SOURCE_RINEX_DIR" ]; then\n  echo "Source RINEX directory not found: $SOURCE_RINEX_DIR"\n  exit 1\nfi\n\nshopt -s nullglob\nfiles=(\n  "$SOURCE_RINEX_DIR"/*.${YY}o\n  "$SOURCE_RINEX_DIR"/*.${YY}o.gz\n  "$SOURCE_RINEX_DIR"/*.${YY}o.GZ\n  "$SOURCE_RINEX_DIR"/*.${YY}o.Z\n  "$SOURCE_RINEX_DIR"/*.${YY}d\n  "$SOURCE_RINEX_DIR"/*.${YY}d.gz\n  "$SOURCE_RINEX_DIR"/*.${YY}d.GZ\n  "$SOURCE_RINEX_DIR"/*.${YY}d.Z\n  "$SOURCE_RINEX_DIR"/*${YEAR}*.rnx\n  "$SOURCE_RINEX_DIR"/*${YEAR}*.RNX\n  "$SOURCE_RINEX_DIR"/*${YEAR}*.rnx.gz\n  "$SOURCE_RINEX_DIR"/*${YEAR}*.RNX.gz\n  "$SOURCE_RINEX_DIR"/*${YEAR}*.rnx.GZ\n  "$SOURCE_RINEX_DIR"/*${YEAR}*.RNX.GZ\n  "$SOURCE_RINEX_DIR"/*${YEAR}*.crx\n  "$SOURCE_RINEX_DIR"/*${YEAR}*.CRX\n  "$SOURCE_RINEX_DIR"/*${YEAR}*.crx.gz\n  "$SOURCE_RINEX_DIR"/*${YEAR}*.CRX.gz\n  "$SOURCE_RINEX_DIR"/*${YEAR}*.crx.GZ\n  "$SOURCE_RINEX_DIR"/*${YEAR}*.CRX.GZ\n)\n\nif [ "${#files[@]}" -eq 0 ]; then\n  echo "No RINEX files found in source folder for year ${YEAR}/${YY}."\n  echo "Accepted examples: hyde0910.${YY}o, hyde0910.${YY}d.gz, HYDE00IND_R_${YEAR}0910000_01D_30S_MO.rnx.gz, or .crx.gz."\n  exit 1\nfi\n\n# Copy with error exit\ncp -f "${files[@]}" rinex/ || exit 1\n\ncd rinex || exit 1\n\n# Normalize first 4 characters of filenames to lowercase (case-insensitive safety)\necho "Normalizing first 4 characters of local RINEX filenames to lowercase..."\npython3 - << \'PY\'\nfrom pathlib import Path\nimport os\n\nyy = os.environ["YY"]\nsuffixes = [\n    f".{yy}o.gz", f".{yy}o.GZ", f".{yy}o.Z", f".{yy}o",\n    f".{yy}d.gz", f".{yy}d.GZ", f".{yy}d.Z", f".{yy}d",\n]\n\nfor p in sorted(Path(".").iterdir()):\n    if not p.is_file():\n        continue\n    name = p.name\n    matched = False\n    for suf in suffixes:\n        if name.endswith(suf) and len(name) >= 7 + len(suf):\n            matched = True\n            break\n    if not matched:\n        continue\n    new_name = name[:4].lower() + name[4:]\n    if new_name == name:\n        continue\n    target = p.with_name(new_name)\n    if target.exists():\n        print(f"ERROR: Cannot rename {name} -> {new_name}; target already exists")\n        raise SystemExit(1)\n    print(f"  {name} -> {new_name}")\n    p.rename(target)\nPY\n\n\n# Explicit local RINEX3 handling: prefer sh_rename_rinex3 for uncompressed .rnx,\n# then fall back to safe short-name conversion using first four filename chars.\necho "Handling local RINEX3 long filenames if present..."\nif command -v sh_rename_rinex3 >/dev/null 2>&1; then\n  for f in *${YEAR}*.rnx *${YEAR}*.RNX; do\n    [ -f "$f" ] || continue\n    echo "  sh_rename_rinex3 -f $f"\n    sh_rename_rinex3 -f "$f" || echo "  [WARNING] sh_rename_rinex3 failed for $f; Python/manual fallback will be tried."\n  done\nelse\n  echo "  sh_rename_rinex3 not found; using Python/manual fallback."\nfi\n\n# Manual fallback for compressed and uncompressed long-name RINEX3 RNX/CRX.\nfor f in *${YEAR}*.rnx.gz *${YEAR}*.RNX.gz *${YEAR}*.rnx.GZ *${YEAR}*.RNX.GZ; do\n  [ -f "$f" ] || continue\n  site=$(echo "$f" | cut -c1-4 | tr \'[:upper:]\' \'[:lower:]\')\n  doy=$(echo "$f" | grep -o "${YEAR}[0-9][0-9][0-9]" | head -1 | sed "s/${YEAR}//")\n  [ -n "$doy" ] || continue\n  ofile="${site}${doy}0.${YY}o"\n  [ -s "$ofile" ] && continue\n  gzip -t "$f" 2>/dev/null || { echo "  invalid gzip: $f"; exit 1; }\n  echo "  Long-name RNX.gz -> $ofile"\n  gunzip -c "$f" > "$ofile" || exit 1\n done\nfor f in *${YEAR}*.rnx *${YEAR}*.RNX; do\n  [ -f "$f" ] || continue\n  site=$(echo "$f" | cut -c1-4 | tr \'[:upper:]\' \'[:lower:]\')\n  doy=$(echo "$f" | grep -o "${YEAR}[0-9][0-9][0-9]" | head -1 | sed "s/${YEAR}//")\n  [ -n "$doy" ] || continue\n  ofile="${site}${doy}0.${YY}o"\n  [ -s "$ofile" ] && continue\n  echo "  Long-name RNX -> $ofile"\n  cp -f "$f" "$ofile" || exit 1\n done\nfor f in *${YEAR}*.crx.gz *${YEAR}*.CRX.gz *${YEAR}*.crx.GZ *${YEAR}*.CRX.GZ; do\n  [ -f "$f" ] || continue\n  site=$(echo "$f" | cut -c1-4 | tr \'[:upper:]\' \'[:lower:]\')\n  doy=$(echo "$f" | grep -o "${YEAR}[0-9][0-9][0-9]" | head -1 | sed "s/${YEAR}//")\n  [ -n "$doy" ] || continue\n  dfile="${site}${doy}0.${YY}d"\n  ofile="${site}${doy}0.${YY}o"\n  [ -s "$ofile" ] && continue\n  gzip -t "$f" 2>/dev/null || { echo "  invalid gzip: $f"; exit 1; }\n  echo "  Long-name CRX.gz -> $dfile -> $ofile"\n  gunzip -c "$f" > "$dfile" || exit 1\n  command -v crx2rnx >/dev/null 2>&1 || { echo "crx2rnx not found"; exit 1; }\n  crx2rnx "$dfile" || exit 1\n done\nfor f in *${YEAR}*.crx *${YEAR}*.CRX; do\n  [ -f "$f" ] || continue\n  site=$(echo "$f" | cut -c1-4 | tr \'[:upper:]\' \'[:lower:]\')\n  doy=$(echo "$f" | grep -o "${YEAR}[0-9][0-9][0-9]" | head -1 | sed "s/${YEAR}//")\n  [ -n "$doy" ] || continue\n  dfile="${site}${doy}0.${YY}d"\n  ofile="${site}${doy}0.${YY}o"\n  [ -s "$ofile" ] && continue\n  echo "  Long-name CRX -> $dfile -> $ofile"\n  cp -f "$f" "$dfile" || exit 1\n  command -v crx2rnx >/dev/null 2>&1 || { echo "crx2rnx not found"; exit 1; }\n  crx2rnx "$dfile" || exit 1\n done\n\n# Remove invalid local compressed files\necho "Checking compressed local RINEX files before uncompressing..."\nfor f in *.${YY}o.gz *.${YY}o.GZ *.${YY}o.Z *.${YY}d.gz *.${YY}d.GZ *.${YY}d.Z; do\n  [ -f "$f" ] || continue\n  if ! gzip -t "$f" 2>/dev/null && ! file "$f" | grep -q "compress\'d data"; then\n    echo "  Invalid/incomplete compressed file: $f"\n    echo "  Remove or re-download this file before processing."\n    exit 1\n  fi\ndone\n\n# Safe uncompression for observation files\necho "Uncompressing observation files if needed..."\nfor f in *.${YY}o.gz *.${YY}o.GZ *.${YY}o.Z; do\n  [ -f "$f" ] || continue\n  echo "  Uncompressing: $f"\n  if [[ "$f" == *.Z ]]; then\n    out="${f%.Z}"\n    gzip -cd "$f" > "$out" 2>/dev/null || uncompress -c "$f" > "$out" || exit 1\n  else\n    gunzip -k -f "$f" || exit 1\n  fi\ndone\n\n# Local Hatanaka conversion with fallback for .Z\necho "Converting local Hatanaka files if present..."\nfor f in *.${YY}d.gz *.${YY}d.GZ *.${YY}d.Z; do\n  [ -f "$f" ] || continue\n  dfile="${f%.*}"\n  echo "  Uncompressing Hatanaka: $f"\n  if [[ "$f" == *.Z ]]; then\n    gzip -cd "$f" > "$dfile" 2>/dev/null || uncompress -c "$f" > "$dfile" || exit 1\n  else\n    gunzip -c "$f" > "$dfile" || exit 1\n  fi\ndone\n\nfor f in *.${YY}d; do\n  [ -f "$f" ] || continue\n  if ! command -v crx2rnx >/dev/null 2>&1; then\n    echo "crx2rnx not found; cannot convert $f"\n    exit 1\n  fi\n  echo "  crx2rnx: $f"\n  crx2rnx "$f" || exit 1\ndone\n\ncd ..\n\necho "Active uncompressed RINEX count:"\nls rinex/*.${YY}o 2>/dev/null | wc -l\n\necho "Day-wise count for selected range:"\nEND_DOY=$((10#$START_DOY + NDAYS - 1))\nfor n in $(seq $((10#$START_DOY)) $END_DOY); do\n  doy=$(printf "%03d" "$n")\n  count=$(ls rinex/*${doy}0.${YY}o 2>/dev/null | wc -l)\n  echo "  DOY $doy : $count files"\ndone\n\'\'\'\n\ndef get_exclude_step() -> str:\n    return r\'\'\'\necho "Excluding source stations: $EXCLUDE_SITES"\ncd "$HOME/$PROJECT" || exit 1\nif [ -z "$EXCLUDE_SITES" ]; then\n  echo "No stations selected for exclusion."\n  exit 0\nfi\nfor ex in $EXCLUDE_SITES; do\n  mkdir -p "rinex_excluded_${ex}"\n  moved=0\n  for f in rinex/${ex}*.${YY}o rinex/${ex}*.${YY}o.gz rinex/${ex}*.${YY}o.GZ rinex/${ex}*.${YY}o.Z rinex/${ex}*.${YY}d rinex/${ex}*.${YY}d.gz rinex/${ex}*.${YY}d.GZ rinex/${ex}*.${YY}d.Z; do\n    [ -e "$f" ] || continue\n    mv "$f" "rinex_excluded_${ex}/"\n    moved=1\n  done\n  if [ "$moved" -eq 1 ]; then\n    echo "  Excluded: $ex"\n  else\n    echo "  No files found for: $ex"\n  fi\ndone\n\'\'\'\n\ndef get_rename_step() -> str:\n    return r\'\'\'\necho "Renaming stations..."\ncd "$HOME/$PROJECT" || exit 1\nif [ "$RENAME_SITE" != "YES" ] || [ -z "$RENAME_PAIRS" ]; then\n  echo "No rename requested."\n  exit 0\nfi\nfor pair in $RENAME_PAIRS; do\n  old=$(echo "$pair" | cut -d: -f1)\n  new=$(echo "$pair" | cut -d: -f2)\n  echo "------------------------------------------------------------"\n  echo "Rename: $old -> $new"\n  echo "------------------------------------------------------------"\n  if [ -z "$old" ] || [ -z "$new" ] || [ "$old" = "$new" ]; then\n    echo "Invalid rename pair: $pair"\n    exit 1\n  fi\n  mkdir -p "rinex_excluded_${old}_oldcode" "rinex_existing_${new}_before_rename"\n  NEWU=$(echo "$new" | tr \'[:lower:]\' \'[:upper:]\')\n  for f in rinex/${old}*.${YY}o; do\n    [ -f "$f" ] || continue\n    base=$(basename "$f")\n    newbase="${new}${base#$old}"\n    target="rinex/$newbase"\n    if [ -f "$target" ]; then\n      echo "  Target exists, backing up: $target"\n      mv "$target" "rinex_existing_${new}_before_rename/"\n    fi\n    echo "  Creating renamed RINEX: $target"\n    awk -v newmarker="$NEWU" \'\n      /MARKER NAME/ { printf "%-60s%-20s\\n", newmarker, "MARKER NAME"; next }\n      {print}\n    \' "$f" > "$target" || exit 1\n  done\n  mv rinex/${old}*.${YY}o "rinex_excluded_${old}_oldcode/" 2>/dev/null || true\n  mv rinex/${old}*.${YY}d "rinex_excluded_${old}_oldcode/" 2>/dev/null || true\n  mv rinex/${old}*.${YY}o.gz "rinex_excluded_${old}_oldcode/" 2>/dev/null || true\n  mv rinex/${old}*.${YY}o.GZ "rinex_excluded_${old}_oldcode/" 2>/dev/null || true\n  mv rinex/${old}*.${YY}o.Z "rinex_excluded_${old}_oldcode/" 2>/dev/null || true\n  mv rinex/${old}*.${YY}d.gz "rinex_excluded_${old}_oldcode/" 2>/dev/null || true\n  mv rinex/${old}*.${YY}d.GZ "rinex_excluded_${old}_oldcode/" 2>/dev/null || true\n  mv rinex/${old}*.${YY}d.Z "rinex_excluded_${old}_oldcode/" 2>/dev/null || true\n  echo "  Rename completed: $old -> $new"\ndone\necho "Final renamed files:"\nfor pair in $RENAME_PAIRS; do\n  new=$(echo "$pair" | cut -d: -f2)\n  ls -lh rinex/${new}*.${YY}o 2>/dev/null || true\ndone\n\'\'\'\n\ndef get_sh_setup_step() -> str:\n    return r\'\'\'\necho "Running sh_setup..."\ncd "$HOME/$PROJECT" || exit 1\nRAW_SH_SETUP_LOG="$HOME/$PROJECT/tables_sh_setup_raw_output.log"\necho "Trying sh_setup with explicit APR first: sh_setup -yr $YEAR -apr $APR_FILE"\nsh_setup -yr "$YEAR" -apr "$APR_FILE" > "$RAW_SH_SETUP_LOG" 2>&1\nrc=$?\nif [ "$rc" -ne 0 ]; then\n  echo "[WARNING] sh_setup -apr failed or is unsupported by this installation. Falling back to sh_setup -yr $YEAR"\n  echo "----- first sh_setup attempt tail -----" >> "$RAW_SH_SETUP_LOG"\n  tail -80 "$RAW_SH_SETUP_LOG" >> "$RAW_SH_SETUP_LOG" 2>/dev/null || true\n  sh_setup -yr "$YEAR" >> "$RAW_SH_SETUP_LOG" 2>&1\n  rc=$?\nfi\nif [ "$rc" -ne 0 ]; then\n  echo "sh_setup failed with return code $rc"\n  echo "Last 120 lines of raw sh_setup output:"\n  tail -120 "$RAW_SH_SETUP_LOG" || true\n  exit "$rc"\nfi\nif [ ! -d tables ]; then\n  echo "tables directory was not created"\n  echo "Last 120 lines of raw sh_setup output:"\n  tail -120 "$RAW_SH_SETUP_LOG" || true\n  exit 1\nfi\n\necho "sh_setup completed. Raw output saved to: $RAW_SH_SETUP_LOG"\necho "Cleaning any default APR copied by sh_setup that does not match selected family: $REF_FRAME"\n\napr_family_for_file() {\n  b=$(basename "$1" | tr \'[:upper:]\' \'[:lower:]\')\n  case "$b" in\n    *igs20*|*igb20*|*igc20*|*itrf20*|custom_igs20*) echo "IGS20" ;;\n    *igs14*|*igb14*|*itrf14*|*all_pbo_igs14*|*all_pbo_nam14*|custom_igs14*) echo "IGS14" ;;\n    *igs08*|*igb08*|*itrf08*|*all_pbo_igs08*|*all_pbo_nam08*|custom_igs08*|custom_itrf08*) echo "IGS08" ;;\n    *) echo "UNKNOWN" ;;\n  esac\n}\n\nfor f in tables/*.apr; do\n  [ -e "$f" ] || continue\n  fam=$(apr_family_for_file "$f")\n  base=$(basename "$f")\n  if [ "$base" = "$APR_FILE" ]; then\n    continue\n  fi\n  if [ "$fam" != "$REF_FRAME" ]; then\n    echo "  Removed non-selected APR from project tables: $base [$fam]"\n    rm -f "$f"\n  fi\ndone\n\nif [ ! -f "$HOME/gg/tables/$APR_FILE" ]; then\n  echo "Selected APR file missing from GAMIT tables: $HOME/gg/tables/$APR_FILE"\n  exit 1\nfi\ncp "$HOME/gg/tables/$APR_FILE" "tables/$APR_FILE" || exit 1\n\necho "Selected frame family: $REF_FRAME"\necho "Selected APR copied to project tables: tables/$APR_FILE"\necho "Tables created. Key files:"\nls -lh tables/station.info tables/sestbl. tables/sittbl. tables/autcln.cmd tables/process.defaults tables/sites.defaults tables/lfile. "tables/$APR_FILE" 2>/dev/null || true\n\'\'\'\n\n# =============================================================================\n# FIXED: get_apr_step - Safer APR update line and case-insensitive conflict removal\n# =============================================================================\ndef get_apr_step() -> str:\n    return r\'\'\'\necho "Configuring APR file..."\necho "REF_FRAME       : $REF_FRAME"\necho "APR_FILE        : $APR_FILE"\necho "CUSTOM_APR_FILE : $CUSTOM_APR_FILE"\necho "CONFLICT_SITE   : $CONFLICT_SITE"\n\ncd "$HOME/$PROJECT/tables" || exit 1\n\nif [ ! -f "$HOME/gg/tables/$APR_FILE" ]; then\n  echo "APR file not found: $HOME/gg/tables/$APR_FILE"\n  echo "Available APR files:"\n  ls "$HOME"/gg/tables/*apr 2>/dev/null || true\n  exit 1\nfi\n\ncp "$HOME/gg/tables/$APR_FILE" . || exit 1\ncp process.defaults process.defaults.before_apr_change 2>/dev/null || true\ncp "$APR_FILE" "$CUSTOM_APR_FILE" || exit 1\n\nif [ -n "$CONFLICT_SITE" ]; then\n  for bad in $CONFLICT_SITE; do\n    bad4=$(echo "$bad" | sed \'s/_GPS$//\')\n    echo "Removing APR conflict if present: $bad or $bad4"\n    # Case-insensitive removal\n    awk -v bad="$bad" -v bad4="$bad4" \'toupper($1) != toupper(bad) && toupper($1) != toupper(bad4) {print}\' "$CUSTOM_APR_FILE" > "${CUSTOM_APR_FILE}.tmp"\n    mv "${CUSTOM_APR_FILE}.tmp" "$CUSTOM_APR_FILE"\n  done\nfi\n\n# Safer APR line update\nif grep -Eq \'^[[:space:]]*set[[:space:]]+aprf[[:space:]]*=\' process.defaults; then\n  sed -i -E "s|^[[:space:]]*set[[:space:]]+aprf[[:space:]]*=.*|set aprf = $CUSTOM_APR_FILE|" process.defaults\nelse\n  echo "set aprf = $CUSTOM_APR_FILE" >> process.defaults\nfi\n\n\n# Patch process.defaults path variables emphasized in the Doc-101/125 notes.\n# This keeps project folders internally consistent and avoids stale template paths.\npython3 - << \'PDPATCH\'\nfrom pathlib import Path\nimport os, re\np = Path("process.defaults")\nif not p.exists():\n    raise SystemExit("process.defaults missing")\ntext = p.read_text(errors="ignore")\nproject = Path.home() / os.environ["PROJECT"]\ncustom = os.environ["CUSTOM_APR_FILE"]\nrepls = {\n    "rawpth": str(project / "raw"),\n    "rinexpth": str(project / "rinex"),\n    "brdcpth": str(project / "brdc"),\n    "igspath": str(project / "igs"),\n    "ionpth": str(project / "ionex"),\n    "gdetph": str(project / "gfiles"),\n    "aprf": custom,\n    "rx_doy_plus": "0",\n    "rx_doy_minus": "0",\n}\nfor key, val in repls.items():\n    pat = re.compile(rf"^[ \\t]*set[ \\t]+{re.escape(key)}[ \\t]*=.*$", re.I | re.M)\n    line = f"set {key} = {val}"\n    if pat.search(text):\n        text = pat.sub(line, text)\n    else:\n        text += ("\\n" if not text.endswith("\\n") else "") + line + "\\n"\np.write_text(text, encoding="utf-8", errors="ignore")\nprint("[OK] process.defaults path/APR/rx_doy settings patched:")\nfor key in repls:\n    print("  " + key)\nprint("[OK] rx_doy_minus is set to 0 so sh_gamit will not look for previous-day RINEX during the noftp production run.")\nPDPATCH\n\n# Frame consistency guard: remove any remaining APR files from other frame families.\napr_family_for_file() {\n  b=$(basename "$1" | tr \'[:upper:]\' \'[:lower:]\')\n  case "$b" in\n    *igs20*|*igb20*|*igc20*|*itrf20*|custom_igs20*) echo "IGS20" ;;\n    *igs14*|*igb14*|*itrf14*|*all_pbo_igs14*|*all_pbo_nam14*|custom_igs14*) echo "IGS14" ;;\n    *igs08*|*igb08*|*itrf08*|*all_pbo_igs08*|*all_pbo_nam08*|custom_igs08*|custom_itrf08*) echo "IGS08" ;;\n    *) echo "UNKNOWN" ;;\n  esac\n}\nfor f in *.apr; do\n  [ -e "$f" ] || continue\n  fam=$(apr_family_for_file "$f")\n  if [ "$f" != "$APR_FILE" ] && [ "$f" != "$CUSTOM_APR_FILE" ] && [ "$fam" != "$REF_FRAME" ]; then\n    echo "Removed non-selected APR after APR setup: $f [$fam]"\n    rm -f "$f"\n  fi\ndone\n\necho "APR SOURCE OF TRUTH:"\necho "  Selected family          : $REF_FRAME"\necho "  Base APR in project      : $APR_FILE"\necho "  Active custom APR        : $CUSTOM_APR_FILE"\necho "  process.defaults aprf    : $CUSTOM_APR_FILE"\n\necho "Final process.defaults APR line:"\ngrep -n "aprf" process.defaults || true\necho "APR setup complete."\n\'\'\'\n\ndef get_sites_defaults_step() -> str:\n    return r\'\'\'\necho "Creating sites.defaults..."\ncd "$HOME/$PROJECT/tables" || exit 1\ncp sites.defaults sites.defaults.before_auto_create 2>/dev/null || true\n{\n  echo "# IGS/reference stations"\n  for s in $IGS_SITES; do\n    echo " ${s}_gps $EXPT ftprnx"\n  done\n  echo ""\n  echo "# Local CORS stations"\n  for s in $LOCAL_SITES; do\n    echo " ${s}_gps $EXPT localrx"\n  done\n} > sites.defaults\ncat sites.defaults\necho "IGS count   : $(grep -c \'ftprnx\' sites.defaults)"\necho "Local count : $(grep -c \'localrx\' sites.defaults)"\n\ncd "$HOME/$PROJECT" || exit 1\nmissing=0\nfor s in $LOCAL_SITES; do\n  for n in $(seq $((10#$START_DOY)) $END_DOY); do\n    doy=$(printf "%03d" "$n")\n    f="rinex/${s}${doy}0.${YY}o"\n    if [ -f "$f" ]; then\n      echo "[OK] $f"\n    else\n      echo "[MISSING] $f"\n      missing=1\n    fi\n  done\ndone\nif [ "$missing" -eq 1 ]; then\n  echo "Some local RINEX files are missing. Fix LOCAL_SITES/rename/exclude settings."\n  exit 1\nfi\n\'\'\'\n\n# =============================================================================\n# FIXED: get_lfile_step - Robust conflict removal\n# =============================================================================\ndef get_lfile_step() -> str:\n    return r\'\'\'\necho "Updating lfile. from local RINEX APPROX POSITION XYZ..."\ncd "$HOME/$PROJECT" || exit 1\ncd tables || exit 1\ncp lfile. lfile.before_local_update 2>/dev/null || true\nfor s in $LOCAL_SITES; do\n  U=$(echo "$s" | tr \'[:lower:]\' \'[:upper:]\')\n  grep -v "^ *${U}_GPS" lfile. > lfile.tmp\n  mv lfile.tmp lfile.\ndone\nif [ -n "$CONFLICT_SITE" ]; then\n  for bad in $CONFLICT_SITE; do\n    bad4=$(echo "$bad" | sed \'s/_GPS$//\')\n    grep -v -E "^ *(${bad}|${bad4})( |$)" lfile. > lfile.tmp\n    mv lfile.tmp lfile.\n  done\nfi\ncd "$HOME/$PROJECT" || exit 1\npython3 - << \'PY\'\nfrom pathlib import Path\nimport os\nproject = Path.home() / os.environ["PROJECT"]\nrinex = project / "rinex"\nlfile = project / "tables" / "lfile."\nsites = os.environ["LOCAL_SITES"].split()\nyy = os.environ["YY"]\nyear = int(os.environ["YEAR"])\nstart_doy = int(os.environ["START_DOY"])\nepoch = year + (start_doy - 1) / 365.25\nadded = 0\nwith open(lfile, "a") as out:\n    for site in sites:\n        files = sorted(rinex.glob(f"{site}*.{yy}o"))\n        if not files:\n            print(f"[WARNING] No RINEX found for {site}")\n            continue\n        f = files[0]\n        xyz = None\n        with open(f, "r", errors="ignore") as fp:\n            for line in fp:\n                if "APPROX POSITION XYZ" in line:\n                    parts = line[:60].split()\n                    if len(parts) >= 3:\n                        xyz = [float(parts[0]), float(parts[1]), float(parts[2])]\n                    break\n        if xyz is None:\n            print(f"[WARNING] No APPROX POSITION XYZ in {f.name}")\n            continue\n        U = site.upper()\n        out.write(\n            f"{U}_GPS {xyz[0]:16.5f} {xyz[1]:16.5f} {xyz[2]:16.5f}"\n            f"     0.00000   0.00000   0.00000    {epoch:.4f}"\n            f" ! Local CORS from RINEX header\\n"\n        )\n        print(f"Added {U}_GPS from {f.name}: {xyz}")\n        added += 1\nif added == 0:\n    print("ERROR: No local lfile entries were added")\n    raise SystemExit(1)\nPY\necho "Final local lfile entries:"\ncd tables || exit 1\nfor s in $LOCAL_SITES; do\n  U=$(echo "$s" | tr \'[:lower:]\' \'[:upper:]\')\n  grep "^ *${U}_GPS" lfile. || echo "[WARNING] Missing lfile entry for $U"\ndone\n\'\'\'\n\ndef get_station_info_step() -> str:\n    return r\'\'\'\necho "STATION.INFO EASY MANAGER - fast, quiet, selected-files only"\ncd "$HOME/$PROJECT/tables" || exit 1\n\nREPORT="station_info_easy_report.txt"\nFILES_USED="station_info_files_used.txt"\nCMD_FILE="station_info_update_command.txt"\nUPDATE_LOG="station_info_update.log"\nREF_LOG="station_info_ref_filter.log"\nCACHE_FILE="station_info_easy_cache_key.txt"\nCACHE_NOW="station_info_easy_cache_key.current"\n\n: > "$REPORT"\n: > "$FILES_USED"\n: > "$CMD_FILE"\n: > "$UPDATE_LOG"\n: > "$REF_LOG"\n\n{\n  echo "STATION.INFO EASY MANAGER"\n  echo "Project     : $HOME/$PROJECT"\n  echo "Experiment  : $EXPT"\n  echo "Year/DOY    : $YEAR $START_DOY to $END_DOY"\n  echo "Local sites : $LOCAL_SITES"\n  echo "IGS sites   : $IGS_SITES"\n  echo "Conflict    : ${CONFLICT_SITE:-None}"\n  echo ""\n} >> "$REPORT"\n\n# 1. Create sitelist from selected IGS/reference stations.\necho "Creating tables/sitelist from selected IGS/reference sites..."\n: > sitelist\nfor s in $IGS_SITES; do\n  echo " $s" >> sitelist\ndone\n\necho "Selected reference station sitelist:" >> "$REPORT"\ncat sitelist >> "$REPORT"\necho "" >> "$REPORT"\n\n# 2. Build the exact selected local RINEX file list. Do not use ../rinex/*.YYo blindly.\nmissing=0\nfor s in $LOCAL_SITES; do\n  for n in $(seq $((10#$START_DOY)) $END_DOY); do\n    doy=$(printf "%03d" "$n")\n    f="../rinex/${s}${doy}0.${YY}o"\n    if [ -f "$f" ]; then\n      echo "$f" >> "$FILES_USED"\n    else\n      echo "[WARNING] Missing for station.info: $f" | tee -a "$REPORT"\n      missing=1\n    fi\n  done\ndone\n\nnfiles=$(wc -l < "$FILES_USED" | tr -d \' \')\necho "Number of selected local RINEX files for station.info: $nfiles"\necho "Number of selected local RINEX files: $nfiles" >> "$REPORT"\n\nif [ "$nfiles" -eq 0 ]; then\n  echo "No local RINEX files found for station.info" | tee -a "$REPORT"\n  exit 1\nfi\n\n# 3. RINEX header dashboard/report: marker, receiver, antenna, height, interval.\npython3 - << \'PYEASY1\'\nfrom pathlib import Path\nimport os, re, hashlib\n\nfiles_used = Path(\'station_info_files_used.txt\')\nreport = Path(\'station_info_easy_report.txt\')\ncache_now = Path(\'station_info_easy_cache_key.current\')\nlocal_sites = os.environ.get(\'LOCAL_SITES\',\'\').split()\nfiles = [Path(x.strip()) for x in files_used.read_text().splitlines() if x.strip()]\n\ndef read_header(path: Path):\n    md = {\'marker\':\'Unknown\', \'receiver\':\'Unknown\', \'antenna\':\'Unknown\', \'height\':\'Unknown\', \'interval\':\'Unknown\', \'approx\':\'NO\', \'epochs\':0}\n    try:\n        in_header = True\n        with open(path, \'r\', errors=\'ignore\') as f:\n            for line in f:\n                if in_header:\n                    if \'MARKER NAME\' in line:\n                        md[\'marker\'] = line[:60].strip()\n                    elif \'REC # / TYPE / VERS\' in line:\n                        md[\'receiver\'] = line[:60].strip()\n                    elif \'ANT # / TYPE\' in line:\n                        md[\'antenna\'] = line[:60].strip()\n                    elif \'ANTENNA: DELTA H/E/N\' in line:\n                        parts = line[:60].split()\n                        if parts: md[\'height\'] = parts[0]\n                    elif \'INTERVAL\' in line:\n                        md[\'interval\'] = line[:20].strip()\n                    elif \'APPROX POSITION XYZ\' in line:\n                        md[\'approx\'] = \'YES\'\n                    elif \'END OF HEADER\' in line:\n                        in_header = False\n                    continue\n                m3 = re.match(r\'^>\\s*\\d{4}\\s+\\d{1,2}\\s+\\d{1,2}\\s+\\d{1,2}\\s+\\d{1,2}\', line)\n                m2 = re.match(r\'\\s*\\d{2}\\s+\\d{1,2}\\s+\\d{1,2}\\s+\\d{1,2}\\s+\\d{1,2}\', line)\n                if m3 or m2:\n                    md[\'epochs\'] += 1\n    except Exception as e:\n        md[\'marker\'] = f\'Could not read: {e}\'\n    return md\n\nby_site = {s: [] for s in local_sites}\nfor f in files:\n    site = f.name[:4].lower()\n    if site in by_site:\n        by_site[site].append(f)\n\nlines = []\nlines.append(\'\\nSTATION.INFO INPUT CHECK\')\nlines.append(\'Station  Days  Marker  Receiver                 Antenna           Height   Intv   Epochs(min-max)  Status\')\nlines.append(\'-\'*115)\n\ncache_parts = []\nfor site in local_sites:\n    fs = sorted(by_site.get(site, []))\n    statuses = []\n    markers = []\n    receivers = []\n    antennas = []\n    heights = []\n    intervals = []\n    epochs = []\n    for f in fs:\n        st = f.stat()\n        cache_parts.append(f\'{f}:{st.st_size}:{int(st.st_mtime)}\')\n        md = read_header(f)\n        markers.append(md[\'marker\']); receivers.append(md[\'receiver\']); antennas.append(md[\'antenna\'])\n        heights.append(md[\'height\']); intervals.append(md[\'interval\']); epochs.append(int(md[\'epochs\']))\n        marker4 = str(md[\'marker\']).split()[0].upper()[:4]\n        if marker4 and marker4 != site.upper():\n            statuses.append(f\'MARKER {marker4}!={site.upper()}\')\n        if str(md[\'height\']).strip() in (\'0\', \'0.0\', \'0.0000\', \'0.00000\'):\n            statuses.append(\'CHECK_HEIGHT\')\n        if md[\'approx\'] != \'YES\':\n            statuses.append(\'NO_APPROX_XYZ\')\n    days = f\'{len(fs)}/{int(os.environ.get("NDAYS","0") or 0)}\'\n    marker = (markers[0] if markers else \'-\')[:8]\n    rec = (receivers[0] if receivers else \'-\')[:24]\n    ant = (antennas[0] if antennas else \'-\')[:16]\n    hgt = (heights[0] if heights else \'-\')[:8]\n    itv = (intervals[0] if intervals else \'-\')[:6]\n    ep = \'-\' if not epochs else f\'{min(epochs)}-{max(epochs)}\'\n    status = \'OK\' if not statuses else \',\'.join(sorted(set(statuses)))\n    lines.append(f\'{site.upper():8s} {days:5s} {marker:8s} {rec:24s} {ant:16s} {hgt:8s} {itv:6s} {ep:15s} {status}\')\nlines.append(\'-\'*115)\nwith open(report, \'a\') as out:\n    out.write(\'\\n\'.join(lines) + \'\\n\')\nprint(\'\\n\'.join(lines))\n\nkey_raw = \'\\n\'.join(cache_parts + [os.environ.get(\'LOCAL_SITES\',\'\'), os.environ.get(\'IGS_SITES\',\'\'), os.environ.get(\'CONFLICT_SITE\',\'\')])\ncache_now.write_text(hashlib.sha256(key_raw.encode()).hexdigest() + \'\\n\')\nPYEASY1\n\n# 4. Cache: if same selected files and station.info already contains all locals, skip sh_upd_stnfo.\nif [ -f "$CACHE_FILE" ] && cmp -s "$CACHE_FILE" "$CACHE_NOW"; then\n  if python3 - << \'PYEASY2\'\nfrom pathlib import Path\nimport os, re, sys\ntext = Path(\'station.info\').read_text(errors=\'ignore\').upper() if Path(\'station.info\').exists() else \'\'\nmissing=[]\nfor s in os.environ.get(\'LOCAL_SITES\',\'\').split():\n    u=s.upper()\n    if not re.search(r\'^\\s*\' + re.escape(u) + r\'(\\s|$)\', text, flags=re.M):\n        missing.append(u)\nif missing:\n    print(\'Missing in station.info despite cache:\', \' \'.join(missing))\n    sys.exit(1)\nsys.exit(0)\nPYEASY2\n  then\n    echo "[OK] station.info already up to date for this exact selected RINEX set. Skipping sh_upd_stnfo."\n    echo "station.info update skipped by cache." >> "$REPORT"\n    exit 0\n  fi\nfi\n\n# 5. Backup and make station.info smaller using selected IGS/reference sitelist.\ncp station.info station.info.before_easy_update_$(date +%Y%m%d_%H%M%S) 2>/dev/null || true\ncp station.info station.info.easy_original 2>/dev/null || true\n\necho "Reducing station.info to selected IGS/reference stations using sitelist..."\nrm -f station.info.new\nif sh_upd_stnfo -ref station.info -l sitelist > "$REF_LOG" 2>&1 && [ -s station.info.new ]; then\n  mv station.info.new station.info\n  echo "[OK] station.info reduced using sitelist."\n  echo "station.info reduced using sitelist." >> "$REPORT"\nelse\n  echo "[WARNING] Could not reduce station.info with sitelist. Keeping original station.info. See $REF_LOG"\n  [ -f station.info.easy_original ] && cp station.info.easy_original station.info\n  echo "station.info reduction skipped/fallback used." >> "$REPORT"\nfi\n\n# 6. Remove previous local/conflict/renamed entries before adding clean metadata.\npython3 - << \'PYEASY3\'\nfrom pathlib import Path\nimport os\nremove=set()\nfor s in os.environ.get(\'LOCAL_SITES\',\'\').split():\n    u=s.upper(); remove.add(u); remove.add(u+\'_GPS\')\nfor s in os.environ.get(\'CONFLICT_SITE\',\'\').split():\n    u=s.upper(); remove.add(u); remove.add(u.replace(\'_GPS\',\'\'))\nfor pair in os.environ.get(\'RENAME_PAIRS\',\'\').split():\n    if \':\' in pair:\n        old,new=pair.split(\':\',1)\n        for x in (old,new):\n            u=x.upper(); remove.add(u); remove.add(u+\'_GPS\')\np=Path(\'station.info\')\nif not p.exists():\n    raise SystemExit(\'station.info missing\')\nout=[]; removed=0\nfor line in p.read_text(errors=\'ignore\').splitlines(True):\n    parts=line.split()\n    first=parts[0].upper() if parts else \'\'\n    first4=first.replace(\'_GPS\',\'\')\n    if first in remove or first4 in remove:\n        removed += 1\n        continue\n    out.append(line)\np.write_text(\'\'.join(out), encoding=\'utf-8\', errors=\'ignore\')\nprint(f\'[OK] Removed {removed} old local/conflict station.info line(s).\')\nPYEASY3\n\n# 7. Run sh_upd_stnfo quietly on selected local RINEX only.\nmapfile -t RINEX_FILES < "$FILES_USED"\n{\n  echo "cd $HOME/$PROJECT/tables"\n  printf \'sh_upd_stnfo -ref station.info -files\'\n  for f in "${RINEX_FILES[@]}"; do printf \' %q\' "$f"; done\n  printf \' -w station.info\\n\'\n} > "$CMD_FILE"\n\necho "Running sh_upd_stnfo quietly. Full output will be in: $PWD/$UPDATE_LOG"\nsh_upd_stnfo -ref station.info -files "${RINEX_FILES[@]}" -w station.info > "$UPDATE_LOG" 2>&1\nrc=$?\nif [ "$rc" -ne 0 ]; then\n  echo "sh_upd_stnfo failed with code $rc. Last log lines:"\n  tail -80 "$UPDATE_LOG" || true\n  exit "$rc"\nfi\ncp "$CACHE_NOW" "$CACHE_FILE" 2>/dev/null || true\n\n# 8. Verify local stations and print only a short useful summary.\necho "station.info updated. Verification summary:"\npython3 - << \'PYEASY4\'\nfrom pathlib import Path\nimport os, re, sys\np=Path(\'station.info\')\ntext=p.read_text(errors=\'ignore\') if p.exists() else \'\'\nlines=text.splitlines()\nreport=Path(\'station_info_easy_report.txt\')\nsummary=[]; missing=[]\nsummary.append(\'\\nSTATION.INFO UPDATE RESULT\')\nsummary.append(\'Station  Entry  Status        Last station.info line\')\nsummary.append(\'-\'*110)\nfor s in os.environ.get(\'LOCAL_SITES\',\'\').split():\n    u=s.upper(); matches=[]\n    for line in lines:\n        parts=line.split()\n        if parts and parts[0].upper()==u:\n            matches.append(line)\n    if matches:\n        last=matches[-1]\n        status=\'OK\'\n        if re.search(r\'\\s0\\.0000+\\s\', last): status=\'CHECK_HEIGHT\'\n        summary.append(f\'{u:8s} FOUND  {status:12s} {last[:75]}\')\n    else:\n        missing.append(u)\n        summary.append(f\'{u:8s} MISSING ERROR        -\')\nsummary.append(\'-\'*110)\nprint(\'\\n\'.join(summary))\nwith open(report,\'a\') as f:\n    f.write(\'\\n\'.join(summary)+\'\\n\')\nif missing:\n    print(\'ERROR: Missing local stations in station.info:\', \' \'.join(missing))\n    sys.exit(1)\nPYEASY4\n\necho "[OK] station.info easy update completed."\necho "Reports saved:"\necho "  $PWD/$REPORT"\necho "  $PWD/$FILES_USED"\necho "  $PWD/$CMD_FILE"\necho "  $PWD/$UPDATE_LOG"\necho "NOTE: antenna height 0.0000 is acceptable only for demo. Correct it for final scientific results."\n\'\'\'\n\n# =============================================================================\n# FIXED: get_otl_step - Robust sestbl. update\n# =============================================================================\ndef get_otl_step() -> str:\n    return r\'\'\'\necho "Checking Ocean Tide Loading files..."\necho "This step is mandatory because sh_gamit fails with: Ocean loading requested no list or grid file"\n\nmkdir -p "$HOME/gg/GRIDS"\nOTL_GRID_MASTER="$HOME/gg/GRIDS/otl_FES2004.grid"\nOTL_GRID_MIN_BYTES=600000000\n\ncheck_big_readable_file() {\n  f="$1"\n  minbytes="$2"\n  label="$3"\n  if [ ! -r "$f" ]; then\n    echo "[MISSING] $label not readable: $f"\n    return 1\n  fi\n  bytes=$(wc -c < "$f" 2>/dev/null || echo 0)\n  echo "[INFO] $label size: $bytes bytes"\n  if [ "$bytes" -lt "$minbytes" ]; then\n    echo "[MISSING] $label too small/incomplete: $f"\n    return 1\n  fi\n  echo "[OK] $label readable and size looks valid: $f"\n  return 0\n}\n\ndownload_otl_grid() {\n  cd "$HOME/gg/GRIDS" || exit 1\n  echo "Downloading/resuming OTL grid: otl_FES2004.grid"\n  echo "This file is large, about 697 MB. It may take several minutes, but it is downloaded only once."\n\n  if [ -e otl_FES2004.grid ] || [ -L otl_FES2004.grid ]; then\n    bytes=$(wc -c < otl_FES2004.grid 2>/dev/null || echo 0)\n    if [ "$bytes" -eq 0 ]; then\n      echo "[WARNING] Removing zero-byte OTL grid"\n      rm -f otl_FES2004.grid\n    elif LC_ALL=C head -c 300 otl_FES2004.grid 2>/dev/null | grep -Eiq \'(<html|<!doctype|login|error|not found|forbidden|unauthorized)\'; then\n      echo "[WARNING] Existing OTL grid looks like HTML/error page, removing"\n      rm -f otl_FES2004.grid\n    elif [ "$bytes" -lt "$OTL_GRID_MIN_BYTES" ]; then\n      echo "[INFO] Keeping partial binary OTL grid for resume: $bytes bytes"\n    fi\n  fi\n\n  curl -k -f -L -C - \\\n    --connect-timeout 60 \\\n    --max-time 3600 \\\n    --speed-limit 100 --speed-time 180 \\\n    --retry 5 --retry-delay 10 --retry-connrefused \\\n    -o otl_FES2004.grid \\\n    https://chandler.mit.edu/ftp/GRIDS/otl_FES2004.grid\n}\n\nif ! check_big_readable_file "$OTL_GRID_MASTER" "$OTL_GRID_MIN_BYTES" "OTL grid"; then\n  if [ "$NOFTP_FLAG" = "-noftp" ]; then\n    echo "OTL grid missing/incomplete in -noftp mode."\n    echo "Expected: $OTL_GRID_MASTER"\n    exit 1\n  fi\n  download_otl_grid || true\n  if ! check_big_readable_file "$OTL_GRID_MASTER" "$OTL_GRID_MIN_BYTES" "OTL grid after download"; then\n    echo "[ERROR] OTL grid still missing/incomplete after download attempt."\n    echo "Manual command:"\n    echo "mkdir -p ~/gg/GRIDS && cd ~/gg/GRIDS"\n    echo "curl -k -f -L -C - --connect-timeout 60 --max-time 3600 --speed-limit 100 --speed-time 180 --retry 5 --retry-delay 10 -o otl_FES2004.grid https://chandler.mit.edu/ftp/GRIDS/otl_FES2004.grid"\n    exit 1\n  fi\nfi\n\ncd "$HOME/$PROJECT/tables" || exit 1\n\n# ====== PATCH: Robust sestbl. OTL settings update ======\nif [ -f sestbl. ]; then\n  cp sestbl. sestbl.before_otl_check 2>/dev/null || true\n\n  if grep -qiE \'^[[:space:]]*Use otl.grid\' sestbl.; then\n    sed -i -E \'s/^[[:space:]]*Use otl.grid.*/Use otl.grid = Y      /I\' sestbl.\n  else\n    echo "Use otl.grid = Y      " >> sestbl.\n  fi\n\n  if grep -qiE \'^[[:space:]]*Use otl.list\' sestbl.; then\n    sed -i -E \'s/^[[:space:]]*Use otl.list.*/Use otl.list = N      /I\' sestbl.\n  else\n    echo "Use otl.list = N      " >> sestbl.\n  fi\nfi\n# =====================================================\n\nrm -f otl.grid otl.list otlcmc.dat\nln -s "$OTL_GRID_MASTER" otl.grid\n\nif [ -r "$HOME/gg/tables/otl_FES2014bM_igb14_comb.list" ]; then\n  ln -s "$HOME/gg/tables/otl_FES2014bM_igb14_comb.list" otl.list\nelif [ -r "$HOME/gg/tables/otl.list" ]; then\n  ln -s "$HOME/gg/tables/otl.list" otl.list\nelse\n  echo "[WARNING] No readable otl.list found in ~/gg/tables"\nfi\n\nif [ -r "$HOME/gg/tables/otlcmc.dat" ]; then\n  ln -s "$HOME/gg/tables/otlcmc.dat" otlcmc.dat\nelse\n  echo "[WARNING] No readable otlcmc.dat found in ~/gg/tables"\nfi\n\necho "OTL link check in project tables:"\nls -lh otl.grid otl.list otlcmc.dat 2>/dev/null || true\necho "Resolved OTL targets:"\nreadlink -f otl.grid  || true\nreadlink -f otl.list  || true\nreadlink -f otlcmc.dat || true\n\ntest -r otl.grid || { echo "[ERROR] otl.grid link exists but target is not readable"; exit 1; }\nbytes=$(wc -c < otl.grid 2>/dev/null || echo 0)\nif [ "$bytes" -lt "$OTL_GRID_MIN_BYTES" ]; then\n  echo "[ERROR] otl.grid target is too small/incomplete: $bytes bytes"\n  exit 1\nfi\necho "[OK] otl.grid readable and complete-looking"\ntest -r otl.list && echo "[OK] otl.list readable" || echo "[INFO] otl.list not used because Use otl.list = N"\ntest -r otlcmc.dat && echo "[OK] otlcmc.dat readable" || echo "[WARNING] otlcmc.dat not readable"\necho "sestbl OTL settings:"\ngrep -ni "Use otl.grid\\|Use otl.list\\|Tide Model\\|ocean" sestbl. 2>/dev/null || true\n\'\'\'\n\n\n# =============================================================================\n# download_gzip - bounded resume-first CDDIS download with mirror fallback\n# =============================================================================\nDOWNLOAD_FUNCTION = r"""\ndownload_gzip() {\n  outfile="$1"\n  url="$2"\n  max_attempts="${3:-8}"\n  alt_url="${4:-}"\n  if [ -z "$alt_url" ]; then\n    alt_url=$(echo "$url" | sed \'s#https://cddis.nasa.gov#https://gdc.cddis.eosdis.nasa.gov#\')\n  fi\n  attempt=1\n  while [ "$attempt" -le "$max_attempts" ]; do\n    if [ -s "$outfile" ] && gzip -t "$outfile" 2>/dev/null; then\n      echo "[OK] $outfile already complete"\n      return 0\n    fi\n    if [ -f "$outfile" ] && [ ! -s "$outfile" ]; then\n      rm -f "$outfile"\n    fi\n    if [ -f "$outfile" ] && ! gzip -t "$outfile" 2>/dev/null; then\n      if LC_ALL=C head -c 300 "$outfile" 2>/dev/null | grep -Eiq \'(<html|<!doctype|earthdata|login|not found|error|forbidden|unauthorized)\'; then\n        rm -f "$outfile"\n      else\n        bytes=$(wc -c < "$outfile" 2>/dev/null || echo 0)\n        echo "[INFO] Keeping partial binary gzip for resume: $outfile (${bytes} bytes)"\n      fi\n    fi\n    use_url="$url"\n    if [ "$attempt" -gt $(( (max_attempts + 1) / 2 )) ] && [ "$alt_url" != "$url" ]; then\n      use_url="$alt_url"\n      echo "[INFO] Switching to alternate CDDIS host/mirror after repeated failures."\n    fi\n    echo "Download attempt $attempt/$max_attempts: $outfile"\n    echo "URL: $use_url"\n    curl -f -L -n --http1.1 --ipv4 -C - -b "$HOME/.urs_cookies" -c "$HOME/.urs_cookies" --retry 2 --retry-delay 5 --retry-connrefused --connect-timeout 45 --max-time 180 --speed-limit 50 --speed-time 45 -o "$outfile" "$use_url"\n    curl_rc=$?\n    if [ -s "$outfile" ] && gzip -t "$outfile" 2>/dev/null; then\n      echo "[OK] Download complete: $outfile"\n      return 0\n    fi\n    echo "[WARNING] Download not complete yet: $outfile | curl rc=$curl_rc"\n    attempt=$((attempt + 1))\n    sleep 5\n  done\n  echo "[ERROR] Download failed after $max_attempts attempts: $outfile"\n  echo "[HINT] You can manually download the same file into this folder and retry."\n  return 1\n}\n"""\n\ndef get_product_step(doy: str) -> str:\n    return f"export DOY_NOW={q(doy)}\\n" + DOWNLOAD_FUNCTION + r\'\'\'\necho "Preparing SP3, IONEX and BRDC for DOY $DOY_NOW..."\ncd "$HOME/$PROJECT" || exit 1\nmkdir -p igs ionex brdc\ndoy="$DOY_NOW"\ndate_ymd=$(date -u -d "${YEAR}-01-01 +$((10#$doy - 1)) days" +%Y%m%d)\ngps_days=$(( ( $(date -u -d "$date_ymd" +%s) - $(date -u -d "1980-01-06" +%s) ) / 86400 ))\ngps_week=$(( gps_days / 7 ))\ngps_dow=$(( gps_days % 7 ))\nsp3_long="IGS0OPSFIN_${YEAR}${doy}0000_01D_15M_ORB.SP3.gz"\nsp3_short="igs${gps_week}${gps_dow}.sp3"\nionex_long="IGS0OPSFIN_${YEAR}${doy}0000_01D_02H_GIM.INX.gz"\nionex_short="igsg${doy}0.${YY}i"\nbrdc_gz="brdc${doy}0.${YY}n.gz"\nbrdc_short="brdc${doy}0.${YY}n"\necho "Date: $date_ymd | GPS week/day: $gps_week/$gps_dow"\necho "SP3   : $sp3_short"\necho "IONEX : $ionex_short"\necho "BRDC  : $brdc_short"\n\ncd "$HOME/$PROJECT/igs" || exit 1\nif [ -f "$sp3_short" ] && tail -1 "$sp3_short" | grep -q "EOF"; then\n  echo "[OK] Existing SP3 complete"\nelse\n  if [ "$GAMIT_ORBIT_MODE" = "OFFLINE_IGSF" ] || [ "$GAMIT_ORBIT_MODE" = "OFFLINE_IGSG" ]; then\n    echo "[MISSING] SP3 in strict offline mode: $sp3_short"\n    exit 1\n  fi\n  download_gzip "$sp3_long" "https://cddis.nasa.gov/archive/gnss/products/${gps_week}/${sp3_long}" 8 || exit 1\n  gunzip -c "$sp3_long" > "$sp3_short" || exit 1\nfi\ntail -1 "$sp3_short" | grep -q "EOF" || { echo "SP3 does not end with EOF"; exit 1; }\n\ncd "$HOME/$PROJECT/ionex" || exit 1\nif [ -f "$ionex_short" ] && tail -1 "$ionex_short" | grep -q "END OF FILE"; then\n  echo "[OK] Existing IONEX complete"\nelse\n  if [ "$GAMIT_ORBIT_MODE" = "OFFLINE_IGSF" ] || [ "$GAMIT_ORBIT_MODE" = "OFFLINE_IGSG" ]; then\n    echo "[MISSING] IONEX in strict offline mode: $ionex_short"\n    exit 1\n  fi\n  download_gzip "$ionex_long" "https://cddis.nasa.gov/archive/gnss/products/ionex/${YEAR}/${doy}/${ionex_long}" 10 || exit 1\n  gunzip -c "$ionex_long" > "$ionex_short" || exit 1\nfi\ntail -1 "$ionex_short" | grep -q "END OF FILE" || { echo "IONEX does not end with END OF FILE"; exit 1; }\n\ncd "$HOME/$PROJECT/brdc" || exit 1\nif [ -s "$brdc_short" ]; then\n  echo "[OK] Existing BRDC found"\nelse\n  if [ "$GAMIT_ORBIT_MODE" = "OFFLINE_IGSF" ] || [ "$GAMIT_ORBIT_MODE" = "OFFLINE_IGSG" ]; then\n    echo "[MISSING] BRDC in strict offline mode: $brdc_short"\n    exit 1\n  fi\n  download_gzip "$brdc_gz" "https://cddis.nasa.gov/archive/gnss/data/daily/${YEAR}/${doy}/${YY}n/${brdc_gz}" 8 || exit 1\n  gunzip -c "$brdc_gz" > "$brdc_short" || exit 1\nfi\n[ -s "$brdc_short" ] || { echo "BRDC missing or empty"; exit 1; }\n\n# EOP checks required for safe -noftp runs.\ncd "$HOME/$PROJECT" || exit 1\nmkdir -p tables\nfor eop in pole.usno ut1.usno; do\n  if [ -s "tables/$eop" ]; then\n    echo "[OK] EOP present: tables/$eop"\n  elif [ -s "$HOME/gg/tables/$eop" ]; then\n    echo "[OK] Copying EOP from ~/gg/tables/$eop"\n    cp -f "$HOME/gg/tables/$eop" "tables/$eop" || exit 1\n  else\n    echo "[MISSING] EOP file: $eop"\n    if [ "$GAMIT_ORBIT_MODE" = "OFFLINE_IGSF" ] || [ "$GAMIT_ORBIT_MODE" = "OFFLINE_IGSG" ] || [ "$GAMIT_ORBIT_MODE" = "PREFETCH_IGSF_NOFTP" ]; then\n      echo "Required for productive/noftp run. Fix tables/$eop before GAMIT."\n      exit 1\n    fi\n  fi\n done\n\necho "Products ready for DOY $doy."\n\'\'\'\n\n# =============================================================================\n# FIXED: get_global_rinex_step - handles .Z with fallback + lowercase normalization\n# =============================================================================\ndef get_global_rinex_step(doy: str) -> str:\n    return f"export DOY_NOW={q(doy)}\\n" + r\'\'\'\necho "Preparing/checking global IGS RINEX for DOY $DOY_NOW..."\ncd "$HOME/$PROJECT" || exit 1\nmkdir -p rinex control\ndoy="$DOY_NOW"\nACTIVE_IGS_FILE="$HOME/$PROJECT/control/active_igs_sites_${doy}.txt"\n\nclean_bad_global_files() {\n  cd "$HOME/$PROJECT/rinex" || exit 1\n  doy="$1"\n  echo "Cleaning invalid/empty global RINEX files for DOY $doy..."\n  for s in $IGS_SITES; do\n    for f in ${s}${doy}0.${YY}o ${s}${doy}0.${YY}d; do\n      if [ -f "$f" ] && [ ! -s "$f" ]; then rm -f "$f"; fi\n    done\n    for f in ${s}${doy}0.${YY}o.gz ${s}${doy}0.${YY}o.GZ ${s}${doy}0.${YY}o.Z \\\n             ${s}${doy}0.${YY}d.gz ${s}${doy}0.${YY}d.GZ ${s}${doy}0.${YY}d.Z; do\n      [ -f "$f" ] || continue\n      if ! gzip -t "$f" 2>/dev/null && ! file "$f" | grep -q "compress\'d data"; then\n        echo "  Removing invalid compressed file: $f"\n        rm -f "$f"\n      fi\n    done\n  done\n  cd "$HOME/$PROJECT" || exit 1\n}\n\nconvert_global_rinex_for_day() {\n  cd "$HOME/$PROJECT/rinex" || exit 1\n  doy="$1"\n\n  # Normalize first 4 characters of global short-name RINEX files to lowercase\n  echo "Normalizing first 4 characters of global short-name RINEX files to lowercase..."\n  python3 - << \'PY\'\nfrom pathlib import Path\nimport os\n\nyy = os.environ["YY"]\ndoy = os.environ.get("DOY_NOW", "")\n\nsuffixes = [\n    f".{yy}o.gz", f".{yy}o.GZ", f".{yy}o.Z", f".{yy}o",\n    f".{yy}d.gz", f".{yy}d.GZ", f".{yy}d.Z", f".{yy}d",\n]\n\nfor p in sorted(Path(".").iterdir()):\n    if not p.is_file():\n        continue\n    name = p.name\n    if doy and f"{doy}0" not in name:\n        continue\n    matched = False\n    for suf in suffixes:\n        if name.endswith(suf) and len(name) >= 7 + len(suf):\n            matched = True\n            break\n    if not matched:\n        continue\n    new_name = name[:4].lower() + name[4:]\n    if new_name == name:\n        continue\n    target = p.with_name(new_name)\n    if target.exists():\n        print(f"WARNING: Cannot rename {name} -> {new_name}; target already exists")\n        continue\n    print(f"  {name} -> {new_name}")\n    p.rename(target)\nPY\n\n  # Uncompress .o.gz/.o.GZ/.o.Z\n  echo "Uncompressing .o.gz/.o.GZ/.o.Z files if present..."\n  for f in *${doy}0.${YY}o.gz *${doy}0.${YY}o.GZ *${doy}0.${YY}o.Z; do\n    [ -f "$f" ] || continue\n    if gzip -t "$f" 2>/dev/null; then\n      echo "  gunzip -k: $f"\n      gunzip -k -f "$f" || exit 1\n    elif file "$f" | grep -q "compress\'d data"; then\n      echo "  uncompress (Z): $f"\n      gzip -cd "$f" > "${f%.Z}" 2>/dev/null || uncompress -c "$f" > "${f%.Z}" || exit 1\n    else\n      echo "  Invalid compressed, removing: $f"\n      rm -f "$f"\n    fi\n  done\n\n  # Uncompress .d.gz/.d.GZ/.d.Z (Hatanaka)\n  echo "Uncompressing Hatanaka .d.gz/.d.GZ/.d.Z files if present..."\n  for f in *${doy}0.${YY}d.gz *${doy}0.${YY}d.GZ *${doy}0.${YY}d.Z; do\n    [ -f "$f" ] || continue\n    if gzip -t "$f" 2>/dev/null; then\n      dfile="${f%.*}"\n      echo "  gunzip -c: $f -> $dfile"\n      gunzip -c "$f" > "$dfile" || exit 1\n    elif file "$f" | grep -q "compress\'d data"; then\n      dfile="${f%.Z}"\n      echo "  uncompress -c: $f -> $dfile"\n      gzip -cd "$f" > "$dfile" 2>/dev/null || uncompress -c "$f" > "$dfile" || exit 1\n    else\n      echo "  Invalid compressed, removing: $f"\n      rm -f "$f"\n    fi\n  done\n\n  # Handle long-name RINEX3 .crx.gz (including .GZ)\n  echo "Handling long-name RINEX3 .crx.gz files if present..."\n  for f in *${YEAR}${doy}0000*.crx.gz *${YEAR}${doy}0000*.CRX.gz *${YEAR}${doy}0000*.crx.GZ *${YEAR}${doy}0000*.CRX.GZ; do\n    [ -f "$f" ] || continue\n    site=$(echo "$f" | cut -c1-4 | tr \'[:upper:]\' \'[:lower:]\')\n    dfile="${site}${doy}0.${YY}d"\n    ofile="${site}${doy}0.${YY}o"\n    [ -s "$ofile" ] && continue\n    gzip -t "$f" 2>/dev/null || { rm -f "$f"; continue; }\n    echo "  Long-name CRX -> short Hatanaka: $f -> $dfile"\n    gunzip -c "$f" > "$dfile" || { rm -f "$dfile"; continue; }\n    command -v crx2rnx >/dev/null 2>&1 || { echo "crx2rnx not found"; exit 1; }\n    crx2rnx "$dfile"\n    [ -s "$ofile" ] || rm -f "$ofile"\n  done\n\n  # Handle long-name RINEX3 .rnx.gz (including .GZ)\n  echo "Handling long-name RINEX3 .rnx.gz files if present..."\n  for f in *${YEAR}${doy}0000*.rnx.gz *${YEAR}${doy}0000*.RNX.gz *${YEAR}${doy}0000*.rnx.GZ *${YEAR}${doy}0000*.RNX.GZ; do\n    [ -f "$f" ] || continue\n    site=$(echo "$f" | cut -c1-4 | tr \'[:upper:]\' \'[:lower:]\')\n    ofile="${site}${doy}0.${YY}o"\n    [ -s "$ofile" ] && continue\n    gzip -t "$f" 2>/dev/null || { rm -f "$f"; continue; }\n    echo "  Long-name RNX -> short observation: $f -> $ofile"\n    gunzip -c "$f" > "$ofile" || rm -f "$ofile"\n  done\n\n  # Convert any remaining .d files (short-name Hatanaka)\n  echo "Converting Hatanaka .d to .o if present..."\n  for f in *${doy}0.${YY}d; do\n    [ -f "$f" ] || continue\n    command -v crx2rnx >/dev/null 2>&1 || { echo "crx2rnx not found"; exit 1; }\n    ofile="${f%.${YY}d}.${YY}o"\n    [ -s "$ofile" ] && continue\n    echo "  crx2rnx: $f"\n    crx2rnx "$f"\n    [ -s "$ofile" ] || rm -f "$ofile"\n  done\n\n  cd "$HOME/$PROJECT" || exit 1\n}\n\ncheck_available_igs() {\n  cd "$HOME/$PROJECT" || exit 1\n  doy="$1"\n  active=""\n  missing=""\n  for s in $IGS_SITES; do\n    f="rinex/${s}${doy}0.${YY}o"\n    if [ -s "$f" ]; then\n      echo "[OK] Global RINEX ready: $s"\n      active="$active $s"\n    else\n      echo "[MISSING] Global RINEX not ready: $s"\n      missing="$missing $s"\n    fi\n  done\n  active=$(echo "$active" | xargs)\n  missing=$(echo "$missing" | xargs)\n  echo "$active" > "$ACTIVE_IGS_FILE"\n  echo "Active IGS stations for DOY $doy: ${active:-NONE}"\n  echo "Missing IGS stations for DOY $doy: ${missing:-NONE}"\n  n_active=$(echo "$active" | wc -w)\n  if [ "$n_active" -lt 3 ]; then\n    echo "ERROR: Less than 3 IGS stations are available."\n    exit 1\n  fi\n  cd "$HOME/$PROJECT/tables" || exit 1\n  cp sites.defaults "sites.defaults.before_active_igs_${doy}" 2>/dev/null || true\n  {\n    echo "# Active IGS/reference stations for DOY $doy"\n    for s in $active; do echo " ${s}_gps $EXPT ftprnx"; done\n    echo ""\n    echo "# Local CORS stations"\n    for s in $LOCAL_SITES; do echo " ${s}_gps $EXPT localrx"; done\n  } > sites.defaults\n  cat sites.defaults\n}\n\n\ntry_fallback_reference_sites() {\n  cd "$HOME/$PROJECT" || exit 1\n  doy="$1"\n  current_active=""\n  for s in $IGS_SITES; do\n    [ -s "rinex/${s}${doy}0.${YY}o" ] && current_active="$current_active $s"\n  done\n  n_current=$(echo "$current_active" | wc -w)\n  if [ "$n_current" -ge 5 ]; then\n    return 0\n  fi\n  FALLBACK_IGS_SITES="${FALLBACK_IGS_SITES:-hyde iisc ntus pol2 lhaz cusv coco xmis dgar mal2 pimo bako shao hkws hksl jfng daej badg reun djig bhr4}"\n  need=""\n  for s in $FALLBACK_IGS_SITES; do\n    echo "$IGS_SITES $current_active" | grep -qw "$s" && continue\n    need="$need $s"\n  done\n  need=$(echo "$need" | xargs)\n  [ -n "$need" ] || return 0\n  echo "[INFO] Active IGS count is $n_current. Trying fallback reference stations: $need"\n  cd "$HOME/$PROJECT/rinex" || exit 1\n  if command -v timeout >/dev/null 2>&1; then\n    timeout 900 sh_get_rinex -archive cddis -yr "$YEAR" -doy "$doy" -ndays 1 -sites $need -ftp_prog curl -inv -xcheck N || true\n  else\n    sh_get_rinex -archive cddis -yr "$YEAR" -doy "$doy" -ndays 1 -sites $need -ftp_prog curl -inv -xcheck N || true\n  fi\n  cd "$HOME/$PROJECT" || exit 1\n  clean_bad_global_files "$doy"\n  convert_global_rinex_for_day "$doy"\n  extra=""\n  for s in $need; do\n    [ -s "rinex/${s}${doy}0.${YY}o" ] && extra="$extra $s"\n  done\n  extra=$(echo "$extra" | xargs)\n  if [ -n "$extra" ]; then\n    export IGS_SITES="$(echo "$IGS_SITES $extra" | xargs -n1 | awk \'!seen[$0]++\' | xargs)"\n    echo "[OK] Added fallback IGS stations for this day: $extra"\n  fi\n}\n\nclean_bad_global_files "$doy"\nconvert_global_rinex_for_day "$doy"\n\nmissing_before=0\nfor s in $IGS_SITES; do\n  [ -s "rinex/${s}${doy}0.${YY}o" ] || missing_before=1\ndone\n\nif [ "$missing_before" -eq 0 ]; then\n  check_available_igs "$doy"\n  exit 0\nfi\n\nif [ "$NOFTP_FLAG" = "-noftp" ] || [ "$DOWNLOAD_GLOBAL_RINEX" != "YES" ]; then\n  check_available_igs "$doy"\n  exit 0\nfi\n\nif ! command -v sh_get_rinex >/dev/null 2>&1; then\n  echo "sh_get_rinex not found. Cannot download global RINEX."\n  check_available_igs "$doy"\n  exit 0\nfi\n\ncd "$HOME/$PROJECT/rinex" || exit 1\nif command -v timeout >/dev/null 2>&1; then\n  timeout 900 sh_get_rinex -archive cddis -yr "$YEAR" -doy "$doy" -ndays 1 -sites $IGS_SITES -ftp_prog curl -inv -xcheck N\nelse\n  sh_get_rinex -archive cddis -yr "$YEAR" -doy "$doy" -ndays 1 -sites $IGS_SITES -ftp_prog curl -inv -xcheck N\nfi\ncd "$HOME/$PROJECT" || exit 1\nclean_bad_global_files "$doy"\nconvert_global_rinex_for_day "$doy"\ntry_fallback_reference_sites "$doy"\ncheck_available_igs "$doy"\n\'\'\'\n\n# =============================================================================\n# FIXED: get_gamit_step - SOLVE Normal stop + h-file success logic\n# =============================================================================\ndef get_gamit_step(doy: str) -> str:\n    return f"export DOY_NOW={q(doy)}\\n" + r\'\'\'\necho "Running GAMIT for DOY $DOY_NOW..."\ncd "$HOME/$PROJECT" || exit 1\ndoy="$DOY_NOW"\nACTIVE_IGS_FILE="$HOME/$PROJECT/control/active_igs_sites_${doy}.txt"\n\nif [ -s "$ACTIVE_IGS_FILE" ]; then\n  ACTIVE_IGS_SITES=$(cat "$ACTIVE_IGS_FILE")\nelse\n  ACTIVE_IGS_SITES="$IGS_SITES"\nfi\n\n# -----------------------------------------------------------------------------\n# IMPORTANT PATCH: clean per-day RINEX sandbox\n# -----------------------------------------------------------------------------\n# Earlier version allowed sh_gamit cleanup/linking from one day to leave the\n# common rinex/ folder in a mixed state. Then the next day could fail with:\n#   MAKEXP: No RINEX or X-files found\n# This patch keeps rinex_all/ as a master pool and rebuilds rinex/ with ONLY the\n# current DOY files before every sh_gamit run. This prevents previous-day files,\n# compressed cleanup products, truncated downloads, or long-name leftovers from\n# confusing sh_link_rinex.\nprepare_clean_rinex_for_day() {\n  day="$1"\n  mkdir -p rinex rinex_all control\n  echo "Preparing clean per-day RINEX folder for DOY $day..."\n\n  shopt -s nullglob\n  # Save every existing observation/Hatanaka file to the master pool first.\n  for f in rinex/*.${YY}o rinex/*.${YY}d \\\n           rinex/*.${YY}o.gz rinex/*.${YY}o.GZ rinex/*.${YY}o.Z \\\n           rinex/*.${YY}d.gz rinex/*.${YY}d.GZ rinex/*.${YY}d.Z \\\n           rinex/*${YEAR}*.crx.gz rinex/*${YEAR}*.CRX.gz \\\n           rinex/*${YEAR}*.rnx.gz rinex/*${YEAR}*.RNX.gz; do\n    [ -f "$f" ] || continue\n    cp -pf "$f" rinex_all/ 2>/dev/null || true\n  done\n\n  # Remove all observation files from working rinex/ so sh_link_rinex sees\n  # only the current day. Product/nav files are not stored here and are untouched.\n  rm -f rinex/*.${YY}o rinex/*.${YY}d \\\n        rinex/*.${YY}o.gz rinex/*.${YY}o.GZ rinex/*.${YY}o.Z \\\n        rinex/*.${YY}d.gz rinex/*.${YY}d.GZ rinex/*.${YY}d.Z \\\n        rinex/*${YEAR}*.crx.gz rinex/*${YEAR}*.CRX.gz \\\n        rinex/*${YEAR}*.rnx.gz rinex/*${YEAR}*.RNX.gz 2>/dev/null || true\n\n  restore_one_site() {\n    site="$1"\n    day="$2"\n    site_u=$(echo "$site" | tr \'[:lower:]\' \'[:upper:]\')\n    base="${site}${day}0.${YY}"\n    out="rinex/${base}o"\n\n    [ -s "$out" ] && return 0\n\n    if [ -s "rinex_all/${base}o" ]; then\n      cp -pf "rinex_all/${base}o" "$out"\n      return 0\n    fi\n    if [ -s "rinex_all/${base}o.gz" ]; then\n      gunzip -c "rinex_all/${base}o.gz" > "$out" && [ -s "$out" ] && return 0\n    fi\n    if [ -s "rinex_all/${base}o.GZ" ]; then\n      gunzip -c "rinex_all/${base}o.GZ" > "$out" && [ -s "$out" ] && return 0\n    fi\n    if [ -s "rinex_all/${base}o.Z" ]; then\n      gzip -cd "rinex_all/${base}o.Z" > "$out" 2>/dev/null || uncompress -c "rinex_all/${base}o.Z" > "$out"\n      [ -s "$out" ] && return 0\n    fi\n\n    if [ -s "rinex_all/${base}d" ]; then\n      cp -pf "rinex_all/${base}d" "rinex/${base}d"\n      ( cd rinex && crx2rnx "${base}d" >/dev/null 2>&1 )\n      [ -s "$out" ] && return 0\n    fi\n    if [ -s "rinex_all/${base}d.gz" ]; then\n      gunzip -c "rinex_all/${base}d.gz" > "rinex/${base}d" && ( cd rinex && crx2rnx "${base}d" >/dev/null 2>&1 )\n      [ -s "$out" ] && return 0\n    fi\n    if [ -s "rinex_all/${base}d.GZ" ]; then\n      gunzip -c "rinex_all/${base}d.GZ" > "rinex/${base}d" && ( cd rinex && crx2rnx "${base}d" >/dev/null 2>&1 )\n      [ -s "$out" ] && return 0\n    fi\n    if [ -s "rinex_all/${base}d.Z" ]; then\n      gzip -cd "rinex_all/${base}d.Z" > "rinex/${base}d" 2>/dev/null || uncompress -c "rinex_all/${base}d.Z" > "rinex/${base}d"\n      ( cd rinex && crx2rnx "${base}d" >/dev/null 2>&1 )\n      [ -s "$out" ] && return 0\n    fi\n\n    long_crx=$(ls rinex_all/${site_u}*_${YEAR}${day}0000*_01D_30S_MO.crx.gz rinex_all/${site_u}*_${YEAR}${day}0000*_01D_30S_MO.CRX.gz 2>/dev/null | head -1 || true)\n    if [ -n "$long_crx" ] && [ -s "$long_crx" ]; then\n      gunzip -c "$long_crx" > "rinex/${base}d" && ( cd rinex && crx2rnx "${base}d" >/dev/null 2>&1 )\n      [ -s "$out" ] && return 0\n    fi\n    long_rnx=$(ls rinex_all/${site_u}*_${YEAR}${day}0000*_01D_30S_MO.rnx.gz rinex_all/${site_u}*_${YEAR}${day}0000*_01D_30S_MO.RNX.gz 2>/dev/null | head -1 || true)\n    if [ -n "$long_rnx" ] && [ -s "$long_rnx" ]; then\n      gunzip -c "$long_rnx" > "$out" && [ -s "$out" ] && return 0\n    fi\n\n    return 1\n  }\n\n  missing_restore=0\n  for s in $LOCAL_SITES $ACTIVE_IGS_SITES; do\n    if restore_one_site "$s" "$day"; then\n      echo "[OK] restored for GAMIT: $s"\n    else\n      echo "[MISSING] could not restore current-day RINEX: $s"\n      missing_restore=1\n    fi\n  done\n\n  echo "Working rinex/ files for DOY $day:"\n  ls -1 rinex/*${day}0.${YY}o 2>/dev/null | sed \'s#^#  #\' || true\n\n  n_work=$(ls rinex/*${day}0.${YY}o 2>/dev/null | wc -l)\n  if [ "$n_work" -lt 3 ]; then\n    echo "ERROR: Too few current-day RINEX files in working rinex/: $n_work"\n    return 1\n  fi\n  [ "$missing_restore" -eq 0 ] || return 1\n  return 0\n}\n\nrefresh_sites_defaults_for_day() {\n  day="$1"\n  cd "$HOME/$PROJECT/tables" || exit 1\n  cp sites.defaults "sites.defaults.before_gamit_${day}" 2>/dev/null || true\n  {\n    echo "# Active IGS/reference stations for DOY $day"\n    for s in $ACTIVE_IGS_SITES; do echo " ${s}_gps $EXPT ftprnx"; done\n    echo ""\n    echo "# Local CORS stations"\n    for s in $LOCAL_SITES; do echo " ${s}_gps $EXPT localrx"; done\n  } > sites.defaults\n  cd "$HOME/$PROJECT" || exit 1\n}\n\nprepare_clean_rinex_for_day "$doy" || { echo "ERROR: Could not prepare clean RINEX for DOY $doy"; exit 1; }\nrefresh_sites_defaults_for_day "$doy"\n\necho "Local stations      : $LOCAL_SITES"\necho "Active IGS stations : $ACTIVE_IGS_SITES"\n\nmissing=0\nfor s in $LOCAL_SITES; do\n  f="rinex/${s}${doy}0.${YY}o"\n  [ -s "$f" ] && echo "[OK] Local RINEX: $s" || { echo "[MISSING] Local RINEX: $s"; missing=1; }\ndone\nfor s in $ACTIVE_IGS_SITES; do\n  f="rinex/${s}${doy}0.${YY}o"\n  [ -s "$f" ] && echo "[OK] IGS RINEX: $s" || { echo "[MISSING] IGS RINEX: $s"; missing=1; }\ndone\n\nn_igs=$(echo "$ACTIVE_IGS_SITES" | wc -w)\n[ "$n_igs" -ge 3 ] || { echo "ERROR: Less than 3 active IGS stations"; exit 1; }\n[ "$missing" -eq 0 ] || { echo "Required RINEX files are missing"; exit 1; }\n\ndate_ymd=$(date -u -d "${YEAR}-01-01 +$((10#$doy - 1)) days" +%Y%m%d)\ngps_days=$(( ( $(date -u -d "$date_ymd" +%s) - $(date -u -d "1980-01-06" +%s) ) / 86400 ))\ngps_week=$(( gps_days / 7 ))\ngps_dow=$(( gps_days % 7 ))\nsp3_short="igs${gps_week}${gps_dow}.sp3"\n\nif [ "${GAMIT_ORBIT_MODE:-OFFLINE_IGSF}" = "OFFLINE_IGSG" ]; then\n  if find . -maxdepth 3 -type f \\( -name "g*${YY}${doy}*" -o -name "*.g" -o -name "gfile*" \\) | grep -q .; then\n    echo "[OK] Local g-file candidate found for -orbt igsg mode"\n  else\n    echo "[WARNING] No obvious local g-file candidate found. GAMIT may still create/use one depending on tables, but review this before productive offline mode."\n  fi\nelse\n  [ -s "igs/$sp3_short" ] || { echo "Missing SP3: igs/$sp3_short"; exit 1; }\nfi\n[ -s "brdc/brdc${doy}0.${YY}n" ] || { echo "Missing BRDC: brdc/brdc${doy}0.${YY}n"; exit 1; }\n[ -s "ionex/igsg${doy}0.${YY}i" ] || { echo "Missing IONEX: ionex/igsg${doy}0.${YY}i"; exit 1; }\n[ -s "tables/pole.usno" ] || { echo "Missing EOP: tables/pole.usno"; exit 1; }\n[ -s "tables/ut1.usno" ] || { echo "Missing EOP: tables/ut1.usno"; exit 1; }\n\n# Safe rerun handling: never delete the day folder destructively.\nfor cand in "${doy}G" "$doy"; do\n  if [ -d "$cand" ]; then\n    backup="${cand}_backup_$(date +%Y%m%d_%H%M%S)"\n    echo "Existing GAMIT day folder detected: $cand"\n    echo "Moving old folder to timestamped backup: $backup"\n    mv "$cand" "$backup" || exit 1\n  fi\n done\n\ncase "${GAMIT_ORBIT_MODE:-PREFETCH_IGSF_NOFTP}" in\n  PREFETCH_IGSF_NOFTP)\n    orbit_args=(-orbit igsf)\n    noftp_args=(-noftp)\n    mode_label="RECOMMENDED online pre-download + sh_gamit noftp mode (-orbit igsf -noftp)"\n    ;;\n  INTERNET_IGSF)\n    orbit_args=(-orbit igsf)\n    noftp_args=()\n    mode_label="GAMIT-managed internet mode; sh_gamit may download internally"\n    ;;\n  OFFLINE_IGSG)\n    orbit_args=(-orbt igsg)\n    noftp_args=(-noftp)\n    mode_label="strict offline local g-file mode (-orbt igsg -noftp)"\n    ;;\n  OFFLINE_IGSF|*)\n    orbit_args=(-orbit igsf)\n    noftp_args=(-noftp)\n    mode_label="strict offline SP3/final-orbit mode (-orbit igsf -noftp)"\n    ;;\nesac\n\ncmd=(sh_gamit -d "$YY" "$doy" -gnss G -expt "$EXPT" "${orbit_args[@]}" -aprfile "$CUSTOM_APR_FILE" "${noftp_args[@]}" -pres ELEV)\n\necho "Command preview / orbit mode: $mode_label"\nprintf \'  %q\' "${cmd[@]}"; echo\n\necho "Product source note: Do not silently switch between -orbit igsf and -orbt igsg. Current mode is ${GAMIT_ORBIT_MODE:-PREFETCH_IGSF_NOFTP}."\nif [ "${GAMIT_ORBIT_MODE:-PREFETCH_IGSF_NOFTP}" = "PREFETCH_IGSF_NOFTP" ]; then\n  echo "[OK] Recommended mode active: SP3/IONEX/BRDC/IGS RINEX were prepared before this step; sh_gamit will not run internal FTP/CDDIS download."\nfi\n\nif [ "${AUTOM_GAMIT_DRY_RUN:-0}" = "1" ]; then\n  echo "[DRY-RUN] sh_gamit command was previewed but not executed."\n  exit 0\nfi\n\n"${cmd[@]}" 2>&1 | tee "sh_gamit_${doy}.log"\nrc=${PIPESTATUS[0]}\necho "sh_gamit return code: $rc"\n\nsolve_ok=0\nhfile_ok=0\n\nif grep -qi "SOLVE/solve: Normal stop" "sh_gamit_${doy}.log"; then\n  solve_ok=1\n  echo "[OK] DOY $doy completed with SOLVE Normal stop."\nelse\n  echo "[ERROR] SOLVE Normal stop not found."\n  grep -Ei "FATAL|ERROR|Normal stop|STOP|No RINEX|No X-files|No RINEX or X-files" "sh_gamit_${doy}.log" | tail -120 || true\nfi\n\nif ls "${doy}G"/h*.${YY}${doy} >/dev/null 2>&1; then\n  hfile_ok=1\n  echo "[OK] Real GAMIT h-file created:"\n  ls -lh "${doy}G"/h*.${YY}${doy}\nelse\n  echo "[ERROR] No real h-file h*.${YY}${doy} was detected."\n  ls -lh "${doy}G"/h* 2>/dev/null || true\nfi\n\nif [ "$solve_ok" -eq 1 ] && [ "$hfile_ok" -eq 1 ]; then\n  if [ "$rc" -ne 0 ]; then\n    echo "[WARNING] sh_gamit returned code $rc, but SOLVE Normal stop and h-file are present."\n    echo "[WARNING] Treating this day as successful but please review the log."\n  fi\nelse\n  echo "[ERROR] GAMIT day $doy failed because SOLVE Normal stop or h-file is missing."\n  echo "[INFO] Current working rinex files were:"\n  ls -lh rinex/*${doy}0.${YY}o 2>/dev/null || true\n  exit 1\nfi\n\nreal_fatal_lines=$(grep -Ei "FATAL" "sh_gamit_${doy}.log" | grep -Evi "Removing existing GAMIT\\.\\[status\\]\\[warning\\]\\[fatal\\] files" | grep -Evi "GAMIT\\.\\[status\\]\\[warning\\]\\[fatal\\]" || true)\nif [ -n "$real_fatal_lines" ]; then\n  echo "[WARNING] Word FATAL found in log, but SOLVE Normal stop and h-file were reached."\n  echo "$real_fatal_lines" | tail -30\nfi\n\'\'\'\n\n# =============================================================================\n# get_qc_step - Shows local stations individually\n# =============================================================================\ndef get_qc_step(doy: str) -> str:\n    return f"export DOY_NOW={q(doy)}\\n" + r\'\'\'\necho "Quality check for DOY $DOY_NOW..."\ncd "$HOME/$PROJECT" || exit 1\ndoy="$DOY_NOW"\ndaydir=""\nfor cand in "${doy}G" "$doy"; do\n  if [ -d "$cand" ]; then daydir="$cand"; break; fi\ndone\nif [ -z "$daydir" ]; then\n  echo "[WARNING] No DDD or DDDG day folder found yet for DOY $doy"\n  daydir="${doy}G"\nfi\necho "Using day folder for QC: $daydir"\n\necho "----- SOLVE/FATAL/ERROR status -----"\ngrep -i "SOLVE/solve: Normal stop\\|FATAL\\|ERROR" "sh_gamit_${doy}.log" 2>/dev/null | grep -vi "GAMIT.\\[status\\]\\[warning\\]\\[fatal\\]" | tail -100 || true\n\necho ""\necho "----- NRMS -----"\nfor sf in "${daydir}/sh_gamit_${doy}G.summary" "${daydir}/sh_gamit_${doy}.summary" "${daydir}/sh_gamit.summary"; do\n  [ -s "$sf" ] && { grep -i "nrms" "$sf" 2>/dev/null; break; }\ndone || echo "No NRMS found"\n\necho ""\necho "----- H-files -----"\nls -lh "${daydir}"/h*.${YY}${doy} 2>/dev/null || echo "No real h-file h*.${YY}${doy} found"\n\necho ""\necho "----- Local station AUTCLN summary -----"\nif [ -s "${daydir}/autcln.post.sum" ]; then\n  found=0\n  for s in $LOCAL_SITES; do\n    U=$(echo "$s" | tr \'[:lower:]\' \'[:upper:]\')\n    if grep -q "$U" "${daydir}/autcln.post.sum"; then\n      found=1\n      echo ""\n      echo "### $U ###"\n      grep "$U" "${daydir}/autcln.post.sum" | head -20\n    fi\n  done\n  if [ "$found" -eq 0 ]; then\n    echo "No local station names directly found in autcln.post.sum."\n    head -40 "${daydir}/autcln.post.sum"\n  fi\nelse\n  echo "autcln.post.sum not found"\nfi\n\necho ""\necho "----- BAD Pre-RNG -----"\nzgrep -i "BAD Pre-RNG" "${daydir}/autcln.out.gz" 2>/dev/null | head -50 || echo "No BAD Pre-RNG lines found"\n\necho "QC complete for DOY $doy."\n\'\'\'\n\n# =============================================================================\n# SCRIPT RUNNER\n# =============================================================================\ndef export_block(settings: Dict[str, str]) -> str:\n    lines = ["set -o pipefail", "set +e"]\n    for k in [\n        "PROJECT", "EXPT", "YEAR", "YY", "START_DOY", "NDAYS",\n        "SOURCE_RINEX_DIR", "LOCAL_SITES", "IGS_SITES", "EXCLUDE_SITES",\n        "RENAME_SITE", "RENAME_PAIRS", "CONFLICT_SITE", "REF_FRAME",\n        "APR_FILE", "CUSTOM_APR_FILE", "NOFTP_FLAG", "FRESH_START",\n        "DOWNLOAD_GLOBAL_RINEX", "STRICT_NOFTP_CHECK", "GAMIT_ORBIT_MODE", "PRES_OPTION", "AUTOM_GAMIT_DRY_RUN", "FALLBACK_IGS_SITES",\n    ]:\n        lines.append(f"export {k}={q(settings.get(k, \'\'))}")\n    lines.append("export END_DOY=$((10#$START_DOY + NDAYS - 1))")\n    return "\\n".join(lines) + "\\n"\n\ndef run_bash_script(step_name: str, bash_code: str, settings: Dict[str, str], log_dir: Path) -> bool:\n    safe = "".join(c if c.isalnum() else "_" for c in step_name.lower())[:60]\n    script_path = log_dir / f"{safe}.sh"\n    log_path = log_dir / f"{safe}.log"\n    script_path.write_text(export_block(settings) + "\\n" + bash_code, encoding="utf-8")\n    os.chmod(script_path, 0o755)\n    if os.environ.get("AUTOM_GAMIT_DRY_RUN", "0") == "1":\n        print_progress(f"[DRY-RUN] Step script written but not executed: {step_name}")\n        print_info(f"Script: {script_path}")\n        print_info("No shell commands were executed in this step.")\n        return True\n    print_progress(f"Running step: {step_name}")\n    print_info(f"Script: {script_path}")\n    print_info(f"Log   : {log_path}")\n    proc = None\n    rc = 1\n    try:\n        with open(log_path, "w", encoding="utf-8", errors="ignore") as log:\n            proc = subprocess.Popen(\n                ["/bin/bash", str(script_path)],\n                stdout=subprocess.PIPE,\n                stderr=subprocess.STDOUT,\n                text=True,\n                bufsize=1,\n                preexec_fn=os.setsid,\n            )\n            assert proc.stdout is not None\n            for line in proc.stdout:\n                print(line, end="")\n                log.write(line)\n            rc = proc.wait()\n    except KeyboardInterrupt:\n        print_warning("User pressed Ctrl+C")\n        if proc is not None:\n            try:\n                os.killpg(os.getpgid(proc.pid), signal.SIGTERM)\n            except Exception:\n                pass\n        return False\n    if rc == 0:\n        print_success(f"Step finished: {step_name}")\n        return True\n    print_error(f"Step failed: {step_name} | Return code: {rc}")\n    print_info(f"Check log: {log_path}")\n    return False\n\ndef run_critical(step_name: str, bash_code: str, settings: Dict[str, str], log_dir: Path, allow_continue: bool = False) -> None:\n    stage_control_before(step_name, settings)\n    while True:\n        ok = run_bash_script(step_name, bash_code, settings, log_dir)\n        if ok:\n            stage_control_after(step_name, settings)\n            return\n        print_stage_method(step_name, settings)\n        print_warning("This stage did not complete. Read the method/implication above and choose what to do.")\n        ans = ask_retry_continue_quit()\n        if ans == "r":\n            continue\n        if ans == "c":\n            if allow_continue:\n                print_warning("Continuing because this stage was marked as optional/allow_continue.")\n                stage_control_after(step_name, settings)\n                return\n            print_warning("Continuing a critical failed step can break later steps.")\n            if ask_yes_no("Continue anyway?", "no"):\n                stage_control_after(step_name, settings)\n                return\n            continue\n        sys.exit(1)\n\n# =============================================================================\n# DATA-FIRST DECISION HELPERS\n# =============================================================================\ndef expected_doy_list(start_doy: str, ndays: str) -> List[str]:\n    start = int(norm_doy(start_doy))\n    n = int(ndays)\n    return [f"{d:03d}" for d in range(start, start + n)]\n\ndef file_doy(file_path: str, yy: str) -> str | None:\n    core = strip_rinex_suffix(Path(file_path).name, yy)\n    if core is None or len(core) < 7:\n        return None\n    return core[4:7]\n\ndef prefer_file(files: List[str]) -> str:\n    def rank(name: str) -> int:\n        if re.search(r"\\.\\d\\do$", name):\n            return 0\n        if re.search(r"\\.\\d\\do\\.(gz|GZ)$", name):\n            return 1\n        if re.search(r"\\.\\d\\dd$", name):\n            return 2\n        if re.search(r"\\.\\d\\dd\\.(gz|GZ)$", name):\n            return 3\n        return 9\n    return sorted(files, key=lambda f: (rank(Path(f).name), Path(f).name))[0]\n\ndef station_quality(info: dict, expected_doys: List[str], yy: str) -> Dict[str, object]:\n    by_doy: Dict[str, List[str]] = {}\n    for f in info.get("files", []):\n        d = file_doy(f, yy)\n        if d:\n            by_doy.setdefault(d, []).append(f)\n    available = []\n    missing = []\n    partial = []\n    need_conversion = []\n    epochs = []\n    for d in expected_doys:\n        files = by_doy.get(d, [])\n        if not files:\n            missing.append(d)\n            continue\n        available.append(d)\n        f = prefer_file(files)\n        name = Path(f).name\n        if re.search(r"\\.\\d\\dd(\\.gz|\\.GZ|\\.Z)?$", name) or name.endswith(".Z"):\n            need_conversion.append(d)\n            continue\n        md = read_rinex_metadata(f)\n        ep = int(md.get("num_epochs", 0) or 0)\n        epochs.append(ep)\n        if ep < 2500:\n            partial.append(d)\n    if len(available) == 0:\n        status = "NO_DATA"\n    elif missing:\n        status = "MISSING_DAYS"\n    elif partial:\n        status = "PARTIAL"\n    elif need_conversion:\n        status = "NEEDS_CONV"\n    else:\n        status = "OK"\n    return {\n        "available": available,\n        "missing": missing,\n        "partial": partial,\n        "need_conversion": need_conversion,\n        "min_epochs": min(epochs) if epochs else None,\n        "max_epochs": max(epochs) if epochs else None,\n        "status": status,\n    }\n\ndef show_data_decision_table(station_info: Dict[str, dict], expected_doys: List[str], yy: str) -> None:\n    print_header("DATA STATUS TABLE - DECIDE AFTER SEEING THIS")\n    print_info("Station code shown here is only the source RINEX file code.")\n    print_info("After this table, you will decide: keep, exclude, or rename.")\n    print_info("Expected DOYs: " + " ".join(expected_doys))\n    print()\n    print(f"{\'Source\':<8} {\'Files\':>5} {\'Days\':>9} {\'Missing\':<18} {\'Partial\':<18} {\'Epochs min-max\':<15} {\'Status\':<12}")\n    print(ctext("-" * 95, Colors.CYAN))\n    for st in sorted(station_info):\n        qinfo = station_quality(station_info[st], expected_doys, yy)\n        files = len(station_info[st].get("files", []))\n        days = f"{len(qinfo[\'available\'])}/{len(expected_doys)}"\n        missing = " ".join(qinfo["missing"]) if qinfo["missing"] else "-"\n        partial = " ".join(qinfo["partial"]) if qinfo["partial"] else "-"\n        ep = "-" if qinfo["min_epochs"] is None else f"{qinfo[\'min_epochs\']}-{qinfo[\'max_epochs\']}"\n        status = str(qinfo["status"])\n        color = Colors.GREEN if status == "OK" else (Colors.YELLOW if status in ("NEEDS_CONV", "PARTIAL") else Colors.RED)\n        print(f"{st:<8} {files:>5} {days:>9} {missing:<18} {partial:<18} {ep:<15} {ctext(f\'{status:<12}\', color)}")\n    print(ctext("-" * 95, Colors.CYAN))\n    print_info("You may still process a PARTIAL station if you want. The program does not decide for you.")\n\ndef station_detail_loop(station_info: Dict[str, dict]) -> None:\n    while ask_yes_no("View detailed header/epoch information for any station?", "no"):\n        st = ask_input("Enter station code to view details", "").lower().strip()\n        if st:\n            show_station_details(st, station_info)\n\ndef get_partial_stations(station_info: Dict[str, dict], expected_doys: List[str], yy: str) -> Tuple[List[str], List[str]]:\n    partial = []\n    ok = []\n    for st in station_info:\n        qinfo = station_quality(station_info[st], expected_doys, yy)\n        status = qinfo.get("status", "NO_DATA")\n        if status in ("OK", "NEEDS_CONV"):\n            ok.append(st)\n        else:\n            partial.append(st)\n    return sorted(partial), sorted(ok)\n\ndef ask_source_station_selection(stations: List[str], station_info: Dict[str, dict], expected_doys: List[str], yy: str) -> Tuple[str, str]:\n    print_header("SELECT SOURCE STATIONS FOR PROCESSING")\n    partial_stations, ok_stations = get_partial_stations(station_info, expected_doys, yy)\n    detected_sites = sorted(stations)\n    default_keep = ok_stations.copy() if ok_stations else detected_sites.copy()\n    default_text = " ".join(default_keep)\n    if partial_stations:\n        print_warning("The following stations have partial/missing data:")\n        for st in partial_stations:\n            qinfo = station_quality(station_info[st], expected_doys, yy)\n            print(f"  {st}: missing={qinfo.get(\'missing\', [])}, partial={qinfo.get(\'partial\', [])}")\n        if ask_yes_no(f"Exclude all partial stations ({len(partial_stations)} station(s)) from processing?", "yes"):\n            default_keep = [s for s in default_keep if s not in partial_stations]\n            default_text = " ".join(default_keep)\n    print_success("Detected local RINEX stations: " + " ".join(detected_sites))\n    print_info("Default keep list: " + (default_text if default_text else "None"))\n    print_info("Type all to keep all detected stations.")\n    while True:\n        selected = norm_sites(ask_input("Source station codes to keep", default_text))\n        if selected.strip().lower() == "all":\n            selected_list = detected_sites\n            selected = " ".join(detected_sites)\n        else:\n            if selected == "":\n                selected = default_text\n            selected_list = station_list(selected)\n        unknown = sorted(set(selected_list) - set(detected_sites))\n        if unknown:\n            print_error("Station codes not found in scan: " + " ".join(unknown))\n            continue\n        if not selected_list:\n            print_error("At least one source station must be selected.")\n            continue\n        selected_partial = [s for s in selected_list if s in partial_stations]\n        if selected_partial and not ask_yes_no("Continue with selected PARTIAL stations?", "no"):\n            continue\n        exclude_sites = " ".join(sorted(set(detected_sites) - set(selected_list)))\n        print_success("Source stations selected: " + selected)\n        print_warning("Stations to exclude: " + (exclude_sites if exclude_sites else "None"))\n        if ask_yes_no("Confirm this station selection?", "yes"):\n            return selected, exclude_sites\n\ndef ask_rename_pairs_data_first(source_sites: str, apr_file: str) -> Tuple[str, str, str, str]:\n    print_header("OPTIONAL RENAME - USER DECIDES")\n    source_list = station_list(source_sites)\n    apr_matches = [s for s in source_list if apr_has_station(apr_file, s)]\n    if apr_matches:\n        print_warning("Selected source codes also appear in APR file: " + " ".join(apr_matches))\n    rename_pairs_str = ""\n    if ask_yes_no("Do you want to rename any selected source station?", "no"):\n        while True:\n            rename_pairs_str = norm_sites(ask_input("Enter rename pairs, example old:new", ""))\n            pairs = parse_rename_pairs(rename_pairs_str)\n            if not pairs:\n                rename_pairs_str = ""\n                break\n            old_names = [old for old, _ in pairs]\n            unknown_old = sorted(set(old_names) - set(source_list))\n            bad = [f"{old}:{new}" for old, new in pairs if not validate_station_code(old) or not validate_station_code(new)]\n            if unknown_old:\n                print_error("Rename OLD code not selected: " + " ".join(unknown_old))\n                continue\n            if bad:\n                print_error("Invalid rename pairs: " + " ".join(bad))\n                continue\n            break\n    pairs = parse_rename_pairs(rename_pairs_str)\n    rename_map = {old: new for old, new in pairs}\n    final_sites = " ".join([rename_map.get(s, s) for s in source_list])\n    rename_site = "YES" if pairs else "NO"\n    default_conflicts = [old.upper() for old, _new in pairs if apr_has_station(apr_file, old)]\n    conflict_site = ""\n    if default_conflicts:\n        text = " ".join(sorted(set(default_conflicts)))\n        if ask_yes_no("Remove old renamed station entries from custom APR? " + text, "yes"):\n            conflict_site = normalize_conflict_sites(text)\n    if ask_yes_no("Do you want to manually enter any APR conflict site to remove?", "no"):\n        manual = ask_input("APR conflict site(s), example HYDE ABCD or HYDE_GPS", conflict_site.replace("_GPS", ""))\n        conflict_site = normalize_conflict_sites(manual)\n    print_success("Final GAMIT local station codes: " + final_sites)\n    print_success("Rename setting: " + rename_site + (f" ({rename_pairs_str})" if rename_pairs_str else ""))\n    print_success("APR conflict removal: " + (conflict_site if conflict_site else "None"))\n    return final_sites, rename_site, rename_pairs_str, conflict_site\n\n\ndef print_frame_family_note() -> None:\n    print_header("IGS / ITRF FRAME NOTE")\n    print_info("ITRF is the official global terrestrial reference frame; IGS is the GNSS realization aligned to it.")\n    print_info("So IGS20 / ITRF2020 is one consistent frame family, not two separate choices.")\n    print_info("Use one family throughout the run: IGS20 with 20-series APR/products, IGS14 with 14-series APR/products, or IGS08 with 08/ITRF2008 APR/products.")\n    print_info("The launcher now removes non-selected APR-family files from the project tables after sh_setup to avoid mixed-frame confusion.")\n\n\ndef choose_reference_frame_and_apr() -> Tuple[str, str, str]:\n    print_header("REFERENCE FRAME AND APR FILE")\n    print_frame_family_note()\n    frame_options = ["IGS20 / ITRF2020", "IGS14 / ITRF2014", "IGS08 / ITRF2008"]\n    frame_index = ask_choice_index("Choose APR/frame family", frame_options, 0)\n    ref_frame = ["IGS20", "IGS14", "IGS08"][frame_index]\n\n    apr_file = auto_select_apr_file(ref_frame)\n    while True:\n        if not apr_file or not (Path.home() / "gg" / "tables" / apr_file).is_file():\n            show_available_apr_files()\n            default = {\n                "IGS20": "igb20_comb.apr",\n                "IGS14": "igs14_comb.apr",\n                "IGS08": "All_PBO_igs08.apr",\n            }.get(ref_frame, apr_file)\n            apr_file = ask_input("Enter APR file name exactly from ~/gg/tables", default)\n        else:\n            print_success(f"Auto-selected APR file: {apr_file}")\n            if not ask_yes_no("Use this APR file?", "yes"):\n                show_available_apr_files()\n                apr_file = ask_input("Enter APR file name exactly from ~/gg/tables", apr_file)\n\n        if not (Path.home() / "gg" / "tables" / apr_file).is_file():\n            print_error(f"APR file not found in ~/gg/tables/: {apr_file}")\n            apr_file = ""\n            continue\n\n        if apr_matches_frame_name(ref_frame, apr_file):\n            break\n\n        print_error("APR file does not match selected reference frame.")\n        print_error(f"Selected frame: {ref_frame}")\n        print_error(f"Selected APR  : {apr_file}")\n        print_info("Examples:")\n        print("  IGS20 -> igb20_comb.apr / igs20.apr / itrf20*.apr")\n        print("  IGS14 -> igs14_comb.apr / igb14_comb.apr / itrf14*.apr")\n        print("  IGS08 -> All_PBO_igs08.apr / igs08_comb.apr / igb08_comb.apr / itrf08*.apr")\n        apr_file = ""\n\n    custom_apr_file = f"custom_{ref_frame.lower()}.apr"\n    print_success(f"Reference frame locked: {ref_frame}")\n    print_success(f"APR file locked       : {apr_file}")\n    print_success(f"Custom APR will be    : {custom_apr_file}")\n    return ref_frame, apr_file, custom_apr_file\n\n\n\ndef find_gamit_day_dir(project_dir: Path, doy: str) -> Path:\n    """Support both GAMIT day folder styles: DDDG and DDD."""\n    for name in (f"{doy}G", doy):\n        p = project_dir / name\n        if p.is_dir():\n            return p\n    return project_dir / f"{doy}G"\n\n\ndef find_first_existing(paths: List[Path]) -> Path | None:\n    for p in paths:\n        if p.is_file():\n            return p\n    return None\n\n\ndef parse_strict_daily_qc(project_dir: Path, doy: str, yy: str, local_sites: List[str]) -> Dict[str, object]:\n    """Parse practical one-day/full-day QC items from DDD or DDDG folders."""\n    day_dir = find_gamit_day_dir(project_dir, doy)\n    log_file = project_dir / f"sh_gamit_{doy}.log"\n    summary_file = find_first_existing([\n        day_dir / f"sh_gamit_{doy}G.summary",\n        day_dir / f"sh_gamit_{doy}.summary",\n        day_dir / "sh_gamit.summary",\n    ])\n    text = ""\n    if summary_file:\n        text += summary_file.read_text(errors="ignore") + "\\n"\n    if log_file.is_file():\n        text += log_file.read_text(errors="ignore") + "\\n"\n    result: Dict[str, object] = {\n        "day_dir": str(day_dir),\n        "summary_file": str(summary_file) if summary_file else "",\n        "total_xfiles": None,\n        "rms_values": [],\n        "postfit_nrms": [],\n        "prefit_nrms": [],\n        "zero_rms_warning": False,\n        "zero_observation_warning": False,\n        "lfile_update_gt_0_3m": False,\n        "missing_local_stations": [],\n    }\n    m = re.search(r"Total\\s+xfiles\\s*[:=]?\\s*(\\d+)", text, re.I)\n    if m:\n        result["total_xfiles"] = int(m.group(1))\n    for m in re.finditer(r"\\bRMS\\b[^0-9\\n-]*([-+]?\\d+(?:\\.\\d+)?)", text, re.I):\n        try: result["rms_values"].append(float(m.group(1)))\n        except Exception: pass\n    for m in re.finditer(r"Postfit\\s+nrms\\s*[:=]?\\s*([-+]?\\d+(?:\\.\\d+)?)", text, re.I):\n        try: result["postfit_nrms"].append(float(m.group(1)))\n        except Exception: pass\n    for m in re.finditer(r"Prefit\\s+nrms\\s*[:=]?\\s*([-+]?\\d+(?:\\.\\d+)?)", text, re.I):\n        try: result["prefit_nrms"].append(float(m.group(1)))\n        except Exception: pass\n    result["zero_rms_warning"] = bool(re.search(r"\\b0+(?:\\.0+)?\\s*(?:m)?\\s*RMS\\b|\\bRMS\\s*[:=]?\\s*0+(?:\\.0+)?\\b|zero\\s+RMS", text, re.I))\n    result["zero_observation_warning"] = bool(re.search(r"zero\\s+obs|0\\s+observations|no\\s+observations|no\\s+data", text, re.I))\n    result["lfile_update_gt_0_3m"] = bool(re.search(r"lfile.*(?:update|change).*([3-9]\\d{2,}|0\\.[3-9]|[1-9]\\.)\\s*m", text, re.I))\n    # Station presence in h-file\n    hfiles = sorted([p for p in day_dir.glob(f"h*.{yy}{doy}") if p.is_file() and p.stat().st_size > 0])\n    htext = hfiles[0].read_text(errors="ignore").upper() if hfiles else ""\n    missing = []\n    for s in local_sites:\n        if s.upper() not in htext:\n            missing.append(s.upper())\n    result["missing_local_stations"] = missing\n    return result\n\n\ndef print_strict_qc_report(project_dir: Path, doy: str, yy: str, local_sites: List[str]) -> bool:\n    qc = parse_strict_daily_qc(project_dir, doy, yy, local_sites)\n    print_info(f"  QC day folder: {qc[\'day_dir\']}")\n    if qc.get("summary_file"):\n        print_info(f"  QC summary file: {qc[\'summary_file\']}")\n    tx = qc.get("total_xfiles")\n    if tx is not None:\n        print_success(f"  Total xfiles: {tx}")\n    else:\n        print_warning("  Total xfiles not parsed")\n    pnrms = qc.get("postfit_nrms") or []\n    if pnrms:\n        maxn = max(pnrms)\n        msg = ", ".join(f"{v:.4f}" for v in pnrms)\n        if maxn <= 0.2:\n            print_success(f"  Postfit NRMS target met (<=0.2): {msg}")\n        else:\n            print_warning(f"  Postfit NRMS above strict 0.2 target; review: {msg}")\n    else:\n        print_warning("  Postfit NRMS not parsed")\n    if qc.get("zero_rms_warning"):\n        print_warning("  Zero RMS clue found; check if solution has no real observations")\n    if qc.get("zero_observation_warning"):\n        print_warning("  zero-observation/no-data clue found")\n    if qc.get("lfile_update_gt_0_3m"):\n        print_warning("  lfile coordinate update >0.3 m clue found; backup day folder and rerun after lfile update")\n    missing = qc.get("missing_local_stations") or []\n    if missing:\n        print_warning("  Local stations missing from h-file: " + ", ".join(missing))\n    nrms_bad = (not pnrms) or (max(pnrms) > 0.2)\n    return not (nrms_bad or qc.get("zero_rms_warning") or qc.get("zero_observation_warning") or qc.get("lfile_update_gt_0_3m") or missing)\n\n# =============================================================================\n# FIXED: postprocess_summary - robust station parser, uppercase content\n# =============================================================================\ndef postprocess_summary(settings: Dict[str, str], doy_list: List[str], log_dir: Path) -> None:\n    project_dir = Path.home() / settings["PROJECT"]\n    yy = settings["YY"]\n\n    print_header("APR / ITRF CONFIRMATION FOR ALL DAYS")\n    for doy in doy_list:\n        log = project_dir / f"sh_gamit_{doy}.log"\n        print()\n        print(f"DOY {doy}")\n        if not log.exists():\n            print_warning(f"  Missing log: {log}")\n            continue\n        text = log.read_text(errors="ignore")\n        m = re.search(r"Input options -d .*?-aprfile\\s+(\\S+)", text)\n        if m:\n            print_success(f"  APR file used by sh_gamit: {m.group(1)}")\n        else:\n            print_info(f"  APR file expected from settings: {settings[\'CUSTOM_APR_FILE\']}")\n        print_success(f"  Selected frame family: {settings[\'REF_FRAME\']}")\n        for line in text.splitlines():\n            if "Updating lfile. with coordinates from:" in line:\n                print_info("  " + line.strip())\n                break\n\n    print_header("H-FILE AND SOLUTION CHECK - ALL DAYS")\n    good_days = 0\n\n    for doy in doy_list:\n        day_dir = find_gamit_day_dir(project_dir, doy)\n        hfiles = sorted([p for p in day_dir.glob(f"h*.{yy}{doy}") if p.is_file() and p.stat().st_size > 0])\n        summary_file = find_first_existing([day_dir / f"sh_gamit_{doy}G.summary", day_dir / f"sh_gamit_{doy}.summary", day_dir / "sh_gamit.summary"]) or (day_dir / f"sh_gamit_{doy}G.summary")\n        log_file = project_dir / f"sh_gamit_{doy}.log"\n\n        print()\n        print(ctext(f"DOY {doy}", Colors.CYAN + Colors.BOLD))\n\n        log_ok = False\n        if log_file.exists():\n            log_text = log_file.read_text(errors="ignore")\n            log_ok = "SOLVE/solve: Normal stop" in log_text\n            print_success("  SOLVE Normal stop found") if log_ok else print_warning("  SOLVE Normal stop not found")\n        else:\n            print_warning("  sh_gamit log not found")\n\n        station_ok = False\n        if hfiles:\n            hfile = hfiles[0]\n            print_success(f"  H-file: {hfile.name} ({hfile.stat().st_size} bytes)")\n            content = hfile.read_text(errors="ignore").upper()\n            station_markers = sorted(set(re.findall(r"\\b([A-Z0-9]{4}_[A-Z0-9]{3})\\b", content)))\n            station_codes = sorted(set(m.split("_")[0] for m in station_markers))\n            m_count = re.search(r"Number of stations:\\s*([0-9]+)", content, re.IGNORECASE)\n            if m_count:\n                header_count = int(m_count.group(1))\n                print_success(f"  Number of stations from h-file header: {header_count}")\n            print_success(f"  Unique station codes parsed from h-file: {len(station_codes)}")\n            if station_codes:\n                print_info(\n                    "  Stations: "\n                    + " ".join(station_codes[:25])\n                    + (f" ... +{len(station_codes)-25} more" if len(station_codes) > 25 else "")\n                )\n            local_upper = [s.upper() for s in station_list(settings["LOCAL_SITES"])]\n            found = [s for s in local_upper if s in station_codes]\n            missing = [s for s in local_upper if s not in station_codes]\n            if found:\n                print_success("  Local stations found: " + ", ".join(found))\n            if missing:\n                print_warning("  Local stations missing: " + ", ".join(missing))\n            station_ok = len(missing) == 0\n        else:\n            print_warning("  H-file not found")\n\n        nrms_vals = []\n        if summary_file.exists():\n            with open(summary_file, "r", errors="ignore") as f:\n                for line in f:\n                    if "Postfit nrms:" in line:\n                        try:\n                            nrms_vals.append(float(line.split("Postfit nrms:")[1].strip().split()[0]))\n                        except Exception:\n                            pass\n            if nrms_vals:\n                print_success("  Postfit NRMS values: " + ", ".join(f"{v:.4f}" for v in nrms_vals))\n                print_success("  NRMS quality looks good") if max(nrms_vals) < 0.5 else print_warning("  NRMS needs review")\n            else:\n                print_info("  No Postfit NRMS values parsed")\n        else:\n            print_warning("  Summary file not found")\n\n        strict_ok = print_strict_qc_report(project_dir, doy, yy, station_list(settings["LOCAL_SITES"]))\n\n        if log_ok and hfiles and nrms_vals and max(nrms_vals) < 0.5 and station_ok and strict_ok:\n            good_days += 1\n\n    print_header("FINAL GAMIT STATUS")\n    print_success(f"Good-looking days: {good_days}/{len(doy_list)}")\n    if good_days == len(doy_list):\n        print_success("GAMIT run is successful for all processed days.")\n    else:\n        print_warning("Some days need review. Check logs and h-files above.")\n\n    print_header("NEXT STEPS FOR GLOBK")\n    print_info("GLOBK/GLORG is not run in this program.")\n    print(f"  cd ~/{settings[\'PROJECT\']}")\n    print(f"  find . -path \'./???G/h*.{settings[\'YY\']}???\' -type f | sort > hfile_list.txt")\n    print("  # Then run separate autom_globk.py or prepare proper GLOBK command/control files")\n    print_warning("For final scientific results, correct antenna heights and receiver/antenna metadata in station.info.")\n    print_info(f"Processing logs are saved in: {log_dir}")\n\n\n\n\n\ndef write_doc101_doc126_gamit_notes(settings: Dict[str, str], doy_list: List[str], log_dir: Path) -> Path:\n    """Save practical GAMIT notes extracted from uploaded Doc-101 and Doc-126 PDFs."""\n    project_dir = Path.home() / settings["PROJECT"]\n    out = log_dir / "doc101_doc126_gamit_practical_notes.txt"\n    out.parent.mkdir(parents=True, exist_ok=True)\n    text = f"""DOC-101 / DOC-126 GAMIT PRACTICAL NOTES ADDED\n\n1. Tables folder meaning\n   - tables/ is the processing recipe folder for a year/project.\n   - Core files include sites.defaults, process.defaults, station.info, lfile., sestbl., sittbl., autcln.cmd, EOP/model files, and APR/reference files.\n\n2. process.defaults safety\n   - The selected APR family must be enforced after sh_setup because sh_setup/process.defaults may still point to an older default such as igb14_comb.apr.\n   - RINEX path, brdc path, igs path, gfiles path, and sky-plot output path must be consistent with the project folder.\n\n3. station.info importance\n   - station.info is the metadata catalog for receiver, receiver serial, antenna type, antenna height, offsets, marker, and session dates.\n   - Wrong antenna model/height can introduce centimeter-level bias and cannot be fixed by good network geometry.\n   - Recommended workflow: reduce station.info using selected IGS/reference sitelist, then update local CORS from selected RINEX only.\n   - Useful forms shown in uploaded notes include:\n       sh_upd_stnfo -l sitelist\n       mv station.info.new station.info\n       sh_upd_stnfo -ref station.info -files ../rinex/*.YYo -w station.info\n\n4. Product preparation\n   - For offline/noftp workflow, check/download IGS/reference RINEX, precise orbit, BRDC navigation, IONEX, pole.usno, ut1.usno, and otl_FES2004.grid before sh_gamit.\n   - For multi-GNSS products the notes mention CODM orbit products, while GPS-only final orbit examples use IGSF.\n\n5. sh_gamit workflow\n   - Process one day first, inspect the summary, then process the full span with the same settings.\n   - Day folders can be DDDG when -gnss G is used, or DDD without -gnss.\n   - The program must check both forms.\n\n6. Daily QC rules emphasized in Doc-101/Doc-126\n   - Total xfiles should match the number of used RINEX files, including IGS + CORS.\n   - Average RMS should generally be less than about 8 mm in the training slides; 10 mm is a broader practical warning limit.\n   - Postfit NRMS should generally be less than about 0.2 for a good solution.\n   - If station coordinate adjustment/update is greater than 0.3 m, back up the day folder and rerun after coordinate update.\n   - If station is missing, check h-file station observation count, l-file last-line coordinate entry, and approximate XYZ.\n   - If station has zero observation or zero RMS, check RINEX receiver/header metadata; the notes specifically warn about incomplete receiver names such as missing TRIMBLE in TRIMBLE ALLOY.\n\n7. Error-handling reminders\n   - Missing SP3/g-file: check igs/gfiles product folder and noftp product preparation.\n   - Missing BRDC: check brdc/brdcDDD0.YYn or compressed .Z form.\n   - Missing pole/UT1: copy/fix pole.usno and ut1.usno in relevant tables/processing folders.\n   - Missing/corrupt ocean loading: replace/download otl_FES2004.grid; do not silently disable OTL for production.\n   - Sestbl/sittbl formatting is space-sensitive; avoid tabs and preserve column alignment.\n\n8. Installation/environment reminders\n   - Productive checks should verify sh_gamit, solve, autcln, sh_glred, globk, glorg, htoglb, crx2rnx, sh_setup, and sh_upd_stnfo in PATH.\n   - Linux dependencies mentioned in the notes include make, csh/tcsh, X11 libraries, gcc/gfortran, and GMT for plotting.\n   - Existing installations should be checked using commands such as which sh_gamit, which solve, and which autcln.\n\nProcessed DOYs in this run: {\', \'.join(doy_list)}\nProject: {project_dir}\n"""\n    out.write_text(text, encoding="utf-8")\n    print_success(f"Saved Doc-101/Doc-126 GAMIT practical notes: {out}")\n    return out\n\n\n\ndef write_doc151_doc176_gamit_notes(settings: Dict[str, str], doy_list: List[str], log_dir: Path) -> Path:\n    """Save practical notes extracted from uploaded Doc-151 and Doc-176 PDFs."""\n    project_dir = Path.home() / settings["PROJECT"]\n    out = log_dir / "doc151_doc176_gamit_practical_notes.txt"\n    out.parent.mkdir(parents=True, exist_ok=True)\n    text = f"""DOC-151 / DOC-176 GAMIT PRACTICAL NOTES ADDED\n\n1. RINEX observation-file structure\n   - RINEX observation files contain a header and an observation body.\n   - The header contains version, satellite systems, marker name, receiver, antenna, antenna height/offset, approximate XYZ, observation types, interval, first/last observation time, and END OF HEADER.\n   - The body contains epoch records, satellite identifiers/PRNs, observables, signal strength, and optional receiver clock offset.\n   - Carrier phase is normally in cycles; pseudorange/range is in metres.\n\n2. RINEX 2 / RINEX 3 naming\n   - GAMIT supports RINEX 2.x and 3.x, but RINEX 3 long filenames must be converted/renamed to GAMIT short-name format.\n   - Required short-name format is <ssss><ddd><session>.<yy>o, for example hyd20910.26o.\n   - Prefer sh_rename_rinex3 -f *.rnx where available; otherwise use the Python fallback and then verify station/day coverage.\n\n3. GNSS constellation handling\n   - GAMIT/GLOBK 10.61 and later support RINEX 3 and multiple GNSS constellations.\n   - GAMIT processes each GNSS network separately using -gnss.\n   - Common options are G for GPS, R for GLONASS, C for BeiDou, E for Galileo, and J for QZSS.\n   - GPS-only examples use IGSF orbit products. For non-GPS / mixed-GNSS processing, CODE/CODM-type products may be required.\n   - This launcher remains GPS-first for the tested CORS workflow unless the user intentionally selects another network workflow.\n\n4. APR and lfile relationship\n   - .apr files and lfile. contain Cartesian coordinates and, where available, velocity information.\n   - lfile. is updated after daily processing if coordinate adjustments exceed the threshold, commonly 0.3 m.\n   - Good a priori coordinates are required so prefit residuals are small enough for AUTCLN to clean and repair data robustly.\n   - If coordinate updates are large, back up the day folder and rerun with updated coordinates.\n\n5. Daily summary QC from uploaded slides\n   - Total xfiles should equal the number of RINEX files actually used.\n   - Average RMS for individual/all sites should generally be less than about 8 mm in the training slides; 10 mm is a broader practical warning limit.\n   - Postfit NRMS should be around 0.2 or less.\n   - Large coordinate updates >0.3 m require a rerun.\n   - Practical rule noted: about 1 m a-priori coordinate error can create roughly 1 mm final coordinate effect.\n\n6. GAMIT module reminder\n   - ARC integrates satellite orbits and produces G/T-file style orbit products from SP3/model input.\n   - MODEL computes residuals/partials and uses rcvant.dat, clock files, lfile, x-files, t-files, ionosphere/met inputs, solid/ocean tide models, and antenna PCO/PCV models.\n   - AUTCLN edits residuals, detects outliers, repairs cycle slips, and produces postfit residual summaries/reweights.\n   - SOLVE performs weighted least squares and outputs q-files and h-files.\n   - q-file = constrained solution record; h-file = loose solution/covariance for GLOBK.\n\n7. Installation / WSL / plotting reminders\n   - For Linux/WSL, check dependencies such as make, csh/tcsh, gfortran, libx11-dev, bc, curl, GMT, and Ghostscript.\n   - Check PATH using which sh_gamit, which solve, which autcln, which sh_glred, which globk, and which glorg.\n   - In WSL, .netrc is needed for Earthdata/CDDIS downloads.\n   - For plots, Ghostscript/ps2pdf are needed for viewing/converting PostScript, and VcXsrv may be needed for GUI plotting under WSL.\n\nProcessed DOYs in this run: {\', \'.join(doy_list)}\nProject: {project_dir}\n"""\n    out.write_text(text, encoding="utf-8")\n    print_success(f"Saved Doc-151/Doc-176 GAMIT practical notes: {out}")\n    return out\n\n\n\ndef apply_manual_antenna_heights_to_station_info(project_dir: Path, rows: List[str]) -> None:\n    """Apply manually entered antenna heights to matching station.info lines.\n\n    This is conservative: for each matching station, only the first 0.0000 height-like\n    token in the station.info line is replaced. A timestamped backup is always saved.\n    The user should still review station.info before scientific final processing.\n    """\n    station_info = project_dir / "tables" / "station.info"\n    if not station_info.is_file():\n        print_warning("station.info not found, so manual antenna heights were saved but not applied.")\n        return\n    heights: Dict[str, float] = {}\n    for row in rows:\n        if "," not in row:\n            print_warning(f"Ignoring manual height row without comma: {row}")\n            continue\n        st, val = row.split(",", 1)\n        st = st.strip().upper().replace("_GPS", "")[:4]\n        try:\n            h = float(val.strip())\n        except Exception:\n            print_warning(f"Ignoring manual height row with invalid number: {row}")\n            continue\n        if len(st) == 4:\n            heights[st] = h\n    if not heights:\n        print_warning("No valid manual antenna heights were entered.")\n        return\n    backup = station_info.with_name(f"station.info.before_manual_height_apply_{datetime.now().strftime(\'%Y%m%d_%H%M%S\')}")\n    backup.write_text(station_info.read_text(errors="ignore"), encoding="utf-8", errors="ignore")\n    old_lines = station_info.read_text(errors="ignore").splitlines(True)\n    new_lines: List[str] = []\n    applied: Dict[str, int] = {k: 0 for k in heights}\n    for line in old_lines:\n        parts = line.split()\n        if parts:\n            code = parts[0].strip().upper().replace("_GPS", "")[:4]\n            if code in heights:\n                htxt = f"{heights[code]:8.4f}".strip()\n                # station.info normally stores antenna height as 0.0000 before antenna/radome tokens.\n                newline, n = re.subn(r"(?<![0-9.])0\\.0000(?![0-9.])", htxt, line, count=1)\n                if n:\n                    line = newline\n                    applied[code] += 1\n        new_lines.append(line)\n    station_info.write_text("".join(new_lines), encoding="utf-8", errors="ignore")\n    print_success(f"Applied manual antenna heights to station.info; backup saved: {backup}")\n    for st, h in sorted(heights.items()):\n        count = applied.get(st, 0)\n        if count:\n            print_success(f"  {st}: {h:.4f} m applied to {count} line(s)")\n        else:\n            print_warning(f"  {st}: no station.info line was changed; please review manually")\n\ndef handle_zero_antenna_height_decision(settings: Dict[str, str]) -> None:\n    """Production safety gate when station.info contains 0.0000 antenna heights."""\n    project_dir = Path.home() / settings["PROJECT"]\n    report = project_dir / "tables" / "station_info_easy_report.txt"\n    station_info = project_dir / "tables" / "station.info"\n    text = report.read_text(errors="ignore") if report.is_file() else ""\n    local_sites = [s.upper() for s in station_list(settings.get("LOCAL_SITES", ""))]\n    zero_sites = []\n    for s in local_sites:\n        if re.search(rf"\\b{s}\\b.*CHECK_HEIGHT", text, re.I):\n            zero_sites.append(s)\n    if not zero_sites and station_info.is_file():\n        stxt = station_info.read_text(errors="ignore")\n        for s in local_sites:\n            if re.search(rf"^\\s*{s}\\s+{s}\\s+.*\\s0\\.0000\\s", stxt, re.I | re.M):\n                zero_sites.append(s)\n    zero_sites = sorted(set(zero_sites))\n    if not zero_sites:\n        return\n    print_header("ANTENNA HEIGHT ZERO - PRODUCTION DECISION")\n    print_warning("station.info/RINEX reports antenna height 0.0000 for: " + " ".join(zero_sites))\n    print_warning("The program will not invent antenna heights. Wrong heights can bias vertical coordinates.")\n    print("1. Continue for demo/training only")\n    print("2. Enter antenna heights manually now (station,height_m)")\n    print("3. Load antenna heights from CSV")\n    print("4. Stop and correct RINEX/station.info manually")\n    choice = ask_input("Choose antenna-height action", "1").strip()\n    if choice == "4":\n        print_error("Stopped so antenna heights can be corrected for production.")\n        sys.exit(1)\n    if choice == "2":\n        print_info("Enter values like HYD2,0.123 one by one. Blank line to finish.")\n        rows = []\n        while True:\n            line = ask_input("station,height_m", "").strip()\n            if not line:\n                break\n            rows.append(line)\n        csv_path = project_dir / "tables" / "manual_antenna_heights_entered.csv"\n        csv_path.write_text("station,height_m\\n" + "\\n".join(rows) + "\\n")\n        print_success(f"Saved manual antenna-height CSV for review: {csv_path}")\n        apply_manual_antenna_heights_to_station_info(project_dir, rows)\n        print_warning("Manual heights were applied conservatively. Review station.info before scientific final processing.")\n    elif choice == "3":\n        path = normalize_input_path(ask_input("Path to antenna-height CSV", str(project_dir / "tables" / "antenna_heights.csv")))\n        if not Path(path).is_file():\n            print_error(f"CSV not found: {path}")\n            sys.exit(1)\n        rows = []\n        for line in Path(path).read_text(errors="ignore").splitlines():\n            line = line.strip()\n            if not line or line.lower().startswith("station"):\n                continue\n            rows.append(line)\n        print_success(f"Antenna-height CSV selected: {path}")\n        apply_manual_antenna_heights_to_station_info(project_dir, rows)\n        print_warning("CSV heights were applied conservatively. Review station.info before scientific final processing.")\n    else:\n        print_warning("Continuing for demo/training only with 0.0000 antenna-height warning recorded.")\n\n# =============================================================================\n# MAIN PROGRAM\n# =============================================================================\ndef main() -> int:\n    if "--write-template-config" in sys.argv[1:]:\n        write_template_config()\n        return 0\n    load_runtime_config_from_argv()\n    print_header("AUTOM-GAMIT DATA-FIRST INTERACTIVE PROGRAM")\n    print("This is a GAMIT-only program. GLOBK/GLORG will be separate.")\n    print("The program first reads RINEX data status, then asks what to keep, exclude, or rename.")\n    if ask_yes_no("Pause before/after every processing stage for explanation?", "yes"):\n        os.environ.pop("AUTOM_GAMIT_AUTO_STAGE", None)\n        print_info("Stage explanation pauses enabled. Set AUTOM_GAMIT_AUTO_STAGE=1 or answer no to run faster.")\n    else:\n        os.environ["AUTOM_GAMIT_AUTO_STAGE"] = "1"\n        print_info("Stage pauses disabled for this run.")\n\n    print_header("BASIC SETTINGS FOR SCAN")\n    rinex_dir = normalize_input_path(ask_input("Path to local/source RINEX files", "/home/geodesy/Documents/cors-rinex"))\n    year = ask_input("Year", "2026").strip()\n    yy = year[-2:]\n    start_doy = norm_doy(ask_input("Start DOY to inspect/process", "091"))\n    inspect_days = ask_input("Number of days to inspect in RINEX table", "5").strip()\n    expt = ask_input("GAMIT experiment code, 4 characters", "cors").lower().strip()\n    project = ask_input("Project folder name", "cors2026").strip()\n\n    try:\n        expected_doys = expected_doy_list(start_doy, inspect_days)\n    except Exception:\n        print_error("Invalid START_DOY or number of days.")\n        return 1\n\n    print_header("READING LOCAL RINEX BEFORE ANY DECISION")\n    print_info(f"Looking in: {rinex_dir}")\n    print_info(f"Year suffix: {yy}")\n    stations, info = scan_rinex_files(rinex_dir, yy)\n    if not stations:\n        print_error(f"No RINEX observation files found in {rinex_dir} for year suffix {yy}")\n        print_info(f"Expected short-name examples: abcd0910.{yy}o, abcd0910.{yy}o.gz, abcd0910.{yy}d.gz")\n        return 1\n\n    show_station_summary(info)\n    show_data_decision_table(info, expected_doys, yy)\n    station_detail_loop(info)\n\n    source_sites, exclude_sites = ask_source_station_selection(stations, info, expected_doys, yy)\n    ref_frame, apr_file, custom_apr_file = choose_reference_frame_and_apr()\n    local_sites, rename_site, rename_pairs_str, conflict_site = ask_rename_pairs_data_first(source_sites, apr_file)\n\n    print_header("IGS / REFERENCE STATIONS")\n    igs_default = "badg bhr4 daej dgar djig iisc mal2 ntus pol2 reun xmis"\n    igs_sites = norm_sites(ask_input("IGS/reference stations", igs_default))\n\n    print_header("PROCESSING DAYS")\n    if ask_yes_no("Process only ONE day first for testing?", "yes"):\n        ndays = "1"\n    else:\n        ndays = ask_input("Number of days to process", inspect_days).strip()\n\n    print_header("RUN MODE")\n    print_info("Products and IGS RINEX are prepared before sh_gamit.")\n    print_info("All sh_gamit commands include -pres ELEV for elevation residual diagnostics.")\n    fresh_start = "YES" if ask_yes_no("Fresh project? YES backs up old project folder", "no") else "NO"\n    download_igs = "YES" if ask_yes_no("Download/check IGS RINEX automatically?", "yes") else "NO"\n    orbit_mode_options = [\n        "RECOMMENDED: online pre-download products/RINEX, then sh_gamit -orbit igsf -noftp -pres ELEV",\n        "GAMIT-managed internet mode: sh_gamit may download internally (-orbit igsf -pres ELEV)",\n        "Strict offline SP3/final orbit: no download by Python, sh_gamit -orbit igsf -noftp -pres ELEV",\n        "Strict offline local g-file mode: no download by Python, sh_gamit -orbt igsg -noftp -pres ELEV",\n    ]\n    orbit_idx = ask_choice_index("Choose sh_gamit orbit/product mode", orbit_mode_options, 0)\n    gamit_orbit_mode = ["PREFETCH_IGSF_NOFTP", "INTERNET_IGSF", "OFFLINE_IGSF", "OFFLINE_IGSG"][orbit_idx]\n\n    # IMPORTANT: NOFTP_FLAG here means Python/product-download layer is strict-offline.\n    # In the recommended mode it is intentionally blank so Python can download SP3,\n    # IONEX, BRDC and IGS RINEX first.  sh_gamit itself still receives -noftp\n    # through GAMIT_ORBIT_MODE=PREFETCH_IGSF_NOFTP, preventing internal download loops.\n    noftp_flag = "-noftp" if gamit_orbit_mode in ("OFFLINE_IGSF", "OFFLINE_IGSG") else ""\n    print_info("Command will be previewed before running; the code will not silently switch orbit modes.")\n    if gamit_orbit_mode == "PREFETCH_IGSF_NOFTP":\n        print_success("Selected recommended mode: Python downloads/checks products and IGS RINEX, then sh_gamit runs with -noftp.")\n    elif gamit_orbit_mode == "INTERNET_IGSF":\n        print_warning("Selected GAMIT-managed internet mode. sh_gamit may try to download previous-day/reference RINEX internally and can appear stuck.")\n\n    settings = {\n        "PROJECT": project,\n        "EXPT": expt,\n        "YEAR": year,\n        "YY": yy,\n        "START_DOY": start_doy,\n        "NDAYS": ndays,\n        "SOURCE_RINEX_DIR": rinex_dir,\n        "LOCAL_SITES": local_sites,\n        "IGS_SITES": igs_sites,\n        "EXCLUDE_SITES": exclude_sites,\n        "RENAME_SITE": rename_site,\n        "RENAME_PAIRS": rename_pairs_str,\n        "CONFLICT_SITE": conflict_site,\n        "REF_FRAME": ref_frame,\n        "APR_FILE": apr_file,\n        "CUSTOM_APR_FILE": custom_apr_file,\n        "NOFTP_FLAG": noftp_flag,\n        "GAMIT_ORBIT_MODE": gamit_orbit_mode,\n        "PRES_OPTION": "-pres ELEV",\n        "AUTOM_GAMIT_DRY_RUN": os.environ.get("AUTOM_GAMIT_DRY_RUN", "0"),\n        "FRESH_START": fresh_start,\n        "DOWNLOAD_GLOBAL_RINEX": download_igs,\n        "STRICT_NOFTP_CHECK": "YES",\n        "FALLBACK_IGS_SITES": os.environ.get("FALLBACK_IGS_SITES", "hyde iisc ntus pol2 lhaz cusv coco xmis dgar mal2 pimo bako shao hkws hksl jfng daej badg reun djig bhr4"),\n    }\n\n    os.environ["INTEGRATED_PROJECT_DIR"] = str(Path.home() / project)\n\n    print_header("FINAL PROCESSING SUMMARY")\n    for k in [\n        "PROJECT", "EXPT", "YEAR", "START_DOY", "NDAYS", "SOURCE_RINEX_DIR",\n        "LOCAL_SITES", "EXCLUDE_SITES", "RENAME_SITE", "RENAME_PAIRS",\n        "CONFLICT_SITE", "IGS_SITES", "REF_FRAME", "APR_FILE", "CUSTOM_APR_FILE",\n        "FRESH_START", "NOFTP_FLAG", "GAMIT_ORBIT_MODE", "DOWNLOAD_GLOBAL_RINEX",\n    ]:\n        print(f"{k:24s}: {settings.get(k, \'\')}")\n\n    if not validate_settings(settings):\n        print_error("Settings are not valid. Restart and correct the values.")\n        return 1\n\n    if not ask_yes_no("Proceed with these settings?", "yes"):\n        print_warning("Stopped before processing.")\n        return 0\n\n    timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")\n    log_dir = Path.home() / f"{project}_interactive_logs_{timestamp}"\n    log_dir.mkdir(parents=True, exist_ok=True)\n\n    print_header("PROCESSING STARTED")\n    print_info(f"Logs folder: {log_dir}")\n\n    run_critical("01_check_tools", get_check_tools_step(), settings, log_dir)\n    run_critical("02_auth", get_auth_step(), settings, log_dir)\n    run_critical("03_create_project", get_create_project_step(), settings, log_dir)\n    run_critical("04_copy_rinex", get_copy_rinex_step(), settings, log_dir)\n    run_critical("05_exclude_unselected_source_stations", get_exclude_step(), settings, log_dir, allow_continue=True)\n    run_critical("06_rename_selected_source_stations", get_rename_step(), settings, log_dir, allow_continue=True)\n    run_critical("07_sh_setup", get_sh_setup_step(), settings, log_dir)\n    run_critical("08_apr", get_apr_step(), settings, log_dir)\n    run_critical("09_sites_defaults", get_sites_defaults_step(), settings, log_dir)\n    run_critical("10_lfile", get_lfile_step(), settings, log_dir)\n    run_critical("11_station_info", get_station_info_step(), settings, log_dir)\n    handle_zero_antenna_height_decision(settings)\n    run_critical("12_otl", get_otl_step(), settings, log_dir)\n\n    doy_list = expected_doy_list(start_doy, ndays)\n    for doy in doy_list:\n        print_header(f"DAILY PROCESSING DOY {doy}")\n        run_critical(f"13_products_{doy}", get_product_step(doy), settings, log_dir)\n        run_critical(f"14_global_rinex_{doy}", get_global_rinex_step(doy), settings, log_dir)\n        run_critical(f"15_gamit_{doy}", get_gamit_step(doy), settings, log_dir)\n        run_critical(f"16_qc_{doy}", get_qc_step(doy), settings, log_dir, allow_continue=True)\n\n    print_header("GAMIT PROCESSING COMPLETE")\n    print_success(f"Logs saved in: {log_dir}")\n    print_info("Check h-files in day folders such as 091G/h*.YYDOY.")\n    postprocess_summary(settings, doy_list, log_dir)\n    write_doc101_doc126_gamit_notes(settings, doy_list, log_dir)\n    write_doc151_doc176_gamit_notes(settings, doy_list, log_dir)\n    return 0\n\nif __name__ == "__main__":\n    try:\n        sys.exit(main())\n    except KeyboardInterrupt:\n        print("\\nUser stopped the program.")\n        sys.exit(130)\n'

GLOBK_SOURCE = '#!/usr/bin/env python3\n"""\nAUTOM-GLOBK/GLORG - MASTER FINAL DASHBOARD SCRIPT DOC51-DOC76 COMPLETE\nBased on the successful globkg2.py patching logic and globkg3.py result display.\n\nThis script:\n- Processes GAMIT h-files with the same workflow that worked.\n- Produces daily .org files and optionally a combined .org.\n- Extracts final coordinates, uncertainties, and POS statistics.\n- Saves CSV, PNG plots, and shows a results dashboard.\n- Requested-epoch coordinates do not use lfile/APR 10.0 values as velocities.\n- Local lfile-derived 10.0 velocity mistakes are reset to 0.0.\n- Epoch propagation can use measured long-term POS velocity, external CSV,\n  or a Jade et al. 2017 India plate model for demonstration.\n\nUsage:\n    python3 globk_final_dashboard.py\n"""\n\nfrom __future__ import annotations\n\nimport os\nimport csv\nimport json\nimport re\nimport shlex\nimport shutil\nimport subprocess\nimport sys\nfrom datetime import datetime, date, timedelta\nfrom pathlib import Path\nfrom typing import Dict, List, Optional, Tuple\n\n\n# =============================================================================\n# COLORS AND HELPERS\n# =============================================================================\n\nclass Colors:\n    RED = "\\033[91m"\n    GREEN = "\\033[92m"\n    YELLOW = "\\033[93m"\n    BLUE = "\\033[94m"\n    MAGENTA = "\\033[95m"\n    CYAN = "\\033[96m"\n    BOLD = "\\033[1m"\n    END = "\\033[0m"\n\n\ndef ctext(text: str, color: str) -> str:\n    return f"{color}{text}{Colors.END}"\n\n\ndef print_header(text: str) -> None:\n    print()\n    print(ctext("=" * 90, Colors.CYAN))\n    print(ctext(f"{text:^90}", Colors.CYAN + Colors.BOLD))\n    print(ctext("=" * 90, Colors.CYAN))\n\n\ndef print_info(text: str) -> None:\n    print(ctext(f"i  {text}", Colors.BLUE))\n\n\ndef print_success(text: str) -> None:\n    print(ctext(f"OK {text}", Colors.GREEN))\n\n\ndef print_warning(text: str) -> None:\n    print(ctext(f"WARNING {text}", Colors.YELLOW))\n\n\ndef print_error(text: str) -> None:\n    print(ctext(f"ERROR {text}", Colors.RED))\n\n\ndef print_progress(text: str) -> None:\n    print(ctext(f">> {text}", Colors.MAGENTA))\n\n\n# =============================================================================\n# GLOBK METHOD / IMPLICATION STAGE GATES\n# =============================================================================\nGLOBK_STAGE_DETAILS = {\n    "scan": "Scan h-files and select a consistent DOY range before any GLX/ORG processing.",\n    "frame": "Select APR/EQ/frame and stabilization sites; this realizes the final reference frame.",\n    "patch": "Patch globk.cmd/glorg.cmd safely and report the effective active APR/EQ commands.",\n    "run": "Run sh_glred/htoglb to create daily ORG/GLX outputs, then verify .org files before combining.",\n    "combine": "Optionally combine daily solutions and diagnose GLOBK chi-square/data rejections.",\n    "outputs": "Extract coordinates, velocities, plots, POS statistics, and office-ready reports."\n}\n\n\ndef globk_stage_gate(stage: str) -> None:\n    print_header("GLOBK METHOD AND IMPLICATION: " + stage.upper())\n    print_info(GLOBK_STAGE_DETAILS.get(stage, "Review this GLOBK/GLORG stage before continuing."))\n    print_info("Implication: GLOBK may return 0 even when data are rejected; always check .org/.log diagnostics.")\n    if os.environ.get("AUTOM_GLOBK_AUTO_STAGE", "0") == "1":\n        return\n    while True:\n        ans = input(ctext("Stage control: p = proceed, e = explain again, q = quit [p]: ", Colors.CYAN)).strip().lower()\n        if ans == "":\n            ans = "p"\n        if ans == "p":\n            return\n        if ans == "e":\n            print_info(GLOBK_STAGE_DETAILS.get(stage, "Review this GLOBK/GLORG stage before continuing."))\n            continue\n        if ans == "q":\n            print_warning("Stopped by user before this GLOBK stage.")\n            sys.exit(0)\n        print("Please enter p, e, or q.")\n\n\ndef ask_input(prompt: str, default: str = "") -> str:\n    if default:\n        ans = input(ctext(f"{prompt} [{default}]: ", Colors.CYAN)).strip()\n        return ans if ans else default\n    return input(ctext(f"{prompt}: ", Colors.CYAN)).strip()\n\n\ndef ask_yes_no(question: str, default: str = "yes") -> bool:\n    default = default.lower().strip()\n    prompt = "[Y/n]" if default == "yes" else "[y/N]"\n    while True:\n        ans = input(ctext(f"{question} {prompt}: ", Colors.CYAN)).strip().lower()\n        if ans == "":\n            return default == "yes"\n        if ans in ("y", "yes"):\n            return True\n        if ans in ("n", "no"):\n            return False\n        print("Please answer yes or no.")\n\n\ndef ask_choice(question: str, options: List[str], default: int = 0) -> int:\n    print(ctext(question, Colors.CYAN))\n    for i, opt in enumerate(options, 1):\n        marker = " [default]" if i - 1 == default else ""\n        print(f"  {i}. {opt}{marker}")\n    while True:\n        ans = input(ctext(f"Enter choice (1-{len(options)}) [{default + 1}]: ", Colors.CYAN)).strip()\n        if ans == "":\n            return default\n        if ans.isdigit() and 1 <= int(ans) <= len(options):\n            return int(ans) - 1\n        print(f"Please enter a number from 1 to {len(options)}.")\n\n\ndef normalize_path(text: str) -> Path:\n    text = text.strip().strip(\'"\').strip("\'")\n    if text.startswith("home/"):\n        text = "/" + text\n    return Path(os.path.expandvars(text)).expanduser()\n\n\ndef timestamp() -> str:\n    return datetime.now().strftime("%Y%m%d_%H%M%S")\n\n\ndef command_exists(cmd: str) -> bool:\n    return shutil.which(cmd) is not None\n\n\ndef read_text_safe(path: Path, max_bytes: Optional[int] = None) -> str:\n    try:\n        if max_bytes is None:\n            return path.read_text(errors="ignore")\n        with open(path, "rb") as f:\n            data = f.read(max_bytes)\n        return data.decode(errors="ignore")\n    except Exception:\n        return ""\n\n\ndef backup_file(path: Path, tag: str) -> Optional[Path]:\n    if not path.is_file():\n        return None\n    b = path.with_name(f"{path.name}.before_{tag}_{timestamp()}")\n    shutil.copy2(path, b)\n    return b\n\n\ndef path_for_cmd(path: Path) -> str:\n    try:\n        return str(path.expanduser().resolve())\n    except Exception:\n        return str(path.expanduser())\n\n\ndef yy_to_full_year(yy: str) -> str:\n    n = int(yy)\n    if n >= 80:\n        return f"19{yy}"\n    return f"20{yy}"\n\n\ndef shell_quote(value: object) -> str:\n    return shlex.quote(str(value))\n\n\ndef append_command_log(log_dir: Path, label: str, cmd: List[str]) -> None:\n    """Save exact commands without changing processing behavior."""\n    try:\n        log_dir.mkdir(parents=True, exist_ok=True)\n        cmd_file = log_dir / "commands_used.txt"\n        with open(cmd_file, "a", encoding="utf-8", errors="ignore") as f:\n            f.write(f"\\n[{timestamp()}] {label}\\n")\n            f.write(" ".join(shell_quote(x) for x in cmd) + "\\n")\n    except Exception as e:\n        print_warning(f"Could not save command log: {e}")\n\n\ndef preflight_environment_report(project_dir: Path, log_dir: Path) -> None:\n    """Non-invasive environment check. It warns only; the normal tool check still decides failure."""\n    print_header("PRE-FLIGHT ENVIRONMENT CHECK")\n    checks: List[Tuple[str, bool, str]] = []\n\n    for cmd in ["sh_gamit", "sh_glred", "globk", "glorg", "htoglb", "crx2rnx", "sh_setup", "sh_upd_stnfo"]:\n        p = shutil.which(cmd)\n        checks.append((f"command {cmd}", p is not None, p or "not found in PATH"))\n\n    # Some GAMIT/GLOBK installations do not export GG_TABLES/GAMIT_TABLES\n    # even though the standard ~/gg/tables directory exists. This is not fatal.\n    # The launcher auto-sets both variables for the current Python process when\n    # ~/gg/tables exists, and saves a permanent-fix note in the pre-flight report.\n    default_tables = Path.home() / "gg" / "tables"\n    auto_set_env: List[str] = []\n    for env in ["GG_TABLES", "GAMIT_TABLES"]:\n        val = os.environ.get(env, "").strip()\n        detail = val\n        ok = bool(val)\n        if not val and default_tables.is_dir():\n            os.environ[env] = str(default_tables)\n            detail = f"{default_tables} (auto-set for this run; add export {env}=$HOME/gg/tables to ~/.bashrc for permanence)"\n            ok = True\n            auto_set_env.append(env)\n        checks.append((f"environment {env}", ok, detail or "not set"))\n\n    important_paths = [\n        ("project folder", project_dir),\n        ("project tables", project_dir / "tables"),\n        ("project gsoln", project_dir / "gsoln"),\n        ("GAMIT tables", Path.home() / "gg" / "tables"),\n        ("GAMIT GRIDS", Path.home() / "gg" / "GRIDS"),\n        ("Earthdata .netrc", Path.home() / ".netrc"),\n        ("Earthdata cookies", Path.home() / ".urs_cookies"),\n    ]\n    for label, p in important_paths:\n        checks.append((label, p.exists(), str(p)))\n\n    lines = []\n    for label, ok, detail in checks:\n        status = "OK" if ok else "CHECK"\n        lines.append(f"{status:5s} {label:24s} {detail}")\n        if ok:\n            print_success(f"{label}: {detail}")\n        else:\n            print_warning(f"{label}: {detail}")\n\n    if auto_set_env:\n        lines.append("")\n        lines.append("PERMANENT ENVIRONMENT FIX")\n        lines.append("The launcher auto-set missing GAMIT table variables for this run.")\n        lines.append("To remove the warning permanently, add these lines to ~/.bashrc:")\n        lines.append("export GG_TABLES=$HOME/gg/tables")\n        lines.append("export GAMIT_TABLES=$HOME/gg/tables")\n        lines.append("Then run: source ~/.bashrc")\n\n    try:\n        log_dir.mkdir(parents=True, exist_ok=True)\n        out = log_dir / "preflight_environment_check.txt"\n        out.write_text("\\n".join(lines) + "\\n", encoding="utf-8")\n        print_success(f"Saved pre-flight report: {out}")\n        if auto_set_env:\n            print_info("GG_TABLES/GAMIT_TABLES were auto-set for this run. Permanent ~/.bashrc commands are saved in the pre-flight report.")\n    except Exception as e:\n        print_warning(f"Could not save pre-flight report: {e}")\n\n\ndef globk_project_health_check(\n    project_dir: Path,\n    selected: Dict[str, Dict],\n    year: str,\n    start_doy: str,\n    end_doy: str,\n    expt: str,\n    netext: str,\n    local_stations: List[str],\n    apr_path: Path,\n    eq_path: Optional[Path],\n    frame_name: str,\n    stab_sites: List[str],\n    log_dir: Path,\n) -> None:\n    """Print and save a non-invasive GLOBK project health summary before patching/running."""\n    print_header("GLOBK PROJECT HEALTH CHECK")\n    doys = sorted(selected.keys())\n    hfile_count = sum(len(v.get("hfiles", [])) for v in selected.values())\n    daily_dirs = [f"{d}{selected[d].get(\'netext\', netext)}" for d in doys]\n    gsoln = project_dir / "gsoln"\n    combined_guess = gsoln / f"globk_{expt}_{year[-2:]}{start_doy}_{year[-2:]}{end_doy}.org"\n\n    items = [\n        ("Project", str(project_dir)),\n        ("Selected DOYs", " ".join(doys)),\n        ("Daily folders", " ".join(daily_dirs)),\n        ("H-files found", str(hfile_count)),\n        ("Experiment", expt),\n        ("Network extension", netext),\n        ("Frame family", frame_name),\n        ("APR file", str(apr_path)),\n        ("EQ file", str(eq_path) if eq_path else "not used"),\n        ("Local stations", " ".join(local_stations)),\n        ("Stabilization sites", " ".join(stab_sites)),\n        ("Existing combined .org", str(combined_guess) if combined_guess.is_file() else "not found yet"),\n    ]\n\n    lines = []\n    for k, v in items:\n        lines.append(f"{k:24s}: {v}")\n        print_info(f"{k:24s}: {v}")\n\n    if hfile_count < len(doys):\n        msg = "Fewer h-files than selected days; review day folders before final interpretation."\n        print_warning(msg)\n        lines.append("WARNING: " + msg)\n    if len(stab_sites) < 8:\n        msg = "Only a few stabilization sites; 8-10 is usually better for robustness."\n        print_warning(msg)\n        lines.append("WARNING: " + msg)\n    if eq_path is None:\n        msg = "No EQ file selected. This is acceptable for short tests but less ideal for long time-series."\n        print_warning(msg)\n        lines.append("WARNING: " + msg)\n\n    try:\n        out = log_dir / "globk_project_health_check.txt"\n        out.write_text("\\n".join(lines) + "\\n", encoding="utf-8")\n        print_success(f"Saved project health check: {out}")\n    except Exception as e:\n        print_warning(f"Could not save project health check: {e}")\n\n\ndef save_globk_run_settings(\n    project_dir: Path,\n    log_dir: Path,\n    year: str,\n    start_doy: str,\n    end_doy: str,\n    ndays: int,\n    expt: str,\n    netext: str,\n    doys: List[str],\n    local_stations: List[str],\n    apr_path: Path,\n    eq_path: Optional[Path],\n    frame_name: str,\n    stab_sites: List[str],\n    options: str = "",\n) -> None:\n    """Save repeatable run settings in JSON and TXT; does not affect GLOBK."""\n    data = {\n        "created_at": datetime.now().isoformat(timespec="seconds"),\n        "project_dir": str(project_dir),\n        "year": year,\n        "start_doy": start_doy,\n        "end_doy": end_doy,\n        "ndays": ndays,\n        "doys": doys,\n        "experiment": expt,\n        "network_extension": netext,\n        "local_stations": local_stations,\n        "stabilization_sites": stab_sites,\n        "frame_family": frame_name,\n        "apr_file": str(apr_path),\n        "eq_file": str(eq_path) if eq_path else "",\n        "sh_glred_options": options,\n    }\n    try:\n        log_dir.mkdir(parents=True, exist_ok=True)\n        json_file = log_dir / "final_run_settings.json"\n        txt_file = log_dir / "final_run_settings.txt"\n        json_file.write_text(json.dumps(data, indent=2), encoding="utf-8")\n        txt_file.write_text("\\n".join(f"{k:24s}: {v}" for k, v in data.items()) + "\\n", encoding="utf-8")\n        print_success(f"Saved run settings: {txt_file}")\n        print_success(f"Saved run settings JSON: {json_file}")\n    except Exception as e:\n        print_warning(f"Could not save run settings: {e}")\n\n\ndef write_final_processing_report(\n    project_dir: Path,\n    log_dir: Path,\n    year: str,\n    start_doy: str,\n    end_doy: str,\n    expt: str,\n    yy: str,\n    local_stations: List[str],\n    daily_org_files: List[Path],\n    comb_org: List[Path],\n    apr_path: Path,\n    eq_path: Optional[Path],\n    frame_name: str,\n) -> None:\n    """Create a compact final text report after all processing."""\n    try:\n        out_dir = project_dir / "gsoln" / "final_outputs"\n        out_dir.mkdir(parents=True, exist_ok=True)\n        combined = comb_org[0] if comb_org else None\n        coord_csv = out_dir / "local_final_coordinates.csv"\n        epoch_csvs = sorted(out_dir.glob("local_coordinates_epoch_*.csv"))\n        pos_stats = out_dir / "pos_statistics.txt"\n        commands_file = log_dir / "commands_used.txt"\n\n        lines = [\n            "GAMIT/GLOBK FINAL PROCESSING REPORT",\n            "=" * 70,\n            f"Created              : {datetime.now().isoformat(timespec=\'seconds\')}",\n            f"Project              : {project_dir}",\n            f"Year / DOY range     : {year} {start_doy}-{end_doy}",\n            f"Experiment / Netext  : {expt} / {yy}",\n            f"Frame family         : {frame_name}",\n            f"APR file             : {apr_path}",\n            f"EQ file              : {eq_path if eq_path else \'not used\'}",\n            f"Local stations       : {\' \'.join(local_stations)}",\n            "",\n            "Daily ORG files:",\n        ]\n        lines.extend([f"  {p}" for p in daily_org_files] or ["  none found"])\n        lines += [\n            "",\n            f"Combined ORG         : {combined if combined else \'not found\'}",\n            f"Coordinate CSV       : {coord_csv if coord_csv.is_file() else \'not found\'}",\n            f"POS statistics       : {pos_stats if pos_stats.is_file() else \'not found\'}",\n            f"Command log          : {commands_file if commands_file.is_file() else \'not found\'}",\n            "",\n            "Epoch coordinate CSV files:",\n        ]\n        lines.extend([f"  {p}" for p in epoch_csvs] or ["  none created"])\n        lines += [\n            "",\n            "Notes:",\n            "- This report is generated after GLOBK/GLORG and does not change processing.",\n            "- For final scientific results, verify antenna heights, station.info metadata, APR frame, EQ file, and stabilization stations.",\n        ]\n        report = out_dir / "final_processing_report.txt"\n        report.write_text("\\n".join(lines) + "\\n", encoding="utf-8")\n        print_success(f"Saved final processing report: {report}")\n    except Exception as e:\n        print_warning(f"Could not write final processing report: {e}")\n\n\n# =============================================================================\n# H-FILE DETECTION\n# =============================================================================\n\nHFILE_RE = re.compile(r"^h([A-Za-z0-9]{4})([A-Za-z0-9])\\.(\\d{2})(\\d{3})$")\n\n\ndef parse_hfile_name(path: Path) -> Optional[Dict[str, str]]:\n    m = HFILE_RE.match(path.name)\n    if not m:\n        return None\n    expt, soln_letter, yy, doy = m.groups()\n    return {\n        "expt": expt.lower(),\n        "soln_letter": soln_letter.lower(),\n        "yy": yy,\n        "doy": doy,\n    }\n\n\ndef scan_hfiles(project_dir: Path) -> Dict[str, Dict]:\n    results: Dict[str, Dict] = {}\n    day_pattern = re.compile(r"^(\\d{3})([A-Za-z])$")\n\n    for item in sorted(project_dir.iterdir()):\n        if not item.is_dir():\n            continue\n\n        m = day_pattern.match(item.name)\n        if not m:\n            continue\n\n        folder_doy, netext = m.groups()\n        valid_hfiles = []\n        valid_infos = []\n\n        for p in sorted(item.iterdir()):\n            if not p.is_file() or p.stat().st_size <= 0:\n                continue\n\n            info = parse_hfile_name(p)\n            if not info:\n                continue\n\n            if info["doy"] != folder_doy:\n                print_warning(f"Skipping mismatched h-file: {p.name} inside {item.name}")\n                continue\n\n            valid_hfiles.append(p)\n            valid_infos.append(info)\n\n        if valid_hfiles:\n            info0 = valid_infos[0]\n            results[folder_doy] = {\n                "netext": netext,\n                "hfiles": valid_hfiles,\n                "expt": info0["expt"],\n                "yy": info0["yy"],\n                "soln_letter": info0["soln_letter"],\n            }\n\n    return results\n\n\ndef select_processing_range(scan_results: Dict[str, Dict]) -> Dict[str, Dict]:\n    all_doys = sorted(scan_results.keys())\n    print_header("AVAILABLE H-FILE DAYS")\n    print_info("Available DOYs: " + " ".join(all_doys))\n\n    if ask_yes_no("Process all available h-file days?", "yes"):\n        selected_doys = all_doys\n    else:\n        start_doy = ask_input("Start DOY", all_doys[0]).strip().zfill(3)\n        end_doy = ask_input("End DOY", all_doys[-1]).strip().zfill(3)\n\n        if not (start_doy.isdigit() and end_doy.isdigit()):\n            print_error("Start and end DOY must be numeric.")\n            sys.exit(1)\n\n        if int(start_doy) > int(end_doy):\n            print_error("Start DOY cannot be greater than End DOY.")\n            sys.exit(1)\n\n        selected_doys = [f"{d:03d}" for d in range(int(start_doy), int(end_doy) + 1)]\n\n    missing = [d for d in selected_doys if d not in scan_results]\n    if missing:\n        print_error("Missing h-files for selected DOYs: " + " ".join(missing))\n        sys.exit(1)\n\n    print_success("Selected DOYs: " + " ".join(selected_doys))\n    return {d: scan_results[d] for d in selected_doys}\n\n\ndef check_scan_consistency(scan_results: Dict[str, Dict]) -> bool:\n    yy_set = sorted({d["yy"] for d in scan_results.values()})\n    expt_set = sorted({d["expt"] for d in scan_results.values()})\n    netext_set = sorted({d["netext"] for d in scan_results.values()})\n\n    ok = True\n    if len(yy_set) != 1:\n        print_error("Mixed year suffixes: " + " ".join(yy_set))\n        ok = False\n\n    if len(expt_set) != 1:\n        print_error("Mixed experiment codes: " + " ".join(expt_set))\n        ok = False\n\n    if len(netext_set) != 1:\n        print_error("Mixed network extensions: " + " ".join(netext_set))\n        ok = False\n\n    if ok:\n        print_success("H-file settings are consistent.")\n\n    return ok\n\n\ndef detect_settings(scan_results: Dict[str, Dict]) -> Tuple[str, str, str, str, str, str, List[str]]:\n    doys = sorted(scan_results.keys())\n    if not doys:\n        return "", "", "", "", "", "", []\n\n    expt_counts: Dict[str, int] = {}\n    netext_counts: Dict[str, int] = {}\n    yy_set = set()\n\n    for d in scan_results.values():\n        expt_counts[d["expt"]] = expt_counts.get(d["expt"], 0) + 1\n        netext_counts[d["netext"]] = netext_counts.get(d["netext"], 0) + 1\n        yy_set.add(d["yy"])\n\n    expt = sorted(expt_counts.items(), key=lambda x: x[1], reverse=True)[0][0]\n    netext = sorted(netext_counts.items(), key=lambda x: x[1], reverse=True)[0][0]\n    yy = sorted(yy_set)[0]\n    year = yy_to_full_year(yy)\n\n    return year, doys[0], doys[-1], str(len(doys)), expt, netext, doys\n\n\ndef show_detected_settings(\n    year: str,\n    start_doy: str,\n    end_doy: str,\n    ndays: str,\n    expt: str,\n    netext: str,\n    doys: List[str],\n) -> None:\n    print_header("DETECTED SETTINGS")\n    print(f"{\'Year\':20s}: {year}")\n    print(f"{\'Start DOY\':20s}: {start_doy}")\n    print(f"{\'End DOY\':20s}: {end_doy}")\n    print(f"{\'Number of days\':20s}: {ndays}")\n    print(f"{\'Experiment code\':20s}: {expt}")\n    print(f"{\'Network extension\':20s}: {netext}")\n    print(f"{\'DOY list\':20s}: {\' \'.join(doys)}")\n\n\n# =============================================================================\n# DETECT GAMIT/GLOBK INSTALLATION\n# =============================================================================\n\ndef detect_gamit_paths(project_dir: Path) -> Dict[str, List[Path]]:\n    paths: Dict[str, List[Path]] = {"table_dirs": []}\n\n    def add_dir(p: Path) -> None:\n        p = p.expanduser().resolve()\n        if p.is_dir() and p not in paths["table_dirs"]:\n            paths["table_dirs"].append(p)\n\n    add_dir(project_dir / "tables")\n\n    for env in ["GG_TABLES", "GAMIT_TABLES"]:\n        val = os.environ.get(env, "").strip()\n        if val:\n            add_dir(Path(val).expanduser())\n\n    sh = shutil.which("sh_glred")\n    if sh:\n        p = Path(sh).resolve()\n        if p.parent.name in ["com", "bin"]:\n            add_dir(p.parent.parent / "tables")\n\n    for d in [\n        Path.home() / "gg" / "tables",\n        Path.home() / "GAMIT_GLOBK" / "tables",\n    ]:\n        add_dir(d)\n\n    return paths\n\n\n# =============================================================================\n# APR FIXES AND CHECKS\n# =============================================================================\n\n\ndef ensure_custom_apr_exists(project_dir: Path) -> bool:\n    """Check that a usable project APR exists. Supports custom_igs20/custom_igs14/custom_itrf08."""\n    p = choose_apr_file(project_dir)\n    if p and p.is_file():\n        print_success(f"Usable APR found: {p}")\n        return True\n    print_error("No usable APR found in project tables or process.defaults.")\n    print_error("Run the GAMIT part first or create a custom APR from a proper base frame APR.")\n    return False\n\n\ndef ensure_local_stations_in_apr(apr_file: Path, project_dir: Path, local_stations: List[str]) -> bool:\n    """Append missing local stations from lfile. to the selected APR file."""\n    lfile = project_dir / "tables" / "lfile."\n\n    if not apr_file.is_file():\n        print_error(f"APR file not found. Cannot append local stations: {apr_file}")\n        return False\n\n    if not lfile.is_file():\n        print_warning("lfile. not found; cannot check local stations.")\n        return True\n\n    backup_file(apr_file, "apr_before_local_station_append")\n\n    local_names = [st.upper().replace("_GPS", "") + "_GPS" for st in local_stations]\n    apr_stations = set()\n\n    with open(apr_file, "r", errors="ignore") as f:\n        for line in f:\n            parts = line.split()\n            if parts:\n                apr_stations.add(parts[0].upper())\n\n    missing = [name for name in local_names if name not in apr_stations]\n\n    if not missing:\n        print_success("All local stations already present in selected APR.")\n        return True\n\n    print_warning("Local stations missing from selected APR: " + " ".join(missing))\n\n    with open(lfile, "r", errors="ignore") as f:\n        lines = f.readlines()\n\n    missing_set = set(missing)\n    added_names = set()\n\n    with open(apr_file, "a", encoding="utf-8", errors="ignore") as f:\n        if not read_text_safe(apr_file).endswith("\\n"):\n            f.write("\\n")\n\n        for line in lines:\n            parts = line.split()\n            if not parts:\n                continue\n            name = parts[0].upper()\n            if not name.endswith("_GPS") and len(name) == 4:\n                name = name + "_GPS"\n            if name in missing_set and name not in added_names:\n                # APR/lfile columns after XYZ are velocity components in m/year.\n                # If lfile. has 0.0 0.0 0.0, keep them as zero velocity.\n                # Do NOT insert 10.0 here; 10 m/year would be physically wrong.\n                f.write(line if line.endswith("\\n") else line + "\\n")\n                added_names.add(name)\n\n    still_missing = sorted(missing_set - added_names)\n    if added_names:\n        print_success(f"Added {len(added_names)} station(s) to selected APR from lfile.: {\' \'.join(sorted(added_names))}")\n    if still_missing:\n        print_error("These stations were not found in lfile.: " + " ".join(still_missing))\n        return False\n    return True\n\n\ndef fix_zero_sigmas_in_apr(apr_file: Path, local_stations: List[str]) -> None:\n    """Clean unsafe old local APR entries from earlier experimental versions.\n\n    Important format note:\n    In the APR/lfile style used here, the three columns after X Y Z are ECEF\n    velocity components (m/year), followed by the reference epoch. They are not\n    coordinate sigmas. Therefore a local station line like:\n\n        SITE_GPS X Y Z 10.0 10.0 10.0 2026.x Updated from lfile\n\n    is not scientifically valid as a velocity line. Older experimental code had\n    inserted 10.0 as a loose-sigma idea, but in this APR/lfile context it can be\n    interpreted as 10 m/year velocity. This function resets those suspicious\n    lfile-derived 10.0 values to 0.0 0.0 0.0. Real station velocity should come\n    from long-term time series, external CSV, or a plate model chosen only in the\n    epoch-propagation step.\n    """\n    if not apr_file.is_file():\n        return\n\n    local_upper = {st.upper().replace("_GPS", "") for st in local_stations}\n\n    with open(apr_file, "r", errors="ignore") as f:\n        lines = f.readlines()\n\n    changed = False\n    new_lines = []\n    for line in lines:\n        parts = line.split()\n        if not parts:\n            new_lines.append(line)\n            continue\n        name = parts[0].upper()\n        code4 = name.replace("_GPS", "")\n        if name.endswith("_GPS") and code4 in local_upper and len(parts) >= 7:\n            try:\n                v1 = float(parts[4])\n                v2 = float(parts[5])\n                v3 = float(parts[6])\n                # 10 m/year is impossible for normal tectonic station velocity.\n                # Reset only local stations so global IGS APR files are not touched.\n                if abs(v1 - 10.0) < 1e-9 and abs(v2 - 10.0) < 1e-9 and abs(v3 - 10.0) < 1e-9:\n                    parts[4] = "0.0"\n                    parts[5] = "0.0"\n                    parts[6] = "0.0"\n                    line = " ".join(parts) + "\\n"\n                    changed = True\n            except ValueError:\n                pass\n        new_lines.append(line)\n\n    if changed:\n        backup_file(apr_file, "apr_before_reset_local_apr_columns")\n        with open(apr_file, "w", encoding="utf-8", errors="ignore") as f:\n            f.writelines(new_lines)\n\ndef check_sites_exist_in_apr(apr_path: Path, sites: List[str], label: str) -> bool:\n    """Check whether site codes exist in APR as SITE_GPS."""\n    text = read_text_safe(apr_path, max_bytes=50_000_000).upper()\n    missing = []\n\n    for site in sites:\n        token = site.upper()\n        if not token.endswith("_GPS"):\n            token = token + "_GPS"\n        if token not in text:\n            missing.append(token)\n\n    if missing:\n        print_warning(f"{label} missing from APR: {\' \'.join(missing)}")\n        return False\n\n    print_success(f"All {label} found in APR.")\n    return True\n\n\n\n\ndef is_dry_run() -> bool:\n    return os.environ.get("AUTOM_GAMIT_DRY_RUN", "0") == "1" or any(arg == "--dry-run" for arg in sys.argv[1:])\n\n# =============================================================================\n# COMMAND FILE REGENERATION AND PATCHING (Working globkg2.py logic)\n# =============================================================================\n\ndef regenerate_command_files(project_dir: Path) -> bool:\n    """Use sh_glred -cmd to create fresh command files compatible with installed version."""\n    print_progress("Regenerating command files with sh_glred -cmd")\n\n    log_dir = project_dir / "globk_glorg_logs"\n    log_dir.mkdir(exist_ok=True)\n    log_path = log_dir / "sh_glred_cmd.log"\n\n    cmd = ["sh_glred", "-cmd"]\n\n    if is_dry_run():\n        append_command_log(log_dir, "sh_glred -cmd dry-run", cmd)\n        print_info("[DRY-RUN] Would run: " + " ".join(cmd))\n        return True\n\n    try:\n        with open(log_path, "w", encoding="utf-8", errors="ignore") as f:\n            proc = subprocess.run(\n                cmd,\n                cwd=str(project_dir),\n                stdout=f,\n                stderr=subprocess.STDOUT,\n                text=True,\n                timeout=120,\n            )\n\n        if proc.returncode == 0:\n            print_success("Command files regenerated successfully.")\n            gsoln = project_dir / "gsoln"\n            tables = project_dir / "tables"\n            tables.mkdir(exist_ok=True)\n\n            for fname in ["globk.cmd", "glorg.cmd"]:\n                src = gsoln / fname\n                dst = tables / fname\n                if src.is_file():\n                    shutil.copy2(src, dst)\n                    print_success(f"Copied {fname} to tables/")\n                else:\n                    print_warning(f"{fname} was not found in gsoln/ after sh_glred -cmd")\n\n            return True\n\n        print_warning(f"sh_glred -cmd returned {proc.returncode}. Check log: {log_path}")\n        return False\n\n    except Exception as e:\n        print_error(f"Error during regeneration: {e}")\n        return False\n\n\ndef remove_auto_blocks(text: str) -> str:\n    """Remove old auto-generated blocks."""\n    text = re.sub(\n        r"\\n?\\* --- BEGIN AUTO GLOBK/GLORG FRAME BLOCK ---\\n.*?\\n\\* --- END AUTO GLOBK/GLORG FRAME BLOCK ---\\n?",\n        "\\n",\n        text,\n        flags=re.DOTALL,\n    )\n    return text\n\n\ndef patch_globk_glorg(project_dir: Path, apr_path: Path, eq_path: Optional[Path], stab_sites: List[str]) -> None:\n    """\n    Patch globk.cmd and glorg.cmd using the same simple command style that worked\n    in the user\'s successful globkg2.py run.\n\n    Important:\n    - No leading spaces before active command names.\n    - org is lowercase in org_opt.\n    - Add apr_site coordinate sigma constraints clearly as constraints, not velocities.\n    - Do not aggressively comment/clean old template lines.\n    """\n    tables = project_dir / "tables"\n\n    for fname in ["globk.cmd", "glorg.cmd"]:\n        p = tables / fname\n        if not p.is_file():\n            alt = project_dir / "gsoln" / fname\n            if alt.is_file():\n                shutil.copy2(alt, p)\n            else:\n                print_error(f"Missing {fname}; cannot patch.")\n                sys.exit(1)\n\n    backup_file(tables / "globk.cmd", "pre_patch")\n    backup_file(tables / "glorg.cmd", "pre_patch")\n\n    globk_text = read_text_safe(tables / "globk.cmd")\n    glorg_text = read_text_safe(tables / "glorg.cmd")\n\n    globk_text = remove_auto_blocks(globk_text)\n    glorg_text = remove_auto_blocks(glorg_text)\n\n    # Same working behavior as globkg2.py.\n    if re.search(r"^\\s*org_opt\\b", globk_text, re.MULTILINE):\n        globk_text = re.sub(\n            r"^\\s*org_opt\\b.*$",\n            "org_opt PSUM GDLF CMDS org",\n            globk_text,\n            flags=re.MULTILINE,\n        )\n    else:\n        globk_text = re.sub(\n            r"^apr_file\\b.*$",\n            r"\\g<0>\\norg_opt PSUM GDLF CMDS org",\n            globk_text,\n            flags=re.MULTILINE,\n        )\n\n    if not re.search(r"^\\s*prt_opt\\b", globk_text, re.MULTILINE):\n        globk_text += "\\nprt_opt NOPR\\n"\n\n    if not re.search(r"^\\s*org_cmd\\b", globk_text, re.MULTILINE):\n        globk_text += "\\norg_cmd glorg.cmd\\n"\n\n    block_globk = (\n        "\\n* --- BEGIN AUTO GLOBK/GLORG FRAME BLOCK ---\\n"\n        f"* Added by {Path(__file__).name} on {timestamp()}\\n"\n        "* Frame settings\\n"\n    )\n    if eq_path:\n        # Keep eq optional. In the successful run EQ was not used.\n        block_globk += f"eq_file {path_for_cmd(eq_path)}\\n"\n    block_globk += f"apr_file {path_for_cmd(apr_path)}\\n"\n    block_globk += "* A priori site coordinate sigmas/constraints; these are not station velocities.\\n"\n    block_globk += "apr_site all 10 10 10 0 0 0\\n"\n    block_globk += "org_cmd glorg.cmd\\n"\n    block_globk += "org_opt PSUM GDLF CMDS org\\n"\n    block_globk += "prt_opt NOPR\\n"\n    block_globk += "* --- END AUTO GLOBK/GLORG FRAME BLOCK ---\\n"\n\n    block_glorg = (\n        "\\n* --- BEGIN AUTO GLOBK/GLORG FRAME BLOCK ---\\n"\n        f"* Added by {Path(__file__).name} on {timestamp()}\\n"\n        "* Frame settings\\n"\n    )\n    block_glorg += f"apr_file {path_for_cmd(apr_path)}\\n"\n    block_glorg += "stab_it 4 0.8 3.0\\n"\n    block_glorg += "stab_site clear\\n"\n    if stab_sites:\n        block_glorg += "stab_site " + " ".join(stab_sites) + "\\n"\n    block_glorg += "pos_org xtran ytran ztran xrot yrot zrot\\n"\n    block_glorg += "* --- END AUTO GLOBK/GLORG FRAME BLOCK ---\\n"\n\n    globk_text += block_globk\n    glorg_text += block_glorg\n\n    (tables / "globk.cmd").write_text(globk_text)\n    (tables / "glorg.cmd").write_text(glorg_text)\n\n    gsoln = project_dir / "gsoln"\n    gsoln.mkdir(exist_ok=True)\n    shutil.copy2(tables / "globk.cmd", gsoln / "globk.cmd")\n    shutil.copy2(tables / "glorg.cmd", gsoln / "glorg.cmd")\n\n    print_success("Patched command files and copied to gsoln/.")\n\n\ndef _is_active_command_line(stripped: str) -> bool:\n    if not stripped:\n        return False\n    if stripped.startswith("*") or stripped.startswith("#"):\n        return False\n    if stripped.lower().startswith("x "):\n        return False\n    return True\n\n\ndef get_effective_cmd_value(cmd_file: Path, command_name: str) -> Optional[str]:\n    """Return the last active value for a command such as apr_file or eq_file.\n\n    GAMIT/GLOBK command files contain many template lines. A simple grep can\n    therefore show old/default APR/EQ examples. The last active patched line is\n    the practical value used by this launcher.\n    """\n    if not cmd_file.is_file():\n        return None\n    value: Optional[str] = None\n    for line in read_text_safe(cmd_file).splitlines():\n        stripped = line.strip()\n        if not _is_active_command_line(stripped):\n            continue\n        parts = stripped.split()\n        if parts and parts[0].lower() == command_name.lower() and len(parts) >= 2:\n            value = " ".join(parts[1:])\n    return value\n\n\n\n\ndef audit_globk_glorg_constraint_commands(project_dir: Path, log_dir: Path) -> None:\n    """Check key GLOBK/GLORG constraint commands emphasized in Doc-151/Doc-176."""\n    print_header("GLOBK/GLORG CONSTRAINT COMMAND AUDIT")\n    gsoln = project_dir / "gsoln"\n    globk_cmd = gsoln / "globk.cmd"\n    glorg_cmd = gsoln / "glorg.cmd"\n    globk_text = read_text_safe(globk_cmd).lower()\n    glorg_text = read_text_safe(glorg_cmd).lower()\n    checks = [\n        ("globk apr_site", "apr_site" in globk_text),\n        ("globk apr_file", "apr_file" in globk_text),\n        ("glorg apr_file", "apr_file" in glorg_text),\n        ("glorg stab_site", "stab_site" in glorg_text),\n        ("glorg pos_org", "pos_org" in glorg_text),\n    ]\n    lines = []\n    for label, ok in checks:\n        msg = f"{label}: {\'OK\' if ok else \'MISSING\'}"\n        lines.append(msg)\n        if ok:\n            print_success(msg)\n        else:\n            print_warning(msg)\n    print_info("apr_site 10 10 10 values are a-priori coordinate sigmas/constraints, not velocities.")\n    print_info("GLORG realizes the reference frame by generalized constraints using apr_file + stab_site + Helmert parameters.")\n    out = log_dir / "globk_glorg_constraint_audit.txt"\n    out.write_text("\\n".join(lines) + "\\n", encoding="utf-8")\n    print_success(f"Saved GLOBK/GLORG constraint audit: {out}")\n\ndef report_effective_command_settings(project_dir: Path, log_dir: Path, frame_name: str) -> None:\n    """Print and save the effective active APR/EQ lines after patching."""\n    print_header("EFFECTIVE GLOBK/GLORG COMMAND SETTINGS")\n    gsoln = project_dir / "gsoln"\n    globk_cmd = gsoln / "globk.cmd"\n    glorg_cmd = gsoln / "glorg.cmd"\n\n    globk_apr = get_effective_cmd_value(globk_cmd, "apr_file")\n    globk_eq = get_effective_cmd_value(globk_cmd, "eq_file")\n    glorg_apr = get_effective_cmd_value(glorg_cmd, "apr_file")\n\n    lines = [\n        f"Frame selected by launcher : {frame_name}",\n        f"globk.cmd effective apr_file: {globk_apr or \'not found\'}",\n        f"globk.cmd effective eq_file : {globk_eq or \'not found\'}",\n        f"glorg.cmd effective apr_file: {glorg_apr or \'not found\'}",\n    ]\n\n    for line in lines:\n        print_info(line)\n\n    if frame_name.upper() == "ITRF08":\n        for label, value in [("globk apr", globk_apr), ("glorg apr", glorg_apr)]:\n            if value and "itrf08" not in value.lower() and "custom_itrf08" not in value.lower() and "custom_igs08" not in value.lower() and "igs08" not in value.lower():\n                print_warning(f"{label} does not look like IGS08/ITRF2008: {value}")\n\n    try:\n        log_dir.mkdir(parents=True, exist_ok=True)\n        out = log_dir / "effective_command_settings.txt"\n        out.write_text("\\n".join(lines) + "\\n", encoding="utf-8")\n        print_success(f"Saved effective command settings: {out}")\n    except Exception as e:\n        print_warning(f"Could not save effective command settings: {e}")\n\n\n# =============================================================================\n# RUN SH_GLRED AND VERIFY\n# =============================================================================\n\ndef is_harmless_glred_noise(line: str) -> bool:\n    """Return True for known non-fatal tcsh/sh_glred housekeeping messages.\n\n    GAMIT/GLOBK shell scripts sometimes try to remove or list optional temporary\n    files that do not exist yet. Messages such as "ls: No match." and missing\n    "binhlist" files are common during successful runs. Full lines are still\n    written to the log file; they are only hidden from the live dashboard to\n    avoid confusion.\n    """\n    s = line.strip()\n    harmless_exact = {\n        "ls: No match.",\n        "rm: cannot remove \'binhlist.GLX\': No such file or directory",\n        "rm: cannot remove \'binhlist.glb\': No such file or directory",\n    }\n    if s in harmless_exact:\n        return True\n    if s.startswith("rm: cannot remove \'binhlist.") and "No such file or directory" in s:\n        return True\n    if s.endswith("/gsoln/globk.cmd already exists. NOT overwritten"):\n        return True\n    if s.endswith("/gsoln/glorg.cmd already exists. NOT overwritten"):\n        return True\n    if s.endswith("globk.cmd already exists. NOT overwritten"):\n        return True\n    if s.endswith("glorg.cmd already exists. NOT overwritten"):\n        return True\n    return False\n\n\ndef run_sh_glred(\n    project_dir: Path,\n    year: str,\n    start_doy: str,\n    end_doy: str,\n    expt: str,\n    netext: str,\n    options: str,\n    log_dir: Path,\n) -> int:\n    opt_tokens = options.split()\n\n    cmd = [\n        "sh_glred",\n        "-s",\n        year,\n        start_doy,\n        year,\n        end_doy,\n        "-expt",\n        expt,\n        "-netext",\n        netext,\n        "-opt",\n    ] + opt_tokens\n\n    append_command_log(log_dir, f"daily sh_glred {start_doy}-{end_doy}", cmd)\n    log_path = log_dir / f"sh_glred_{start_doy}_{end_doy}.log"\n\n    print_progress("Running: " + " ".join(cmd))\n    print_info(f"Log file: {log_path}")\n    if is_dry_run():\n        print_info("[DRY-RUN] sh_glred command preview only; not executed.")\n        return 0\n\n    try:\n        with open(log_path, "w", encoding="utf-8", errors="ignore") as f:\n            proc = subprocess.Popen(\n                cmd,\n                cwd=str(project_dir),\n                stdout=subprocess.PIPE,\n                stderr=subprocess.STDOUT,\n                text=True,\n                bufsize=1,\n            )\n\n            assert proc.stdout is not None\n            hidden_noise = 0\n            for line in proc.stdout:\n                f.write(line)\n                if is_harmless_glred_noise(line):\n                    hidden_noise += 1\n                    continue\n                print(line, end="")\n\n            rc = proc.wait()\n            if hidden_noise:\n                print_info(f"Suppressed {hidden_noise} harmless sh_glred housekeeping message(s). Full output is preserved in: {log_path}")\n\n        print_info(f"Return code: {rc}")\n        return rc\n\n    except Exception as e:\n        print_error(f"Exception: {e}")\n        return 1\n\n\ndef run_combined_survey(\n    project_dir: Path,\n    year: str,\n    start_doy: str,\n    end_doy: str,\n    expt: str,\n    netext: str,\n    ndays: int,\n    log_dir: Path,\n) -> int:\n    cmd = [\n        "sh_glred",\n        "-s",\n        year,\n        start_doy,\n        year,\n        end_doy,\n        "-expt",\n        expt,\n        "-netext",\n        netext,\n        "-globk_cmd_prefix",\n        "COMB",\n        "-opt",\n        "G",\n        "-ncomb",\n        str(ndays),\n    ]\n\n    append_command_log(log_dir, f"combined sh_glred {start_doy}-{end_doy}", cmd)\n    log_path = log_dir / f"sh_glred_combined_{start_doy}_{end_doy}.log"\n\n    print_progress("Running: " + " ".join(cmd))\n    print_info(f"Log file: {log_path}")\n    if is_dry_run():\n        print_info("[DRY-RUN] combined sh_glred command preview only; not executed.")\n        return 0\n\n    try:\n        with open(log_path, "w", encoding="utf-8", errors="ignore") as f:\n            proc = subprocess.Popen(\n                cmd,\n                cwd=str(project_dir),\n                stdout=subprocess.PIPE,\n                stderr=subprocess.STDOUT,\n                text=True,\n                bufsize=1,\n            )\n\n            assert proc.stdout is not None\n            hidden_noise = 0\n            for line in proc.stdout:\n                f.write(line)\n                if is_harmless_glred_noise(line):\n                    hidden_noise += 1\n                    continue\n                print(line, end="")\n\n            rc = proc.wait()\n            if hidden_noise:\n                print_info(f"Suppressed {hidden_noise} harmless sh_glred housekeeping message(s). Full output is preserved in: {log_path}")\n\n        print_info(f"Return code: {rc}")\n        return rc\n\n    except Exception as e:\n        print_error(f"Exception during combined survey: {e}")\n        return 1\n\n\ndef verify_org_files(project_dir: Path, expt: str, yy: str, doys: List[str]) -> List[Path]:\n    """Return list of existing daily .org files using correct pattern globk_<expt>_<yy><doy>.org."""\n    orgs: List[Path] = []\n    gsoln = project_dir / "gsoln"\n\n    for doy in doys:\n        expected = gsoln / f"globk_{expt}_{yy}{doy}.org"\n        if expected.is_file() and expected.stat().st_size > 0:\n            orgs.append(expected)\n\n    return orgs\n\n\ndef find_combined_org(project_dir: Path, expt: str, yy: str, start_doy: str, end_doy: str) -> List[Path]:\n    """Find combined .org file."""\n    gsoln = project_dir / "gsoln"\n    expected = gsoln / f"globk_{expt}_{yy}{start_doy}_{yy}{end_doy}.org"\n\n    if expected.is_file() and expected.stat().st_size > 0:\n        return [expected]\n\n    return sorted(gsoln.glob(f"*{expt}*{yy}{start_doy}*{yy}{end_doy}*.org"))\n\n\n# =============================================================================\n# FRAME SELECTION\n# =============================================================================\n\ndef detect_frame_family_from_apr(apr_path: Optional[Path]) -> str:\n    if apr_path is None:\n        return "Unknown"\n\n    text = read_text_safe(apr_path, max_bytes=200_000)\n    if text:\n        t = text.lower()\n        if "itrf20" in t or "igs20" in t or "igb20" in t or "itrf2020" in t:\n            return "IGS20"\n        if "itrf14" in t or "igs14" in t or "igb14" in t or "itrf2014" in t:\n            return "IGS14"\n        if "itrf08" in t or "igs08" in t or "igb08" in t or "itrf2008" in t:\n            return "IGS08"\n\n    name = apr_path.name.lower()\n    if "igs20" in name or "igb20" in name or "itrf20" in name:\n        return "IGS20"\n    if "igs14" in name or "igb14" in name or "itrf14" in name:\n        return "IGS14"\n    if "igs08" in name or "igb08" in name or "itrf08" in name or "custom_itrf08" in name or "all_pbo_igs08" in name:\n        return "IGS08"\n\n    return "Unknown"\n\n\ndef find_frame_files(project_dir: Path, frame: str) -> Tuple[Optional[Path], Optional[Path]]:\n    detected = detect_gamit_paths(project_dir)\n    search_dirs = detected["table_dirs"]\n\n    if frame.upper() == "IGS20":\n        apr_candidates = ["igs20.apr", "igb20_comb.apr", "igb20.apr", "itrf20.apr"]\n        eq_candidates = ["igs20.eq", "igb20_comb.eq", "igb20.eq", "itrf20.eq", "All_PBO.eq"]\n    elif frame.upper() == "IGS14":\n        apr_candidates = ["igs14_comb.apr", "igs14.apr", "igb14_comb.apr", "igb14.apr", "itrf14.apr"]\n        eq_candidates = ["igs14_comb.eq", "igs14.eq", "igb14_comb.eq", "igb14.eq", "itrf14.eq", "All_PBO.eq"]\n    elif frame.upper() in ("IGS08", "ITRF08"):\n        apr_candidates = [\n            "custom_igs08.apr",\n            "custom_itrf08.apr",\n            "All_PBO_igs08.apr",\n            "itrf08_comb.apr",\n            "itrf08.apr",\n            "igb08_comb.apr",\n            "igb08.apr",\n            "igs08.apr",\n        ]\n        eq_candidates = ["All_PBO.eq", "itrf08_comb.eq", "itrf08.eq", "igb08_comb.eq", "igb08.eq", "igs08.eq"]\n    else:\n        return None, None\n\n    apr_path = None\n\n    for d in search_dirs:\n        for name in apr_candidates:\n            p = d / name\n            if p.is_file():\n                apr_path = p\n                break\n        if apr_path:\n            break\n\n    if not apr_path:\n        return None, None\n\n    eq_path = None\n    for d in search_dirs:\n        for name in eq_candidates:\n            p = d / name\n            if p.is_file():\n                eq_path = p\n                break\n        if eq_path:\n            break\n\n    return apr_path, eq_path\n\n\n\ndef apr_family_from_name(apr_file: str) -> str:\n    name = Path(apr_file).name.lower()\n    if any(tok in name for tok in ["igs20", "igb20", "igc20", "itrf20", "custom_igs20"]):\n        return "IGS20"\n    if any(tok in name for tok in ["igs14", "igb14", "itrf14", "all_pbo_igs14", "custom_igs14"]):\n        return "IGS14"\n    if any(tok in name for tok in ["igs08", "igb08", "itrf08", "all_pbo_igs08", "custom_itrf08"]):\n        return "IGS08"\n    return "Unknown"\n\n\ndef parse_aprf_from_process_defaults(project_dir: Path) -> Optional[Path]:\n    defaults = project_dir / "tables" / "process.defaults"\n    if not defaults.is_file():\n        return None\n    text = read_text_safe(defaults)\n    m = re.search(r"^\\s*set\\s+aprf\\s*=\\s*(\\S+)", text, re.I | re.M)\n    if not m:\n        m = re.search(r"^\\s*apr_file\\s+(\\S+)", text, re.I | re.M)\n    if not m:\n        return None\n    token = m.group(1).strip().strip(\'"\').strip("\'")\n    candidates = []\n    p = Path(token).expanduser()\n    if p.is_absolute():\n        candidates.append(p)\n    candidates.append(project_dir / "tables" / token)\n    candidates.append(project_dir / token)\n    for d in detect_gamit_paths(project_dir)["table_dirs"]:\n        candidates.append(d / token)\n    for p in candidates:\n        if p.is_file():\n            return p\n    return None\n\n\ndef choose_apr_file(project_dir: Path) -> Optional[Path]:\n    tables = project_dir / "tables"\n\n    # First priority: the exact APR selected by the GAMIT part in process.defaults.\n    p = parse_aprf_from_process_defaults(project_dir)\n    if p and p.is_file():\n        return p\n\n    # Next priority: any custom APR created by the GAMIT part.\n    if tables.is_dir():\n        for name in ["custom_igs20.apr", "custom_igs14.apr", "custom_igs08.apr", "custom_itrf08.apr"]:\n            p = tables / name\n            if p.is_file():\n                return p\n\n        # Then common frame APRs in project tables.\n        for name in ["igb20_comb.apr", "igs20.apr", "igs14_comb.apr", "igb14_comb.apr", "All_PBO_igs08.apr", "itrf08.apr"]:\n            p = tables / name\n            if p.is_file():\n                return p\n\n    return None\n\n\ndef eq_family_from_name(eq_file: str) -> str:\n    """Return a simple frame/family hint from an EQ filename."""\n    name = Path(eq_file).name.lower()\n    if any(tok in name for tok in ["igs20", "igb20", "igc20", "itrf20"]):\n        return "IGS20"\n    if any(tok in name for tok in ["igs14", "igb14", "itrf14"]):\n        return "IGS14"\n    if any(tok in name for tok in ["igs08", "igb08", "itrf08"]):\n        return "IGS08"\n    if "pbo" in name:\n        return "PBO/general"\n    return "Unknown"\n\n\ndef collect_table_files(project_dir: Path, extension: str) -> List[Path]:\n    """Collect APR/EQ files from project tables and GAMIT/GLOBK table folders."""\n    detected = detect_gamit_paths(project_dir)\n    dirs: List[Path] = []\n\n    for d in [project_dir / "tables", project_dir]:\n        try:\n            if d.is_dir() and d.resolve() not in [x.resolve() for x in dirs]:\n                dirs.append(d)\n        except Exception:\n            pass\n\n    for d in detected.get("table_dirs", []):\n        try:\n            if d.is_dir() and d.resolve() not in [x.resolve() for x in dirs]:\n                dirs.append(d)\n        except Exception:\n            pass\n\n    for d in [Path.home() / "gg" / "tables", Path.home() / "GAMIT_GLOBK" / "tables"]:\n        try:\n            if d.is_dir() and d.resolve() not in [x.resolve() for x in dirs]:\n                dirs.append(d)\n        except Exception:\n            pass\n\n    files: List[Path] = []\n    seen = set()\n    for d in dirs:\n        for p in sorted(d.glob(f"*{extension}")):\n            try:\n                rp = p.resolve()\n            except Exception:\n                rp = p\n            if p.is_file() and str(rp) not in seen:\n                files.append(p)\n                seen.add(str(rp))\n    return files\n\n\ndef preferred_eq_names_for_apr(apr_path: Path) -> List[str]:\n    """Recommended EQ file names for the selected APR/frame."""\n    family = detect_frame_family_from_apr(apr_path)\n    base_eq = apr_path.name.replace(".apr", ".eq")\n\n    if family == "IGS20":\n        return [\n            base_eq,\n            "igb20_comb.eq",\n            "itrf20u24.eq",\n            "itrf20u23.eq",\n            "itrf20.eq",\n            "igs20.eq",\n            "igb20.eq",\n            "igc20.eq",\n            "All_PBO.eq",\n        ]\n\n    if family == "IGS14":\n        return [\n            base_eq,\n            "igb14_comb.eq",\n            "igs14_comb.eq",\n            "itrf14.eq",\n            "igb14.eq",\n            "All_PBO.eq",\n        ]\n\n    if family == "IGS08":\n        return [\n            base_eq,\n            "All_PBO.eq",\n            "All_PBO_eqs.eq",\n            "All_PBO_edits.eq",\n            "igs08.eq",\n            "igb08.eq",\n            "itrf08.eq",\n        ]\n\n    return [base_eq, "All_PBO.eq"]\n\n\ndef choose_eq_file(project_dir: Path, apr: Path) -> Optional[Path]:\n    """\n    Auto EQ selection. First try same-name EQ, then frame-compatible common EQ files.\n    This avoids the earlier situation where custom_itrf08.apr gave no EQ although\n    All_PBO.eq or frame EQ files were available in ~/gg/tables.\n    """\n    eq_files = collect_table_files(project_dir, ".eq")\n    if not eq_files:\n        return None\n\n    preferred = preferred_eq_names_for_apr(apr)\n    for name in preferred:\n        for p in eq_files:\n            if p.name.lower() == name.lower():\n                return p\n\n    return None\n\n\ndef suggest_apr_file(project_dir: Path, apr_files: List[Path]) -> Optional[Path]:\n    """Suggest the project APR already selected by GAMIT, otherwise a custom APR."""\n    auto = choose_apr_file(project_dir)\n    if auto and auto.is_file():\n        for p in apr_files:\n            try:\n                if p.resolve() == auto.resolve():\n                    return p\n            except Exception:\n                if str(p) == str(auto):\n                    return p\n\n    preferred_names = [\n        "custom_igs20.apr",\n        "custom_igs14.apr",\n        "custom_igs08.apr",\n        "custom_itrf08.apr",\n        "igb20_comb.apr",\n        "igs20.apr",\n        "igs14_comb.apr",\n        "All_PBO_igs08.apr",\n    ]\n    for name in preferred_names:\n        for p in apr_files:\n            if p.name.lower() == name.lower():\n                return p\n    return apr_files[0] if apr_files else None\n\n\ndef suggest_eq_file(project_dir: Path, apr_path: Path, eq_files: List[Path]) -> Optional[Path]:\n    """Suggest a frame-compatible EQ file for the chosen APR."""\n    if not eq_files:\n        return None\n    preferred = preferred_eq_names_for_apr(apr_path)\n    for name in preferred:\n        for p in eq_files:\n            if p.name.lower() == name.lower():\n                return p\n    return eq_files[0]\n\n\ndef show_numbered_file_list(title: str, files: List[Path], suggested: Optional[Path] = None) -> None:\n    """Print APR/EQ files as a numbered list and mark the suggestion."""\n    print_header(title)\n    if not files:\n        print_warning("No files found.")\n        return\n\n    try:\n        suggested_resolved = suggested.resolve() if suggested else None\n    except Exception:\n        suggested_resolved = suggested\n\n    for i, p in enumerate(files, 1):\n        try:\n            same = suggested_resolved is not None and p.resolve() == suggested_resolved\n        except Exception:\n            same = suggested is not None and str(p) == str(suggested)\n\n        family = detect_frame_family_from_apr(p) if p.suffix.lower() == ".apr" else eq_family_from_name(p.name)\n        mark = "  <-- suggested" if same else ""\n        print(f"{i:2d}. {p}    [{family}]{mark}")\n\n\ndef ask_file_from_numbered_list(\n    prompt: str,\n    files: List[Path],\n    suggested: Optional[Path],\n    required: bool = True,\n    allow_none: bool = False,\n) -> Optional[Path]:\n    """\n    Ask user to select a file by number or full path.\n    Empty input uses the suggested file when available.\n    """\n    if suggested:\n        default = str(suggested)\n    elif allow_none and not required:\n        default = "none"\n    else:\n        default = ""\n\n    while True:\n        if default:\n            ans = input(ctext(f"{prompt} [{default}]: ", Colors.CYAN)).strip()\n        else:\n            ans = input(ctext(f"{prompt}: ", Colors.CYAN)).strip()\n\n        if ans == "":\n            if suggested:\n                return suggested\n            if allow_none and not required:\n                return None\n            print_warning("Required. Please enter a list number or full path.")\n            continue\n\n        if allow_none and ans.lower() in ("none", "no", "skip", "0"):\n            return None\n\n        if ans.isdigit():\n            idx = int(ans)\n            if 1 <= idx <= len(files):\n                return files[idx - 1]\n            print_warning(f"Number must be between 1 and {len(files)}.")\n            continue\n\n        p = normalize_path(ans)\n        if p.is_file():\n            return p\n\n        print_warning(f"File not found: {p}")\n\n\ndef ask_manual_apr_eq_files(project_dir: Path) -> Tuple[Path, Optional[Path], str]:\n    """Manual APR/EQ selection with visible lists and suggestions."""\n    apr_files = collect_table_files(project_dir, ".apr")\n    suggested_apr = suggest_apr_file(project_dir, apr_files)\n    show_numbered_file_list("AVAILABLE APR FILES", apr_files, suggested_apr)\n\n    apr_path = ask_file_from_numbered_list(\n        "APR file - enter list number or full path",\n        apr_files,\n        suggested_apr,\n        required=True,\n        allow_none=False,\n    )\n\n    if not apr_path or not apr_path.is_file():\n        print_error("APR file is required.")\n        sys.exit(1)\n\n    frame_name = detect_frame_family_from_apr(apr_path)\n\n    eq_files = collect_table_files(project_dir, ".eq")\n    suggested_eq = suggest_eq_file(project_dir, apr_path, eq_files)\n    show_numbered_file_list("AVAILABLE EQ FILES", eq_files, suggested_eq)\n\n    print_info("EQ file is optional for a short test run, but recommended for final long time-series processing.")\n    eq_path = ask_file_from_numbered_list(\n        "EQ file - enter list number/full path, or type none",\n        eq_files,\n        suggested_eq,\n        required=False,\n        allow_none=True,\n    )\n\n    return apr_path, eq_path, frame_name\n\n\ndef ask_file_path(prompt: str, default: str = "", required: bool = True) -> Optional[Path]:\n    while True:\n        ans = ask_input(prompt, default).strip()\n\n        if ans == "" and not required:\n            return None\n\n        if ans == "" and required:\n            print_warning("Required. Please enter a path.")\n            continue\n\n        p = normalize_path(ans)\n        if p.is_file():\n            return p\n\n        print_warning(f"File not found: {p}")\n        if not required and ask_yes_no("Skip?", "yes"):\n            return None\n\n\ndef print_frame_family_note() -> None:\n    print_header("IGS / ITRF FRAME NOTE")\n    print_info("ITRF is the official terrestrial reference frame. IGS is the GNSS realization aligned to that ITRF frame.")\n    print_info("Read the menu as one family: IGS20/ITRF2020, IGS14/ITRF2014, or IGS08/ITRF2008.")\n    print_info("Do not mix families: if you select IGS20, use 20-series APR/EQ/products; if IGS14, use 14-series; if IGS08, use 08/ITRF2008-series.")\n\n\ndef select_frame(project_dir: Path) -> Tuple[Path, Optional[Path], str]:\n    print_header("SELECT REFERENCE FRAME")\n    print_info("Choose the reference frame for your final solution.")\n    print_frame_family_note()\n\n    choices = [\n        "IGS20 / ITRF2020",\n        "IGS14 / ITRF2014",\n        "IGS08 / ITRF2008",\n        "Auto-detect from existing files",\n        "Manually specify APR and EQ files",\n    ]\n\n    idx = ask_choice("Choose reference frame:", choices, default=3)\n\n    apr_path = None\n    eq_path = None\n    frame_name = ""\n\n    if idx == 0:\n        frame_name = "IGS20"\n        apr_path, eq_path = find_frame_files(project_dir, "IGS20")\n    elif idx == 1:\n        frame_name = "IGS14"\n        apr_path, eq_path = find_frame_files(project_dir, "IGS14")\n    elif idx == 2:\n        frame_name = "IGS08"\n        apr_path, eq_path = find_frame_files(project_dir, "IGS08")\n    elif idx == 3:\n        apr_path = choose_apr_file(project_dir)\n        if apr_path:\n            frame_name = detect_frame_family_from_apr(apr_path)\n            eq_path = choose_eq_file(project_dir, apr_path)\n        else:\n            print_warning("Auto-detect failed. Please specify manually.")\n            idx = 4\n\n    if idx == 4 or apr_path is None:\n        apr_path, eq_path, frame_name = ask_manual_apr_eq_files(project_dir)\n\n    if not apr_path or not apr_path.is_file():\n        print_error("APR file is required.")\n        sys.exit(1)\n\n    print_success(f"Frame selected: {frame_name}")\n    print_success(f"APR file: {apr_path}")\n\n    if eq_path:\n        print_success(f"EQ file: {eq_path}")\n    else:\n        print_info("EQ file not used/found.")\n\n    return apr_path, eq_path, frame_name\n\n\n# =============================================================================\n# STABILIZATION SITES DETECTION\n# =============================================================================\n\ndef detect_stab_sites(project_dir: Path, doys: List[str]) -> List[str]:\n    control = project_dir / "control"\n    per_day = []\n\n    if control.is_dir():\n        for doy in doys:\n            p = control / f"active_igs_sites_{doy}.txt"\n            if p.is_file():\n                sites = []\n                for line in read_text_safe(p).splitlines():\n                    line = line.strip()\n                    if not line or line.startswith("*") or line.startswith("#"):\n                        continue\n\n                    for token in line.split():\n                        token = token.upper()\n                        if re.match(r"^[A-Z0-9]{4}$", token):\n                            sites.append(token)\n\n                if sites:\n                    per_day.append(set(sites))\n\n    if per_day:\n        common = set.intersection(*per_day) if len(per_day) > 1 else per_day[0]\n        if len(common) >= 3:\n            return sorted(common)\n\n    sites_defaults = project_dir / "tables" / "sites.defaults"\n    if sites_defaults.is_file():\n        sites = []\n        for line in read_text_safe(sites_defaults).splitlines():\n            stripped = line.strip()\n            if not stripped or stripped.startswith("*") or stripped.startswith("#"):\n                continue\n\n            parts = stripped.split()\n            if not parts:\n                continue\n\n            # Skip x-disabled lines but do not skip real station XMIS.\n            if parts[0].lower() == "x":\n                continue\n\n            if len(parts) >= 3 and parts[2].lower() in ["ftprnx", "glreps"]:\n                site = parts[0].upper()\n                if re.match(r"^[A-Z0-9]{4}$", site) and site not in sites:\n                    sites.append(site)\n\n        if sites:\n            return sites\n\n    print_warning("No stabilization sites auto-detected. Please enter them.")\n    manual = ask_input(\n        "Stabilization sites (space-separated, 4-char codes)",\n        "BADG DAEJ DGAR DJIG IISC MAL2 NTUS POL2 REUN XMIS",\n    ).upper().strip()\n\n    return [s for s in manual.split() if re.match(r"^[A-Z0-9]{4}$", s)]\n\n\n# =============================================================================\n# FINAL RESULTS DASHBOARD\n# =============================================================================\n\ndef parse_pbo_coordinates_from_org(org_file: Path, local_stations: List[str]) -> List[Dict[str, object]]:\n    """\n    Parse final pbo. coordinate records from a GLOBK/GLORG .org file.\n\n    Expected useful line form:\n    pbo. SITE_GPS ... X Y Z sigX sigY sigZ ... | lat lon h ... | N E U sigN sigE sigU ...\n\n    Returns one row per requested local station found.\n    """\n    rows: List[Dict[str, object]] = []\n    wanted = {s.upper() for s in local_stations}\n    seen = set()\n\n    if not org_file.is_file():\n        return rows\n\n    for line in read_text_safe(org_file).splitlines():\n        if not line.startswith("pbo."):\n            continue\n\n        parts_pipe = line.split("|")\n        left = parts_pipe[0].split()\n        if len(left) < 12:\n            continue\n\n        station = left[1].upper()\n        station4 = station.replace("_GPS", "")\n\n        if station4 not in wanted or station4 in seen:\n            continue\n\n        # Left side usually ends with:\n        # X Y Z sigX sigY sigZ corrXY corrXZ corrYZ\n        try:\n            x = float(left[-9])\n            y = float(left[-8])\n            z = float(left[-7])\n            sig_x = float(left[-6])\n            sig_y = float(left[-5])\n            sig_z = float(left[-4])\n        except Exception:\n            x = y = z = sig_x = sig_y = sig_z = None\n\n        lat = lon = height = None\n        sig_h = None\n        if len(parts_pipe) >= 2:\n            middle = parts_pipe[1].split()\n            if len(middle) >= 3:\n                try:\n                    lat = float(middle[0])\n                    lon = float(middle[1])\n                    height = float(middle[2])\n                except Exception:\n                    pass\n            if len(middle) >= 6:\n                try:\n                    sig_h = float(middle[5])\n                except Exception:\n                    pass\n\n        north = east = up = sig_n = sig_e = sig_u = None\n        if len(parts_pipe) >= 3:\n            right = parts_pipe[2].split()\n            if len(right) >= 6:\n                try:\n                    north = float(right[0])\n                    east = float(right[1])\n                    up = float(right[2])\n                    sig_n = float(right[3])\n                    sig_e = float(right[4])\n                    sig_u = float(right[5])\n                except Exception:\n                    pass\n\n        rows.append({\n            "station": station,\n            "x_m": x,\n            "y_m": y,\n            "z_m": z,\n            "sig_x_m": sig_x,\n            "sig_y_m": sig_y,\n            "sig_z_m": sig_z,\n            "lat_deg": lat,\n            "lon_deg": lon,\n            "height_m": height,\n            "sig_height_m": sig_h,\n            "north_m": north,\n            "east_m": east,\n            "up_m": up,\n            "sig_n_m": sig_n,\n            "sig_e_m": sig_e,\n            "sig_u_m": sig_u,\n        })\n        seen.add(station4)\n\n    return rows\n\n\ndef extract_pos_statistics(org_file: Path) -> List[str]:\n    """Extract POS STATISTICS lines from .org file."""\n    if not org_file.is_file():\n        return []\n    return [line.strip() for line in read_text_safe(org_file).splitlines() if "POS STATISTICS" in line.upper()]\n\n\ndef extract_solution_summary(org_file: Path) -> List[str]:\n    """Extract a few key summary lines from .org file."""\n    if not org_file.is_file():\n        return []\n\n    keep = []\n    for line in read_text_safe(org_file).splitlines():\n        u = line.upper()\n        if (\n            "SOLUTION:" in u\n            or "BASELINE ENTRIES" in u\n            or "POS STATISTICS" in u\n            or "WRMS ENU" in u\n            or "NRMS ENU" in u\n        ):\n            keep.append(line.strip())\n\n    return keep[:50]\n\n\ndef write_coordinates_csv(rows: List[Dict[str, object]], out_csv: Path) -> None:\n    """Write coordinate rows to CSV without external dependencies."""\n    out_csv.parent.mkdir(parents=True, exist_ok=True)\n    headers = [\n        "station",\n        "x_m", "y_m", "z_m",\n        "sig_x_m", "sig_y_m", "sig_z_m",\n        "lat_deg", "lon_deg", "height_m", "sig_height_m",\n        "north_m", "east_m", "up_m",\n        "sig_n_m", "sig_e_m", "sig_u_m",\n    ]\n\n    with open(out_csv, "w", encoding="utf-8") as f:\n        f.write(",".join(headers) + "\\n")\n        for row in rows:\n            vals = []\n            for h in headers:\n                v = row.get(h)\n                if v is None:\n                    vals.append("")\n                elif isinstance(v, float):\n                    vals.append(f"{v:.12f}".rstrip("0").rstrip("."))\n                else:\n                    vals.append(str(v))\n            f.write(",".join(vals) + "\\n")\n\n\n# =============================================================================\n# USER-REQUESTED EPOCH COORDINATE OUTPUT\n# =============================================================================\n\ndef _is_leap_year(year: int) -> bool:\n    return year % 4 == 0 and (year % 100 != 0 or year % 400 == 0)\n\n\ndef _decimal_year_from_date(d: date) -> float:\n    days = 366 if _is_leap_year(d.year) else 365\n    return d.year + ((d.timetuple().tm_yday - 1) / days)\n\n\ndef _date_from_year_doy(year: int, doy: int) -> date:\n    return date(year, 1, 1) + timedelta(days=doy - 1)\n\n\ndef _mid_solution_epoch_decimal(year: str, start_doy: str, end_doy: str) -> Tuple[float, str]:\n    """Use the middle of the processed GLOBK span as the coordinate reference epoch."""\n    y = int(year)\n    start = _date_from_year_doy(y, int(start_doy))\n    end = _date_from_year_doy(y, int(end_doy))\n    mid_dt = datetime.combine(start, datetime.min.time()) + (datetime.combine(end, datetime.min.time()) - datetime.combine(start, datetime.min.time())) / 2\n    mid_date = mid_dt.date()\n    return _decimal_year_from_date(mid_date), mid_date.isoformat()\n\n\ndef parse_user_epoch(text: str) -> Tuple[float, str, str]:\n    """\n    Parse user epoch/date.\n    Accepted examples:\n      2025-01-01, 01.01.2025, 01/01/2025, 2025/01/01, 2025.0\n    Returns decimal_year, label_for_file, display_label.\n    """\n    t = text.strip()\n    if not t:\n        raise ValueError("empty epoch")\n\n    # Decimal epoch such as 2025.0 or 2025.5000\n    if re.fullmatch(r"\\d{4}(?:\\.\\d+)?", t):\n        dec = float(t)\n        label = (f"{dec:.5f}").replace(".", "p")\n        return dec, f"epoch_{label}", f"decimal epoch {dec:.5f}"\n\n    formats = [\n        ("%Y-%m-%d", "ymd"),\n        ("%Y/%m/%d", "ymd"),\n        ("%d.%m.%Y", "dmy"),\n        ("%d/%m/%Y", "dmy"),\n        ("%d-%m-%Y", "dmy"),\n    ]\n    for fmt, _kind in formats:\n        try:\n            d = datetime.strptime(t, fmt).date()\n            dec = _decimal_year_from_date(d)\n            return dec, f"epoch_{d.strftime(\'%Y%m%d\')}", d.isoformat()\n        except ValueError:\n            pass\n\n    raise ValueError("Unsupported epoch format. Use YYYY-MM-DD, DD.MM.YYYY, DD/MM/YYYY, or decimal year like 2025.0")\n\n\ndef parse_apr_velocity_for_station(apr_path: Optional[Path], station: str) -> Tuple[Optional[Tuple[float, float, float]], str, Optional[float]]:\n    """\n    Parse ECEF velocity in m/year from an APR line only when it really looks like velocity.\n\n    Important:\n    In this launcher, local stations added from lfile. often have columns 5-7 set to 10.0.\n    Those 10.0 values are loose a-priori coordinate sigmas/constraints, NOT station velocities.\n    Therefore values that look like 10 m sigmas, lfile-updated local entries, or unrealistically\n    large velocities are deliberately rejected.\n    """\n    if apr_path is None or not apr_path.is_file():\n        return None, "no APR file", None\n\n    wanted = station.upper().replace("_GPS", "")\n    wanted_tokens = {wanted, wanted + "_GPS"}\n    try:\n        with open(apr_path, "r", errors="ignore") as f:\n            for line in f:\n                parts = line.split()\n                if len(parts) < 7:\n                    continue\n                name = parts[0].upper()\n                if name not in wanted_tokens:\n                    continue\n                low = line.lower()\n                try:\n                    v1 = float(parts[4])\n                    v2 = float(parts[5])\n                    v3 = float(parts[6])\n                    epoch0 = None\n                    if len(parts) >= 8:\n                        try:\n                            epoch0 = float(parts[7])\n                        except Exception:\n                            epoch0 = None\n\n                    # Lines added from lfile. in this script use columns 5-7 as sigmas.\n                    if "updated from l" in low or "local cors from rinex" in low:\n                        return None, f"APR line for {name} is from lfile/RINEX; columns 5-7 are sigmas, not velocity", epoch0\n\n                    # 10.0 10.0 10.0 is the loose sigma this script writes for local stations.\n                    if abs(v1 - 10.0) < 1e-9 and abs(v2 - 10.0) < 1e-9 and abs(v3 - 10.0) < 1e-9:\n                        return None, f"APR line for {name} has 10.0 sigmas; no real velocity", epoch0\n\n                    # GNSS station ECEF velocities are normally cm/year, not meters/year.\n                    # Anything above 0.5 m/year is almost certainly a sigma/constraint, not velocity.\n                    if max(abs(v1), abs(v2), abs(v3)) > 0.5:\n                        return None, f"APR values for {name} are too large for velocity; treated as sigmas/constraints", epoch0\n\n                    if abs(v1) < 1e-12 and abs(v2) < 1e-12 and abs(v3) < 1e-12:\n                        return None, f"APR line for {name} has zero velocity/no real velocity", epoch0\n\n                    return (v1, v2, v3), f"APR ECEF velocity from {apr_path.name}", epoch0\n                except Exception:\n                    return None, f"APR line found but velocity unreadable in {apr_path.name}", None\n    except Exception as e:\n        return None, f"APR read error: {e}", None\n\n    return None, f"no velocity line for {wanted}_GPS in {apr_path.name}", None\n\n\ndef _norm_velocity_station_name(value: object) -> str:\n    s = str(value or "").strip().upper()\n    if s.endswith("_GPS"):\n        s = s[:-4]\n    return s[:4]\n\n\ndef _first_float(row: Dict[str, str], names: List[str]) -> Optional[float]:\n    lower = {str(k).strip().lower(): v for k, v in row.items()}\n    for name in names:\n        key = name.lower()\n        if key in lower and str(lower[key]).strip() != "":\n            try:\n                return float(str(lower[key]).strip())\n            except Exception:\n                return None\n    return None\n\n\ndef load_external_velocity_csv(path: Path) -> Dict[str, Dict[str, str]]:\n    """\n    Read external velocity CSV.\n\n    Supported station column names: station, site, site_code\n    Supported ECEF velocity columns in m/year:\n      vx_m_per_yr, vy_m_per_yr, vz_m_per_yr   OR   vx, vy, vz\n    Supported local ENU columns in m/year:\n      ve_m_per_yr, vn_m_per_yr, vu_m_per_yr   OR   east_m_per_yr, north_m_per_yr, up_m_per_yr\n    Supported local ENU columns in mm/year:\n      ve_mm_per_yr, vn_mm_per_yr, vu_mm_per_yr OR east_mm_per_yr, north_mm_per_yr, up_mm_per_yr\n    Optional: epoch, source\n    """\n    out: Dict[str, Dict[str, str]] = {}\n    if not path.is_file():\n        print_warning(f"Velocity CSV not found: {path}")\n        return out\n    try:\n        with open(path, newline="", encoding="utf-8", errors="ignore") as f:\n            reader = csv.DictReader(f)\n            if not reader.fieldnames:\n                print_warning("Velocity CSV has no header row.")\n                return out\n            for row in reader:\n                st = _norm_velocity_station_name(row.get("station") or row.get("site") or row.get("site_code") or row.get("code"))\n                if len(st) == 4:\n                    out[st] = {str(k).strip(): str(v).strip() for k, v in row.items() if k is not None}\n    except Exception as e:\n        print_warning(f"Could not read velocity CSV: {e}")\n    return out\n\n\ndef external_velocity_for_station(\n    velocities: Dict[str, Dict[str, str]],\n    station4: str,\n    x0: float,\n    y0: float,\n    z0: float,\n) -> Tuple[Optional[Tuple[float, float, float]], str, Optional[float]]:\n    """Return ECEF velocity in m/year from external CSV, supporting ECEF or local ENU input."""\n    st = station4.upper().replace("_GPS", "")[:4]\n    rec = velocities.get(st)\n    if not rec:\n        return None, "no external velocity", None\n\n    epoch = _first_float(rec, ["epoch", "velocity_epoch", "reference_epoch"])\n    source = str(rec.get("source") or rec.get("velocity_source") or "external velocity CSV")\n\n    vx = _first_float(rec, ["vx_m_per_yr", "vx_m_yr", "vx"])\n    vy = _first_float(rec, ["vy_m_per_yr", "vy_m_yr", "vy"])\n    vz = _first_float(rec, ["vz_m_per_yr", "vz_m_yr", "vz"])\n    if vx is not None and vy is not None and vz is not None:\n        return (vx, vy, vz), source + " (ECEF m/year)", epoch\n\n    ve = _first_float(rec, ["ve_m_per_yr", "ve_m_yr", "east_m_per_yr", "east_m_yr", "e_m_per_yr"])\n    vn = _first_float(rec, ["vn_m_per_yr", "vn_m_yr", "north_m_per_yr", "north_m_yr", "n_m_per_yr"])\n    vu = _first_float(rec, ["vu_m_per_yr", "vu_m_yr", "up_m_per_yr", "up_m_yr", "u_m_per_yr"])\n\n    if ve is None or vn is None or vu is None:\n        ve_mm = _first_float(rec, ["ve_mm_per_yr", "ve_mm_yr", "east_mm_per_yr", "east_mm_yr", "e_mm_per_yr"])\n        vn_mm = _first_float(rec, ["vn_mm_per_yr", "vn_mm_yr", "north_mm_per_yr", "north_mm_yr", "n_mm_per_yr"])\n        vu_mm = _first_float(rec, ["vu_mm_per_yr", "vu_mm_yr", "up_mm_per_yr", "up_mm_yr", "u_mm_per_yr"])\n        if ve_mm is not None and vn_mm is not None and vu_mm is not None:\n            ve, vn, vu = ve_mm / 1000.0, vn_mm / 1000.0, vu_mm / 1000.0\n\n    if ve is not None and vn is not None and vu is not None:\n        import math\n        lat, lon, _h = ecef_to_geodetic_wgs84(x0, y0, z0)\n        lat_r = math.radians(lat)\n        lon_r = math.radians(lon)\n        sin_lat, cos_lat = math.sin(lat_r), math.cos(lat_r)\n        sin_lon, cos_lon = math.sin(lon_r), math.cos(lon_r)\n        # ENU unit vectors in ECEF.\n        ex, ey, ez = -sin_lon, cos_lon, 0.0\n        nx, ny, nz = -sin_lat * cos_lon, -sin_lat * sin_lon, cos_lat\n        ux, uy, uz = cos_lat * cos_lon, cos_lat * sin_lon, sin_lat\n        vx_ecef = ve * ex + vn * nx + vu * ux\n        vy_ecef = ve * ey + vn * ny + vu * uy\n        vz_ecef = ve * ez + vn * nz + vu * uz\n        return (vx_ecef, vy_ecef, vz_ecef), source + " (ENU converted to ECEF)", epoch\n\n    return None, "external velocity row found but required velocity columns missing", epoch\n\n\n\n# =============================================================================\n# INDIA PLATE MODEL VELOCITY SUPPORT\n# =============================================================================\n# Jade et al. (2017) India/ITRF2008 angular velocity components from the shared\n# material. Units in the paper are degrees/Myr; internally converted to rad/year.\n# This is a rigid-plate model velocity, not an official station-wise CORS velocity.\nINDIA_PLATE_JADE2017_W_DEG_PER_MYR = (0.335613, 0.070437, 0.434185)\nINDIA_PLATE_JADE2017_SOURCE = (\n    "Jade_et_al_2017_India_ITRF2008_plate_model_"\n    "Wx0.335613_Wy0.070437_Wz0.434185_deg_per_Myr; "\n    "plate_model_not_station_specific"\n)\n\n\ndef india_plate_model_velocity_ecef(x: float, y: float, z: float) -> Tuple[float, float, float]:\n    """Return India rigid-plate ECEF velocity in m/year using Jade et al. 2017."""\n    import math\n    wx_d, wy_d, wz_d = INDIA_PLATE_JADE2017_W_DEG_PER_MYR\n    scale = math.pi / 180.0 / 1_000_000.0\n    wx, wy, wz = wx_d * scale, wy_d * scale, wz_d * scale\n    vx = wy * z - wz * y\n    vy = wz * x - wx * z\n    vz = wx * y - wy * x\n    return vx, vy, vz\n\n\ndef ecef_velocity_to_enu_mm_per_year(x: float, y: float, z: float, vx: float, vy: float, vz: float) -> Tuple[float, float, float]:\n    """Convert ECEF velocity m/year to local ENU velocity mm/year."""\n    import math\n    lat, lon, _h = ecef_to_geodetic_wgs84(x, y, z)\n    lat_r = math.radians(lat)\n    lon_r = math.radians(lon)\n    sin_lat, cos_lat = math.sin(lat_r), math.cos(lat_r)\n    sin_lon, cos_lon = math.sin(lon_r), math.cos(lon_r)\n    ve = -sin_lon * vx + cos_lon * vy\n    vn = -sin_lat * cos_lon * vx - sin_lat * sin_lon * vy + cos_lat * vz\n    vu = cos_lat * cos_lon * vx + cos_lat * sin_lon * vy + sin_lat * vz\n    return ve * 1000.0, vn * 1000.0, vu * 1000.0\n\n\ndef write_india_plate_velocity_csv(coord_rows: List[Dict[str, object]], out_dir: Path) -> Path:\n    """Write station-wise approximate India plate velocities computed from current XYZ."""\n    out_dir.mkdir(parents=True, exist_ok=True)\n    path = out_dir / "india_plate_velocity_jade2017_model.csv"\n    fields = [\n        "station",\n        "vx_m_per_yr", "vy_m_per_yr", "vz_m_per_yr",\n        "ve_mm_per_yr", "vn_mm_per_yr", "vu_mm_per_yr",\n        "epoch", "source",\n    ]\n    try:\n        with open(path, "w", newline="", encoding="utf-8") as f:\n            writer = csv.DictWriter(f, fieldnames=fields)\n            writer.writeheader()\n            for r in coord_rows:\n                st = str(r.get("station", "")).upper()\n                try:\n                    x = float(r.get("x_m")); y = float(r.get("y_m")); z = float(r.get("z_m"))\n                except Exception:\n                    continue\n                vx, vy, vz = india_plate_model_velocity_ecef(x, y, z)\n                ve, vn, vu = ecef_velocity_to_enu_mm_per_year(x, y, z, vx, vy, vz)\n                writer.writerow({\n                    "station": st,\n                    "vx_m_per_yr": f"{vx:.9f}",\n                    "vy_m_per_yr": f"{vy:.9f}",\n                    "vz_m_per_yr": f"{vz:.9f}",\n                    "ve_mm_per_yr": f"{ve:.3f}",\n                    "vn_mm_per_yr": f"{vn:.3f}",\n                    "vu_mm_per_yr": f"{vu:.3f}",\n                    "epoch": "2008.0",\n                    "source": INDIA_PLATE_JADE2017_SOURCE,\n                })\n    except Exception as e:\n        print_warning(f"Could not write India plate velocity CSV: {e}")\n    return path\n\n\ndef plate_model_velocity_for_station(station4: str, x0: float, y0: float, z0: float) -> Tuple[Tuple[float, float, float], str, Optional[float]]:\n    """Return approximate India plate model velocity for a station XYZ."""\n    vx, vy, vz = india_plate_model_velocity_ecef(x0, y0, z0)\n    return (vx, vy, vz), INDIA_PLATE_JADE2017_SOURCE, 2008.0\n\n\n# =============================================================================\n# LONG-TERM GLOBK POS TIME-SERIES VELOCITY ESTIMATION\n# =============================================================================\n\ndef _decimal_year_from_yyyymmdd(token: str) -> Optional[float]:\n    token = token.strip()\n    if not re.fullmatch(r"\\d{8}", token):\n        return None\n    try:\n        d = datetime.strptime(token, "%Y%m%d").date()\n        return _decimal_year_from_date(d)\n    except Exception:\n        return None\n\n\ndef _looks_like_ecef_xyz(x: float, y: float, z: float) -> bool:\n    import math\n    r = math.sqrt(x * x + y * y + z * z)\n    return 5_500_000.0 <= r <= 7_000_000.0 and max(abs(x), abs(y), abs(z)) < 7_000_000.0\n\n\ndef _median(vals: List[float]) -> float:\n    vals = sorted(vals)\n    n = len(vals)\n    if n == 0:\n        return 0.0\n    mid = n // 2\n    if n % 2:\n        return vals[mid]\n    return 0.5 * (vals[mid - 1] + vals[mid])\n\n\ndef _linear_fit_slope(times: List[float], values: List[float]) -> Tuple[float, float]:\n    """Return slope and intercept for value = intercept + slope * (time - mean_time)."""\n    if len(times) < 2:\n        return 0.0, values[0] if values else 0.0\n    mt = sum(times) / len(times)\n    mv = sum(values) / len(values)\n    den = sum((t - mt) ** 2 for t in times)\n    if den <= 0:\n        return 0.0, mv\n    slope = sum((t - mt) * (v - mv) for t, v in zip(times, values)) / den\n    intercept = mv\n    return slope, intercept\n\n\ndef _parse_pos_xyz_timeseries(pos_path: Path) -> List[Tuple[float, float, float, float]]:\n    """\n    Parse GAMIT/GLOBK/PBO-style .pos files and return decimal_year, X, Y, Z.\n\n    The parser intentionally searches for a plausible ECEF XYZ triplet in each data line,\n    because small differences exist between pos-file variants. It accepts lines with either\n    YYYYMMDD date tokens or decimal-year tokens.\n    """\n    rows: List[Tuple[float, float, float, float]] = []\n    try:\n        with open(pos_path, "r", errors="ignore") as f:\n            for line in f:\n                raw = line.strip()\n                if not raw or raw.startswith(("#", "%", "*", "+")):\n                    continue\n                parts = raw.split()\n                if len(parts) < 6:\n                    continue\n\n                dec_year: Optional[float] = None\n                # Common PBO/GLOBK pos line: YYYYMMDD HHMMSS ... X Y Z ...\n                for tok in parts[:4]:\n                    dec_year = _decimal_year_from_yyyymmdd(tok)\n                    if dec_year is not None:\n                        break\n\n                # Some exported files may have decimal year as one of the first tokens.\n                if dec_year is None:\n                    for tok in parts[:4]:\n                        try:\n                            tv = float(tok)\n                        except Exception:\n                            continue\n                        if 1980.0 <= tv <= 2100.0:\n                            dec_year = tv\n                            break\n\n                if dec_year is None:\n                    continue\n\n                nums: List[Optional[float]] = []\n                for tok in parts:\n                    try:\n                        nums.append(float(tok))\n                    except Exception:\n                        nums.append(None)\n\n                xyz: Optional[Tuple[float, float, float]] = None\n                # In normal .pos files the first plausible ECEF triplet appears near columns 3-6.\n                for i in range(1, min(len(nums) - 2, 16)):\n                    if nums[i] is None or nums[i + 1] is None or nums[i + 2] is None:\n                        continue\n                    x, y, z = float(nums[i]), float(nums[i + 1]), float(nums[i + 2])\n                    if _looks_like_ecef_xyz(x, y, z):\n                        xyz = (x, y, z)\n                        break\n                if xyz is not None:\n                    rows.append((dec_year, xyz[0], xyz[1], xyz[2]))\n    except Exception:\n        return []\n    return rows\n\n\ndef _station_from_pos_filename(pos_path: Path) -> str:\n    stem = pos_path.name.upper()\n    return stem.split(".")[0].replace("_GPS", "")[:4]\n\n\ndef _fit_velocity_from_xyz_timeseries(samples: List[Tuple[float, float, float, float]]) -> Optional[Dict[str, float]]:\n    """Fit Vx,Vy,Vz in m/year from XYZ time series with a light outlier rejection."""\n    # Deduplicate by date/epoch, keeping the last record.\n    by_epoch: Dict[float, Tuple[float, float, float]] = {}\n    for t, x, y, z in samples:\n        by_epoch[round(t, 8)] = (x, y, z)\n    items = sorted((t, xyz[0], xyz[1], xyz[2]) for t, xyz in by_epoch.items())\n    if len(items) < 30:\n        return None\n\n    def fit(items2: List[Tuple[float, float, float, float]]) -> Tuple[float, float, float, float, float, int]:\n        ts = [a[0] for a in items2]\n        xs = [a[1] for a in items2]\n        ys = [a[2] for a in items2]\n        zs = [a[3] for a in items2]\n        vx, x0 = _linear_fit_slope(ts, xs)\n        vy, y0 = _linear_fit_slope(ts, ys)\n        vz, z0 = _linear_fit_slope(ts, zs)\n        mt = sum(ts) / len(ts)\n        res = []\n        for t, x, y, z in items2:\n            px = x0 + vx * (t - mt)\n            py = y0 + vy * (t - mt)\n            pz = z0 + vz * (t - mt)\n            res.append(((x - px) ** 2 + (y - py) ** 2 + (z - pz) ** 2) ** 0.5)\n        rms = (sum(r * r for r in res) / len(res)) ** 0.5 if res else 0.0\n        return vx, vy, vz, rms, mt, len(items2)\n\n    vx, vy, vz, rms, mt, n = fit(items)\n\n    # Simple robust pass: remove gross outliers only, not normal seasonal scatter.\n    if len(items) >= 60:\n        ts = [a[0] for a in items]\n        xs = [a[1] for a in items]\n        ys = [a[2] for a in items]\n        zs = [a[3] for a in items]\n        sx, x0 = _linear_fit_slope(ts, xs)\n        sy, y0 = _linear_fit_slope(ts, ys)\n        sz, z0 = _linear_fit_slope(ts, zs)\n        mt0 = sum(ts) / len(ts)\n        residuals = []\n        for t, x, y, z in items:\n            rr = ((x - (x0 + sx * (t - mt0))) ** 2 + (y - (y0 + sy * (t - mt0))) ** 2 + (z - (z0 + sz * (t - mt0))) ** 2) ** 0.5\n            residuals.append(rr)\n        med = _median(residuals)\n        mad = _median([abs(r - med) for r in residuals])\n        cutoff = max(0.05, med + 6.0 * max(mad, 0.001))  # meters\n        kept = [row for row, rr in zip(items, residuals) if rr <= cutoff]\n        if len(kept) >= 30 and len(kept) >= 0.7 * len(items):\n            vx, vy, vz, rms, mt, n = fit(kept)\n            items = kept\n\n    first = min(a[0] for a in items)\n    last = max(a[0] for a in items)\n    span = last - first\n    return {\n        "vx": vx,\n        "vy": vy,\n        "vz": vz,\n        "rms_m": rms,\n        "n_epochs": float(n),\n        "first_epoch": first,\n        "last_epoch": last,\n        "span_years": span,\n    }\n\n\ndef estimate_longterm_velocity_from_pos(\n    coord_rows: List[Dict[str, object]],\n    project_dir: Path,\n    out_dir: Path,\n    min_span_years: float = 1.0,\n) -> Tuple[Path, Dict[str, Dict[str, str]]]:\n    """\n    Estimate station velocities from long-term GLOBK .pos time-series files.\n\n    This is intended for projects with more than one year of processed daily/weekly positions.\n    The output is a velocity CSV that can be used immediately by the epoch-propagation step.\n    """\n    out_dir.mkdir(parents=True, exist_ok=True)\n    out_csv = out_dir / "station_velocity_from_longterm_pos.csv"\n    out_notes = out_dir / "station_velocity_from_longterm_pos_notes.txt"\n    wanted = {_norm_velocity_station_name(r.get("station")) for r in coord_rows}\n    wanted = {s for s in wanted if len(s) == 4}\n\n    pos_files = sorted((project_dir / "gsoln").rglob("*.pos"))\n    by_station: Dict[str, List[Tuple[float, float, float, float]]] = {s: [] for s in wanted}\n    used_files: Dict[str, List[str]] = {s: [] for s in wanted}\n\n    for pf in pos_files:\n        st = _station_from_pos_filename(pf)\n        if st not in wanted:\n            continue\n        samples = _parse_pos_xyz_timeseries(pf)\n        if samples:\n            by_station.setdefault(st, []).extend(samples)\n            used_files.setdefault(st, []).append(str(pf))\n\n    fields = [\n        "station", "vx_m_per_yr", "vy_m_per_yr", "vz_m_per_yr",\n        "ve_mm_per_yr", "vn_mm_per_yr", "vu_mm_per_yr",\n        "epoch", "source", "n_epochs", "first_epoch", "last_epoch", "span_years", "rms_m", "usable", "note",\n    ]\n    usable_records: Dict[str, Dict[str, str]] = {}\n    lines: List[str] = []\n    lines.append("LONG-TERM GLOBK/POS VELOCITY ESTIMATION")\n    lines.append(f"Project: {project_dir}")\n    lines.append(f"POS files searched under: {project_dir / \'gsoln\'}")\n    lines.append(f"Minimum accepted span: {min_span_years:.2f} year(s)")\n    lines.append("Method: linear trend of ECEF X/Y/Z from .pos time series; light gross-outlier rejection.")\n    lines.append("Scientific note: use at least 1 year, preferably 2-3+ years, for station velocity.")\n    lines.append("")\n\n    with open(out_csv, "w", newline="", encoding="utf-8") as f:\n        writer = csv.DictWriter(f, fieldnames=fields)\n        writer.writeheader()\n        for r in coord_rows:\n            st_full = str(r.get("station", "")).upper()\n            st = _norm_velocity_station_name(st_full)\n            fit = _fit_velocity_from_xyz_timeseries(by_station.get(st, []))\n            row: Dict[str, str] = {\n                "station": st_full,\n                "vx_m_per_yr": "", "vy_m_per_yr": "", "vz_m_per_yr": "",\n                "ve_mm_per_yr": "", "vn_mm_per_yr": "", "vu_mm_per_yr": "",\n                "epoch": "", "source": "Measured_from_long_term_GLOBK_POS_time_series",\n                "n_epochs": "0", "first_epoch": "", "last_epoch": "", "span_years": "", "rms_m": "", "usable": "NO", "note": "No usable POS time series found",\n            }\n            if fit is not None:\n                try:\n                    x = float(r.get("x_m")); y = float(r.get("y_m")); z = float(r.get("z_m"))\n                    vx, vy, vz = float(fit["vx"]), float(fit["vy"]), float(fit["vz"])\n                    ve, vn, vu = ecef_velocity_to_enu_mm_per_year(x, y, z, vx, vy, vz)\n                    span = float(fit["span_years"])\n                    usable = span >= min_span_years\n                    row.update({\n                        "vx_m_per_yr": f"{vx:.9f}",\n                        "vy_m_per_yr": f"{vy:.9f}",\n                        "vz_m_per_yr": f"{vz:.9f}",\n                        "ve_mm_per_yr": f"{ve:.3f}",\n                        "vn_mm_per_yr": f"{vn:.3f}",\n                        "vu_mm_per_yr": f"{vu:.3f}",\n                        "epoch": f"{((float(fit[\'first_epoch\']) + float(fit[\'last_epoch\'])) / 2.0):.6f}",\n                        "n_epochs": str(int(float(fit["n_epochs"]))),\n                        "first_epoch": f"{float(fit[\'first_epoch\']):.6f}",\n                        "last_epoch": f"{float(fit[\'last_epoch\']):.6f}",\n                        "span_years": f"{span:.3f}",\n                        "rms_m": f"{float(fit[\'rms_m\']):.4f}",\n                        "usable": "YES" if usable else "NO",\n                        "note": "Usable measured velocity" if usable else "Time span is less than minimum; not used automatically",\n                    })\n                    if usable:\n                        usable_records[st] = dict(row)\n                except Exception as e:\n                    row["note"] = f"Fit/read error: {e}"\n            writer.writerow(row)\n            lines.append(\n                f"{st_full:10s} usable={row[\'usable\']:3s} n={row[\'n_epochs\']:>5s} "\n                f"span={row[\'span_years\'] or \'-\':>7s} yr  "\n                f"Ve={row[\'ve_mm_per_yr\'] or \'-\':>9s} Vn={row[\'vn_mm_per_yr\'] or \'-\':>9s} Vu={row[\'vu_mm_per_yr\'] or \'-\':>9s} mm/yr  {row[\'note\']}"\n            )\n            if used_files.get(st):\n                lines.append(f"    POS files: {len(used_files[st])} file(s), e.g. {used_files[st][0]}")\n\n    out_notes.write_text("\\n".join(lines) + "\\n", encoding="utf-8")\n    print_success(f"Saved long-term POS velocity CSV: {out_csv}")\n    print_success(f"Saved long-term POS velocity notes: {out_notes}")\n    if usable_records:\n        print_success("Usable measured velocities from long-term POS: " + " ".join(sorted(usable_records)))\n    else:\n        print_warning("No station had >= 1 year usable POS time series. Use external CSV or plate model for now.")\n    return out_csv, usable_records\n\ndef write_velocity_template(coord_rows: List[Dict[str, object]], out_dir: Path) -> Path:\n    """Create a CSV template the user can fill with real station velocities."""\n    out_dir.mkdir(parents=True, exist_ok=True)\n    path = out_dir / "station_velocity_template.csv"\n    fields = [\n        "station",\n        "vx_m_per_yr", "vy_m_per_yr", "vz_m_per_yr",\n        "ve_mm_per_yr", "vn_mm_per_yr", "vu_mm_per_yr",\n        "epoch", "source",\n    ]\n    try:\n        with open(path, "w", newline="", encoding="utf-8") as f:\n            writer = csv.DictWriter(f, fieldnames=fields)\n            writer.writeheader()\n            for r in coord_rows:\n                st = str(r.get("station", "")).upper()\n                writer.writerow({\n                    "station": st,\n                    "vx_m_per_yr": "",\n                    "vy_m_per_yr": "",\n                    "vz_m_per_yr": "",\n                    "ve_mm_per_yr": "",\n                    "vn_mm_per_yr": "",\n                    "vu_mm_per_yr": "",\n                    "epoch": "",\n                    "source": "",\n                })\n    except Exception as e:\n        print_warning(f"Could not write velocity template: {e}")\n    return path\n\n\ndef ecef_to_geodetic_wgs84(x: float, y: float, z: float) -> Tuple[float, float, float]:\n    """Convert ECEF XYZ in meters to WGS84 geodetic latitude, longitude, height."""\n    import math\n    a = 6378137.0\n    f = 1.0 / 298.257223563\n    e2 = f * (2.0 - f)\n    b = a * (1.0 - f)\n    ep2 = (a * a - b * b) / (b * b)\n\n    p = math.hypot(x, y)\n    if p == 0:\n        lon = 0.0\n    else:\n        lon = math.atan2(y, x)\n\n    theta = math.atan2(z * a, p * b)\n    sin_t = math.sin(theta)\n    cos_t = math.cos(theta)\n    lat = math.atan2(z + ep2 * b * sin_t**3, p - e2 * a * cos_t**3)\n\n    for _ in range(5):\n        sin_lat = math.sin(lat)\n        n = a / math.sqrt(1.0 - e2 * sin_lat * sin_lat)\n        h = p / math.cos(lat) - n\n        lat_new = math.atan2(z, p * (1.0 - e2 * n / (n + h)))\n        if abs(lat_new - lat) < 1e-14:\n            lat = lat_new\n            break\n        lat = lat_new\n\n    sin_lat = math.sin(lat)\n    n = a / math.sqrt(1.0 - e2 * sin_lat * sin_lat)\n    h = p / math.cos(lat) - n\n    return math.degrees(lat), math.degrees(lon), h\n\n\ndef write_epoch_coordinates_csv(rows: List[Dict[str, object]], out_csv: Path) -> None:\n    headers = [\n        "station", "target_epoch", "target_label", "reference_epoch", "reference_label", "delta_years",\n        "x_ref_m", "y_ref_m", "z_ref_m",\n        "vx_m_per_yr", "vy_m_per_yr", "vz_m_per_yr", "velocity_source", "apr_velocity_epoch",\n        "x_epoch_m", "y_epoch_m", "z_epoch_m", "lat_epoch_deg", "lon_epoch_deg", "height_epoch_m",\n        "note",\n    ]\n    out_csv.parent.mkdir(parents=True, exist_ok=True)\n    with open(out_csv, "w", encoding="utf-8") as f:\n        f.write(",".join(headers) + "\\n")\n        for row in rows:\n            vals = []\n            for h in headers:\n                v = row.get(h)\n                if v is None:\n                    vals.append("")\n                elif isinstance(v, float):\n                    vals.append(f"{v:.12f}".rstrip("0").rstrip("."))\n                else:\n                    vals.append(str(v).replace(",", ";"))\n            f.write(",".join(vals) + "\\n")\n\n\ndef print_epoch_coordinate_table(rows: List[Dict[str, object]], target_display: str) -> None:\n    print_header(f"LOCAL COORDINATES AT REQUESTED EPOCH: {target_display}")\n    if not rows:\n        print_warning("No epoch coordinates could be created.")\n        return\n\n    print("Station       X_epoch(m)        Y_epoch(m)        Z_epoch(m)        Lat(deg)        Lon(deg)        H(m)        Velocity")\n    print("-" * 126)\n    for r in rows:\n        src = str(r.get("velocity_source", ""))\n        if "Jade_et_al_2017" in src or "plate_model" in src:\n            vel_note = "PLATE-MODEL"\n        elif "CSV" in src or "external" in src.lower():\n            vel_note = "CSV"\n        elif src.startswith("APR"):\n            vel_note = "APR"\n        else:\n            vel_note = "NONE"\n        print(\n            f"{str(r.get(\'station\',\'\')):10s} "\n            f"{float(r.get(\'x_epoch_m\', 0.0)):16.4f} "\n            f"{float(r.get(\'y_epoch_m\', 0.0)):16.4f} "\n            f"{float(r.get(\'z_epoch_m\', 0.0)):16.4f} "\n            f"{float(r.get(\'lat_epoch_deg\', 0.0)):14.10f} "\n            f"{float(r.get(\'lon_epoch_deg\', 0.0)):14.10f} "\n            f"{float(r.get(\'height_epoch_m\', 0.0)):11.4f} "\n            f"{vel_note}"\n        )\n\n\ndef print_velocity_used_table(rows: List[Dict[str, object]], source_title: str) -> None:\n    """Print the actual Vx, Vy, Vz values used for the requested-epoch output."""\n    print_header(f"VELOCITY VALUES USED: {source_title}")\n    if not rows:\n        print_warning("No velocity table could be printed because no epoch rows were created.")\n        return\n    print("Station       Vx(m/yr)       Vy(m/yr)       Vz(m/yr)       Source")\n    print("-" * 96)\n    for r in rows:\n        station = str(r.get("station", ""))[:10]\n        vx = float(r.get("vx_m_per_yr", 0.0))\n        vy = float(r.get("vy_m_per_yr", 0.0))\n        vz = float(r.get("vz_m_per_yr", 0.0))\n        src = str(r.get("velocity_source", "NONE"))\n        print(f"{station:10s} {vx:14.6f} {vy:14.6f} {vz:14.6f}   {src}")\n\n\ndef write_velocity_used_csv(rows: List[Dict[str, object]], out_csv: Path) -> None:\n    fields = [\n        "station", "target_epoch", "target_label", "reference_epoch", "reference_label", "delta_years",\n        "x_ref_m", "y_ref_m", "z_ref_m", "vx_m_per_yr", "vy_m_per_yr", "vz_m_per_yr",\n        "velocity_source", "apr_velocity_epoch", "note",\n    ]\n    with open(out_csv, "w", newline="", encoding="utf-8") as f:\n        writer = csv.DictWriter(f, fieldnames=fields)\n        writer.writeheader()\n        for row in rows:\n            writer.writerow({k: row.get(k, "") for k in fields})\n\n\ndef _epoch_source_suffix(choice: str) -> Tuple[str, str]:\n    if choice == "1":\n        return "india_plate_model", "India plate model"\n    if choice == "2":\n        return "external_velocity_csv", "External station velocity CSV"\n    if choice == "3":\n        return "longterm_pos_velocity", "Measured long-term POS velocity"\n    return "apr_or_no_velocity", "APR velocity if available, otherwise no velocity"\n\n\ndef create_epoch_coordinate_output(\n    coord_rows: List[Dict[str, object]],\n    apr_path: Optional[Path],\n    year: str,\n    start_doy: str,\n    end_doy: str,\n    out_dir: Path,\n) -> None:\n    """Create requested-epoch coordinates, allowing the user to test several velocity sources."""\n    if not coord_rows:\n        print_warning("No final coordinates available for epoch propagation.")\n        return\n\n    print_header("OPTIONAL COORDINATES AT USER-SPECIFIED EPOCH")\n    print_info("Accepted date formats: 2005-01-01, 01.01.2005, 01/01/2005, or decimal epoch 2005.0")\n    print_info("This section can be repeated with different velocity-source options until you finish it.")\n\n    default_epoch = "2005-01-01"\n\n    def ask_target_epoch() -> Tuple[float, str, str]:\n        while True:\n            text = ask_input("Target epoch/date for coordinates", default_epoch)\n            try:\n                return parse_user_epoch(text)\n            except ValueError as e:\n                print_error(str(e))\n\n    target_epoch, target_label, target_display = ask_target_epoch()\n    ref_epoch, ref_label = _mid_solution_epoch_decimal(year, start_doy, end_doy)\n\n    template_path = write_velocity_template(coord_rows, out_dir)\n    india_plate_csv = write_india_plate_velocity_csv(coord_rows, out_dir)\n    print_info(f"Reference coordinate epoch used: {ref_epoch:.6f} ({ref_label}, middle of selected GLOBK span)")\n    print_info(f"Blank velocity CSV template    : {template_path}")\n    print_info(f"India plate model CSV          : {india_plate_csv}")\n    if apr_path:\n        print_info(f"APR file checked for existing station velocity: {apr_path}")\n\n    run_count = 0\n    while True:\n        dt = target_epoch - ref_epoch\n        print_header("VELOCITY SOURCE FOR EPOCH PROPAGATION")\n        print_info(f"Current target epoch/date : {target_epoch:.6f} ({target_display})")\n        print_info(f"Reference epoch/date      : {ref_epoch:.6f} ({ref_label})")\n        print_info(f"Delta years               : {dt:.6f}")\n        print("1. Use India plate model from Jade et al. 2017")\n        print("2. Use external station velocity CSV")\n        print("3. Estimate measured station velocity from long-term GLOBK/POS time series in this project")\n        print("4. Use only APR velocity if present, otherwise no propagation")\n        print("5. Change target epoch/date")\n        print("6. Finish this epoch-coordinate section")\n\n        default_choice = "1" if run_count == 0 else "6"\n        while True:\n            choice = ask_input("Choose velocity-source/result option", default_choice).strip()\n            if choice in ("1", "2", "3", "4", "5", "6"):\n                break\n            print("Please enter 1, 2, 3, 4, 5, or 6.")\n\n        if choice == "5":\n            target_epoch, target_label, target_display = ask_target_epoch()\n            continue\n        if choice == "6":\n            print_success("Finished requested-epoch coordinate section.")\n            break\n\n        source_suffix, source_title = _epoch_source_suffix(choice)\n        velocity_csv: Optional[Path] = None\n        longterm_velocity_csv: Optional[Path] = None\n        external_velocities: Dict[str, Dict[str, str]] = {}\n        longterm_velocities: Dict[str, Dict[str, str]] = {}\n        use_plate_model = False\n\n        if choice == "1":\n            use_plate_model = True\n            print_info("Using India plate-model velocity for this output.")\n        elif choice == "2":\n            while True:\n                ptxt = ask_input("Velocity CSV path", str(template_path))\n                velocity_csv = normalize_path(ptxt)\n                external_velocities = load_external_velocity_csv(velocity_csv)\n                if external_velocities:\n                    print_success(f"Loaded velocities for {len(external_velocities)} station(s) from {velocity_csv}")\n                    break\n                print_warning("No usable velocity records loaded from this CSV.")\n                if not ask_yes_no("Try another velocity CSV path?", "yes"):\n                    external_velocities = {}\n                    velocity_csv = None\n                    break\n        elif choice == "3":\n            project_dir_for_pos = out_dir.parent.parent  # project/gsoln/final_outputs -> project\n            print_info("Estimating velocity from GLOBK .pos time-series files already created under project/gsoln/.")\n            print_info("For reliable measured velocity, use long-term data; 2-3+ years is preferred.")\n            longterm_velocity_csv, longterm_velocities = estimate_longterm_velocity_from_pos(\n                coord_rows, project_dir_for_pos, out_dir, min_span_years=1.0\n            )\n            if not longterm_velocities:\n                print_warning("No usable long-term measured velocity was found for this option.")\n        else:\n            print_info("Plate model and external CSV are not used for this output.")\n\n        epoch_rows: List[Dict[str, object]] = []\n        no_real_velocity_stations: List[str] = []\n        plate_model_stations: List[str] = []\n        external_velocity_stations: List[str] = []\n        longterm_velocity_stations: List[str] = []\n        apr_velocity_stations: List[str] = []\n\n        for r in coord_rows:\n            station_full = str(r.get("station", "")).upper()\n            station4 = station_full.replace("_GPS", "")[:4]\n            try:\n                x0 = float(r.get("x_m"))\n                y0 = float(r.get("y_m"))\n                z0 = float(r.get("z_m"))\n            except Exception:\n                print_warning(f"Skipping {station_full}: missing XYZ in combined .org")\n                continue\n\n            vel, source, apr_vel_epoch = (None, "", None)\n            if external_velocities:\n                vel, source, apr_vel_epoch = external_velocity_for_station(external_velocities, station4, x0, y0, z0)\n                if vel is not None:\n                    external_velocity_stations.append(station4)\n            if vel is None and longterm_velocities:\n                vel, source, apr_vel_epoch = external_velocity_for_station(longterm_velocities, station4, x0, y0, z0)\n                if vel is not None:\n                    longterm_velocity_stations.append(station4)\n            if vel is None and use_plate_model:\n                vel, source, apr_vel_epoch = plate_model_velocity_for_station(station4, x0, y0, z0)\n                plate_model_stations.append(station4)\n            if vel is None:\n                vel, source, apr_vel_epoch = parse_apr_velocity_for_station(apr_path, station4)\n                if vel is not None:\n                    apr_velocity_stations.append(station4)\n\n            if vel is None:\n                vx = vy = vz = 0.0\n                source = "NONE"\n                note = "No velocity available; output equals reference coordinate"\n                no_real_velocity_stations.append(station4)\n            else:\n                vx, vy, vz = vel\n                if abs(vx) < 1e-12 and abs(vy) < 1e-12 and abs(vz) < 1e-12:\n                    note = "Zero velocity used; coordinate unchanged by epoch propagation"\n                    no_real_velocity_stations.append(station4)\n                elif "plate_model" in source:\n                    note = "Propagated using India plate-model velocity"\n                elif external_velocities:\n                    note = "Propagated using external station velocity CSV"\n                elif longterm_velocities:\n                    note = "Propagated using measured velocity estimated from long-term GLOBK/POS time series"\n                else:\n                    note = "Propagated using existing APR station velocity"\n\n            x1 = x0 + vx * dt\n            y1 = y0 + vy * dt\n            z1 = z0 + vz * dt\n            lat, lon, h = ecef_to_geodetic_wgs84(x1, y1, z1)\n\n            epoch_rows.append({\n                "station": station_full,\n                "target_epoch": target_epoch,\n                "target_label": target_display,\n                "reference_epoch": ref_epoch,\n                "reference_label": ref_label,\n                "delta_years": dt,\n                "x_ref_m": x0,\n                "y_ref_m": y0,\n                "z_ref_m": z0,\n                "vx_m_per_yr": vx,\n                "vy_m_per_yr": vy,\n                "vz_m_per_yr": vz,\n                "velocity_source": source,\n                "apr_velocity_epoch": apr_vel_epoch,\n                "x_epoch_m": x1,\n                "y_epoch_m": y1,\n                "z_epoch_m": z1,\n                "lat_epoch_deg": lat,\n                "lon_epoch_deg": lon,\n                "height_epoch_m": h,\n                "note": note,\n            })\n\n        display_title = f"{target_display} / {source_title}"\n        print_epoch_coordinate_table(epoch_rows, display_title)\n        print_velocity_used_table(epoch_rows, source_title)\n\n        out_csv = out_dir / f"local_coordinates_{target_label}_{source_suffix}.csv"\n        out_txt = out_dir / f"local_coordinates_{target_label}_{source_suffix}_notes.txt"\n        velocity_used_csv = out_dir / f"velocity_values_used_{target_label}_{source_suffix}.csv"\n        write_epoch_coordinates_csv(epoch_rows, out_csv)\n        write_velocity_used_csv(epoch_rows, velocity_used_csv)\n        out_txt.write_text(\n            "LOCAL COORDINATES AT USER-SPECIFIED EPOCH\\n"\n            f"Velocity option          : {source_title}\\n"\n            f"Target epoch/date       : {target_display}\\n"\n            f"Target decimal epoch    : {target_epoch:.8f}\\n"\n            f"Reference decimal epoch : {ref_epoch:.8f}\\n"\n            f"Reference date          : {ref_label}\\n"\n            f"Delta years             : {dt:.8f}\\n"\n            f"APR checked             : {apr_path if apr_path else \'Not found\'}\\n"\n            f"External velocity CSV   : {velocity_csv if velocity_csv else \'Not used\'}\\n"\n            f"Long-term POS velocity  : {longterm_velocity_csv if longterm_velocity_csv else \'Not used\'}\\n"\n            f"Blank velocity template : {template_path}\\n"\n            f"India plate CSV         : {india_plate_csv}\\n"\n            "Method                  : XYZ_epoch = XYZ_reference + Vxyz * delta_years\\n"\n            "Measured velocity note  : Long-term POS velocity is computed by linear trend of GLOBK .pos XYZ time series.\\n"\n            "                         Use at least 1 year of data; 2-3+ years is preferred.\\n"\n            "Scientific note         : Plate-model velocities are approximate and not official station-wise CORS velocities.\\n"\n            "                         Replace them with measured station velocities for final scientific products.\\n"\n            f"External velocity stations: {\' \'.join(sorted(set(external_velocity_stations))) if external_velocity_stations else \'None\'}\\n"\n            f"Long-term POS velocity stations: {\' \'.join(sorted(set(longterm_velocity_stations))) if longterm_velocity_stations else \'None\'}\\n"\n            f"Plate model stations    : {\' \'.join(sorted(set(plate_model_stations))) if plate_model_stations else \'None\'}\\n"\n            f"APR velocity stations   : {\' \'.join(sorted(set(apr_velocity_stations))) if apr_velocity_stations else \'None\'}\\n"\n            f"No-velocity stations    : {\' \'.join(sorted(set(no_real_velocity_stations))) if no_real_velocity_stations else \'None\'}\\n",\n            encoding="utf-8",\n        )\n        print_success(f"Saved requested-epoch coordinate CSV: {out_csv}")\n        print_success(f"Saved velocity values used CSV: {velocity_used_csv}")\n        print_success(f"Saved requested-epoch notes: {out_txt}")\n        if choice == "1":\n            print_info("This output used plate-model velocity. Label it clearly in reports.")\n        if choice == "3" and not longterm_velocity_stations:\n            print_warning("No station received measured long-term POS velocity in this run.")\n        if choice == "2" and not external_velocity_stations:\n            print_warning("No station received external CSV velocity in this run.")\n        if no_real_velocity_stations:\n            print_info("Stations without velocity were left unchanged from the reference epoch: " + " ".join(sorted(set(no_real_velocity_stations))))\n\n        run_count += 1\n        print_info("You may now choose another velocity option, change target epoch, or finish this section.")\n\n\ndef _fmt_float(value: object, width: int = 14, decimals: int = 4) -> str:\n    try:\n        if value is None:\n            return " " * width\n        return f"{float(value):{width}.{decimals}f}"\n    except Exception:\n        return f"{\'\':>{width}}"\n\n\ndef print_coordinate_table(rows: List[Dict[str, object]]) -> None:\n    """Print final local station coordinates from the combined .org file."""\n    print_header("FINAL LOCAL STATION COORDINATES FROM COMBINED .org")\n    if not rows:\n        print_warning("No local pbo. coordinate rows found in the combined .org file.")\n        print_info("Check whether local station names in the .org file match the selected station list.")\n        return\n\n    print(\n        f"{\'Station\':10s} {\'X (m)\':>15s} {\'Y (m)\':>15s} {\'Z (m)\':>15s} "\n        f"{\'Latitude (deg)\':>16s} {\'Longitude (deg)\':>16s} {\'Height (m)\':>12s}"\n    )\n    print("-" * 104)\n    for r in rows:\n        print(\n            f"{str(r.get(\'station\',\'\')):10s} "\n            f"{_fmt_float(r.get(\'x_m\'), 15, 4)} "\n            f"{_fmt_float(r.get(\'y_m\'), 15, 4)} "\n            f"{_fmt_float(r.get(\'z_m\'), 15, 4)} "\n            f"{_fmt_float(r.get(\'lat_deg\'), 16, 10)} "\n            f"{_fmt_float(r.get(\'lon_deg\'), 16, 10)} "\n            f"{_fmt_float(r.get(\'height_m\'), 12, 4)}"\n        )\n\n\ndef print_uncertainty_table(rows: List[Dict[str, object]]) -> None:\n    """Print coordinate uncertainty fields parsed from pbo. rows."""\n    print_header("LOCAL STATION UNCERTAINTIES")\n    if not rows:\n        print_warning("No uncertainty rows to print.")\n        return\n\n    print(\n        f"{\'Station\':10s} {\'sigX(m)\':>10s} {\'sigY(m)\':>10s} {\'sigZ(m)\':>10s} "\n        f"{\'sigN(m)\':>10s} {\'sigE(m)\':>10s} {\'sigU(m)\':>10s} {\'sigH(m)\':>10s}"\n    )\n    print("-" * 88)\n    for r in rows:\n        print(\n            f"{str(r.get(\'station\',\'\')):10s} "\n            f"{_fmt_float(r.get(\'sig_x_m\'), 10, 4)} "\n            f"{_fmt_float(r.get(\'sig_y_m\'), 10, 4)} "\n            f"{_fmt_float(r.get(\'sig_z_m\'), 10, 4)} "\n            f"{_fmt_float(r.get(\'sig_n_m\'), 10, 4)} "\n            f"{_fmt_float(r.get(\'sig_e_m\'), 10, 4)} "\n            f"{_fmt_float(r.get(\'sig_u_m\'), 10, 4)} "\n            f"{_fmt_float(r.get(\'sig_height_m\'), 10, 4)}"\n        )\n\n\ndef make_persistent_pos_files(project_dir: Path, daily_org_files: List[Path], log_dir: Path) -> Optional[Path]:\n    """Return the latest existing pos_* directory without failing the dashboard.\n\n    sh_glred/sh_plot_pos often creates pos_YYYY-DOY_YYYY-DOY directories during\n    time-series generation. Older integrated versions called this helper but did\n    not define it, causing a NameError after successful GLOBK processing. This\n    fixed helper locates existing POS directories and reports them. It does not\n    overwrite or delete any file.\n    """\n    gsoln = project_dir / "gsoln"\n    candidates = [p for p in gsoln.glob("pos_*") if p.is_dir()]\n    if not candidates:\n        candidates = [p for p in gsoln.rglob("pos_*") if p.is_dir()]\n\n    candidates = sorted(candidates, key=lambda p: p.stat().st_mtime if p.exists() else 0, reverse=True)\n    if not candidates:\n        print_info("No persistent pos_* time-series directory found yet.")\n        return None\n\n    pos_dir = candidates[0]\n    try:\n        log_dir.mkdir(parents=True, exist_ok=True)\n        (log_dir / "latest_pos_directory.txt").write_text(str(pos_dir) + "\\n", encoding="utf-8")\n    except Exception:\n        pass\n    return pos_dir\n\n\ndef warn_about_pos_filename_frame_label(pos_files: List[Path], frame_name: str, log_dir: Path) -> None:\n    """Explain labels such as orbit_igb14.pos when selected frame is different."""\n    if not pos_files:\n        return\n    names = [p.name for p in pos_files]\n    has_igb14_label = any("igb14" in n.lower() for n in names)\n    if frame_name.upper() == "ITRF08" and has_igb14_label:\n        msg = (\n            "Some .pos filenames contain \'orbit_igb14\'. This is a time-series/product naming "\n            "label produced by the GAMIT/GLOBK plotting tools and does not by itself prove that "\n            "the final GLOBK solution used IGS14. The effective apr_file/eq_file check printed "\n            "above is the source of truth for the frame used by this launcher."\n        )\n        print_info(msg)\n        try:\n            log_dir.mkdir(parents=True, exist_ok=True)\n            (log_dir / "pos_filename_frame_label_note.txt").write_text(msg + "\\n", encoding="utf-8")\n        except Exception:\n            pass\n\n\ndef print_plot_summary_and_optionally_open(project_dir: Path, year: str, start_doy: str, end_doy: str, local_stations: List[str]) -> None:\n    """List GLOBK time-series/residual plots and always try to create office-ready PDFs.\n\n    Convert available PostScript plots to PDF for office viewing/submission.\n\n    Why PDFs may not appear in older runs:\n    1. Older launcher versions reached a NameError before the plot/PDF section.\n    2. The PDF conversion section was placed after the optional epoch-coordinate section.\n    3. Ghostscript/ps2pdf may be missing on Ubuntu.\n    4. sh_plot_pos creates PostScript (.ps) files, not PDF files directly.\n\n    This improved helper runs before the optional epoch section, searches all usual\n    GLOBK plot folders, converts .ps -> .pdf automatically when possible, creates\n    a single merged PDF when possible, and writes a helper shell script when the\n    required converter is missing.\n    """\n    gsoln = project_dir / "gsoln"\n    out_dir = gsoln / "final_outputs"\n    out_dir.mkdir(parents=True, exist_ok=True)\n\n    # Search broadly because sh_plot_pos can create plots_*, pos_*, or pshist_* in gsoln.\n    ps_files = sorted({p.resolve() for p in gsoln.rglob("*.ps") if p.is_file()})\n    eps_files = sorted({p.resolve() for p in gsoln.rglob("*.eps") if p.is_file()})\n    png_files = sorted({p.resolve() for p in gsoln.rglob("*.png") if p.is_file()})\n    existing_pdf_files = sorted({p.resolve() for p in gsoln.rglob("*.pdf") if p.is_file()})\n    plot_files = ps_files + eps_files + png_files + existing_pdf_files\n\n    print_header("TIME-SERIES / RESIDUAL PLOT AND PDF OUTPUTS")\n    if not plot_files:\n        print_info("No plot files were found under project/gsoln yet.")\n        print_info("Usually sh_plot_pos creates plots after daily .org files are produced.")\n        print("Check manually with:")\n        print(f"  find {shell_quote(str(gsoln))} -type f \\\\( -name \'*.ps\' -o -name \'*.png\' -o -name \'*.pdf\' \\\\)")\n        return\n\n    print_success(\n        f"Found plot files: {len(ps_files)} PS, {len(eps_files)} EPS, "\n        f"{len(png_files)} PNG, {len(existing_pdf_files)} existing PDF"\n    )\n\n    all_plot_list = out_dir / "time_series_all_plot_files.txt"\n    all_plot_list.write_text("\\n".join(str(p) for p in plot_files) + "\\n", encoding="utf-8")\n    print_success(f"Saved complete plot list: {all_plot_list}")\n\n    # Print a compact list on screen.\n    for p in plot_files[:60]:\n        try:\n            print(f"  {p.relative_to(gsoln)}")\n        except Exception:\n            print(f"  {p}")\n    if len(plot_files) > 60:\n        print(f"  ... {len(plot_files) - 60} more")\n\n    source_ps_like = ps_files + eps_files\n    if not source_ps_like:\n        if existing_pdf_files:\n            print_success("PDF plots already exist; no PostScript conversion was needed.")\n        else:\n            print_info("No PostScript/EPS files were found to convert to PDF.")\n        return\n\n    pdf_dir = out_dir / f"time_series_plots_pdf_{year}-{start_doy}_{year}-{end_doy}"\n    pdf_dir.mkdir(parents=True, exist_ok=True)\n\n    ps2pdf_cmd = shutil.which("ps2pdf")\n    gs_cmd = shutil.which("gs")\n    pdfunite_cmd = shutil.which("pdfunite")\n\n    helper_script = out_dir / "convert_time_series_plots_to_pdf.sh"\n    helper_lines = [\n        "#!/usr/bin/env bash",\n        "set -euo pipefail",\n        f"PDF_DIR={shell_quote(str(pdf_dir))}",\n        "mkdir -p \\"$PDF_DIR\\"",\n        "if ! command -v ps2pdf >/dev/null 2>&1 && ! command -v gs >/dev/null 2>&1; then",\n        "  echo \'Ghostscript is required. Install with: sudo apt-get update && sudo apt-get install -y ghostscript\'",\n        "  exit 1",\n        "fi",\n    ]\n    for src in source_ps_like:\n        try:\n            rel = src.relative_to(gsoln)\n            safe_name = "__".join(rel.parts)\n        except Exception:\n            safe_name = src.name\n        safe_name = re.sub(r"\\.(ps|eps)$", ".pdf", safe_name, flags=re.I)\n        dst = pdf_dir / safe_name\n        helper_lines.append(f"echo \'Converting {src.name}\'")\n        helper_lines.append(f"if command -v ps2pdf >/dev/null 2>&1; then ps2pdf {shell_quote(str(src))} {shell_quote(str(dst))}; else gs -dBATCH -dNOPAUSE -sDEVICE=pdfwrite -sOutputFile={shell_quote(str(dst))} {shell_quote(str(src))}; fi")\n    helper_lines.append("echo \'PDF files created in:\' \\"$PDF_DIR\\"")\n    helper_script.write_text("\\n".join(helper_lines) + "\\n", encoding="utf-8")\n    helper_script.chmod(0o755)\n    print_success(f"Saved PDF conversion helper script: {helper_script}")\n\n    if not ps2pdf_cmd and not gs_cmd:\n        print_warning("PDF plots were not generated because Ghostscript/ps2pdf is not installed.")\n        print("Install once, then run the helper script:")\n        print("  sudo apt-get update")\n        print("  sudo apt-get install -y ghostscript")\n        print(f"  bash {shell_quote(str(helper_script))}")\n        return\n\n    converter_name = "ps2pdf" if ps2pdf_cmd else "gs"\n    print_info(f"Converting PostScript/EPS plots to PDF using: {converter_name}")\n\n    converted: List[Path] = []\n    failed: List[Tuple[Path, str]] = []\n    for src in source_ps_like:\n        try:\n            rel = src.relative_to(gsoln)\n            safe_name = "__".join(rel.parts)\n        except Exception:\n            safe_name = src.name\n        safe_name = re.sub(r"\\.(ps|eps)$", ".pdf", safe_name, flags=re.I)\n        pdf = pdf_dir / safe_name\n\n        if ps2pdf_cmd:\n            cmd = [ps2pdf_cmd, str(src), str(pdf)]\n        else:\n            cmd = [\n                gs_cmd,\n                "-dBATCH",\n                "-dNOPAUSE",\n                "-sDEVICE=pdfwrite",\n                f"-sOutputFile={pdf}",\n                str(src),\n            ]\n        try:\n            r = subprocess.run(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)\n            if r.returncode == 0 and pdf.is_file() and pdf.stat().st_size > 0:\n                converted.append(pdf)\n            else:\n                failed.append((src, (r.stderr or r.stdout or "unknown conversion error").strip()[:500]))\n        except Exception as e:\n            failed.append((src, str(e)))\n\n    pdf_list_file = out_dir / "time_series_plot_pdf_files.txt"\n    pdf_list_file.write_text("\\n".join(str(p) for p in converted) + "\\n", encoding="utf-8")\n\n    if converted:\n        print_success(f"Created {len(converted)} PDF plot file(s) in: {pdf_dir}")\n        print_success(f"Saved PDF plot list: {pdf_list_file}")\n        print("Open first PDF plot:")\n        print(f"  xdg-open {shell_quote(str(converted[0]))}")\n        print("List all PDF plots:")\n        print(f"  ls -lh {shell_quote(str(pdf_dir))}/*.pdf")\n    else:\n        print_warning("No PDF plot was created although a converter was found. See conversion log below.")\n\n    if failed:\n        fail_file = out_dir / "time_series_plot_pdf_conversion_failed.txt"\n        fail_file.write_text(\n            "\\n".join(f"{src}\\n  {msg}" for src, msg in failed) + "\\n",\n            encoding="utf-8",\n        )\n        print_warning(f"Could not convert {len(failed)} file(s). Details saved: {fail_file}")\n\n    # Also make one combined PDF for easy office submission when possible.\n    if converted:\n        merged_pdf = out_dir / f"time_series_all_plots_{year}-{start_doy}_{year}-{end_doy}.pdf"\n        merge_ok = False\n        merge_err = ""\n        try:\n            if pdfunite_cmd:\n                cmd = [pdfunite_cmd] + [str(p) for p in converted] + [str(merged_pdf)]\n            elif gs_cmd:\n                cmd = [\n                    gs_cmd,\n                    "-dBATCH",\n                    "-dNOPAUSE",\n                    "-sDEVICE=pdfwrite",\n                    f"-sOutputFile={merged_pdf}",\n                ] + [str(p) for p in converted]\n            else:\n                cmd = []\n            if cmd:\n                r = subprocess.run(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)\n                merge_ok = r.returncode == 0 and merged_pdf.is_file() and merged_pdf.stat().st_size > 0\n                merge_err = (r.stderr or r.stdout or "").strip()\n        except Exception as e:\n            merge_err = str(e)\n\n        if merge_ok:\n            print_success(f"Created single combined PDF for office viewing: {merged_pdf}")\n            print("Open combined PDF:")\n            print(f"  xdg-open {shell_quote(str(merged_pdf))}")\n        else:\n            merge_note = out_dir / "time_series_merged_pdf_not_created.txt"\n            merge_note.write_text(\n                "Combined PDF was not created. Individual PDFs are available.\\n"\n                f"Reason: {merge_err or \'pdfunite/gs merge not available\'}\\n"\n                f"PDF folder: {pdf_dir}\\n",\n                encoding="utf-8",\n            )\n            print_info(f"Single combined PDF was not created; individual PDFs are available. Note: {merge_note}")\n\ndef print_final_results_dashboard(\n    project_dir: Path,\n    year: str,\n    start_doy: str,\n    end_doy: str,\n    expt: str,\n    yy: str,\n    local_stations: List[str],\n    daily_org_files: List[Path],\n    comb_org: List[Path],\n    log_dir: Path,\n    apr_path: Optional[Path] = None,\n    frame_name: str = "",\n) -> None:\n    """Print all important results at the end.\n\n    The time-series/PDF section is intentionally placed before the optional\n    user-epoch coordinate section. Therefore, PDFs are generated even if the\n    user later skips or makes mistakes in the epoch-propagation menu.\n    """\n    print_header("FINAL RESULTS DASHBOARD")\n\n    gsoln = project_dir / "gsoln"\n    out_dir = gsoln / "final_outputs"\n    out_dir.mkdir(parents=True, exist_ok=True)\n\n    print_info(f"Project       : {project_dir}")\n    print_info(f"GLOBK folder  : {gsoln}")\n    print_info(f"Daily .org    : {len(daily_org_files)} file(s)")\n    for p in daily_org_files:\n        print(f"  {p.name}")\n\n    combined = comb_org[0] if comb_org else None\n    if combined:\n        print_success(f"Combined .org : {combined.name}")\n    else:\n        print_warning("No combined .org file found.")\n\n    coord_rows: List[Dict[str, object]] = []\n\n    if combined:\n        summary_lines = extract_solution_summary(combined)\n        if summary_lines:\n            print_header("COMBINED .org SOLUTION SUMMARY")\n            for line in summary_lines:\n                print(line)\n\n        pos_stats = extract_pos_statistics(combined)\n        if pos_stats:\n            print_header("POS STATISTICS")\n            for line in pos_stats:\n                print(line)\n\n            stats_file = out_dir / "pos_statistics.txt"\n            stats_file.write_text("\\n".join(pos_stats) + "\\n", encoding="utf-8")\n            print_success(f"Saved POS statistics: {stats_file}")\n\n        coord_rows = parse_pbo_coordinates_from_org(combined, local_stations)\n        print_coordinate_table(coord_rows)\n        print_uncertainty_table(coord_rows)\n\n        if coord_rows:\n            csv_file = out_dir / "local_final_coordinates.csv"\n            write_coordinates_csv(coord_rows, csv_file)\n            print_success(f"Saved coordinate CSV: {csv_file}")\n\n            txt_file = out_dir / "extract_final_coordinates_command.txt"\n            local_pattern = "\\\\|".join(st.upper() for st in local_stations)\n            txt_file.write_text(\n                f"cd {shell_quote(gsoln)}\\n"\n                f"grep \'^pbo.\' {shell_quote(combined.name)} | grep -i \\"{local_pattern}\\"\\n",\n                encoding="utf-8",\n            )\n            print_success(f"Saved extraction command: {txt_file}")\n\n    # Time-series files and plot/PDF conversion come before optional epoch section.\n    try:\n        pos_dir = make_persistent_pos_files(project_dir, daily_org_files, log_dir)\n        if pos_dir:\n            pos_files = sorted(pos_dir.glob("*.pos"))\n            print_header("PERSISTENT TIME-SERIES .pos FILES")\n            print_success(f"Created/found {len(pos_files)} .pos file(s) in {pos_dir}")\n            for p in pos_files[:40]:\n                print(f"  {p.name}")\n            if len(pos_files) > 40:\n                print(f"  ... {len(pos_files) - 40} more")\n            warn_about_pos_filename_frame_label(pos_files, frame_name, log_dir)\n    except Exception as e:\n        print_warning(f"Time-series .pos summary could not be prepared, but processing output is still available: {e}")\n\n    try:\n        print_plot_summary_and_optionally_open(project_dir, year, start_doy, end_doy, local_stations)\n    except Exception as e:\n        print_warning(f"Plot/PDF output section did not complete: {e}")\n        err_file = out_dir / "time_series_pdf_section_error.txt"\n        err_file.write_text(str(e) + "\\n", encoding="utf-8")\n        print_info(f"Saved PDF section error note: {err_file}")\n\n    if coord_rows:\n        if ask_yes_no("Create local coordinates at a user-specified epoch/date?", "yes"):\n            try:\n                create_epoch_coordinate_output(coord_rows, apr_path, year, start_doy, end_doy, out_dir)\n            except Exception as e:\n                print_warning(f"Requested-epoch coordinate section stopped, but final GLOBK results and plot/PDF outputs were already saved: {e}")\n                err_file = out_dir / "requested_epoch_section_error.txt"\n                err_file.write_text(str(e) + "\\n", encoding="utf-8")\n                print_info(f"Saved epoch-section error note: {err_file}")\n\n    print_header("USEFUL FINAL COMMANDS")\n    if combined:\n        local_pattern = "\\\\|".join(st.upper() for st in local_stations)\n        print("Extract local final coordinates:")\n        print(f"  cd {shell_quote(gsoln)}")\n        print(f"  grep \'^pbo.\' {shell_quote(combined.name)} | grep -i \\"{local_pattern}\\"")\n    print()\n    print("List all .org outputs:")\n    print(f"  ls -lh {shell_quote(gsoln)}/*.org")\n    print()\n    print("List all time-series/residual plots and PDFs:")\n    print(f"  find {shell_quote(gsoln)} -type f \\\\( -name \'*.ps\' -o -name \'*.png\' -o -name \'*.pdf\' \\\\)")\n    print()\n    print("Open generated PDF plot folder if available:")\n    print(f"  find {shell_quote(str(out_dir))} -maxdepth 2 -type f -name \'*.pdf\' -print")\n\n\n\n\n# =============================================================================\n# OPTIONAL APR / VELOCITY EXTRACTION\n# =============================================================================\n\ndef run_sh_exglk_apr_extraction(project_dir: Path, combined_org: Optional[Path], log_dir: Path) -> Optional[Path]:\n    """Run sh_exglk APR extraction from the combined .org when available."""\n    if combined_org is None or not combined_org.is_file():\n        print_warning("sh_exglk skipped: combined .org file not available.")\n        return None\n    if not command_exists("sh_exglk"):\n        print_warning("sh_exglk not found; APR extraction skipped.")\n        return None\n    gsoln = project_dir / "gsoln"\n    out_apr = gsoln / f"extracted_{combined_org.stem}.apr"\n    cmd = ["sh_exglk", "-f", combined_org.name, "-apr", out_apr.name]\n    append_command_log(log_dir, "sh_exglk APR extraction", cmd)\n    log_path = log_dir / "sh_exglk_apr_extraction.log"\n    print_progress("Running APR extraction: " + " ".join(cmd))\n    if is_dry_run():\n        print_info("[DRY-RUN] sh_exglk command preview only; not executed.")\n        return out_apr\n    try:\n        with open(log_path, "w", encoding="utf-8", errors="ignore") as f:\n            proc = subprocess.run(cmd, cwd=str(gsoln), stdout=f, stderr=subprocess.STDOUT, text=True, timeout=180)\n        if proc.returncode == 0 and out_apr.is_file():\n            print_success(f"APR extracted by sh_exglk: {out_apr}")\n            return out_apr\n        print_warning(f"sh_exglk returned {proc.returncode}; check {log_path}")\n        return None\n    except Exception as e:\n        print_warning(f"sh_exglk failed: {e}")\n        return None\n\n\ndef parse_vel_file_to_csv(vel_file: Path, out_csv: Path) -> Optional[Path]:\n    """Best-effort parser for sh_org2vel .vel output."""\n    if not vel_file.is_file():\n        return None\n    rows = []\n    for line in vel_file.read_text(errors="ignore").splitlines():\n        if not line.strip() or line.lstrip().startswith(("#", "*")):\n            continue\n        parts = line.split()\n        site = next((p for p in parts if re.match(r"^[A-Za-z0-9]{4}(?:_GPS)?$", p)), None)\n        nums = []\n        for token in parts:\n            try:\n                nums.append(float(token.replace("D", "E")))\n            except Exception:\n                pass\n        if site and len(nums) >= 2:\n            rows.append([site.upper(), *nums[:8], line])\n    if not rows:\n        print_warning(f"No parseable velocity rows found in {vel_file}")\n        return None\n    import csv\n    out_csv.parent.mkdir(parents=True, exist_ok=True)\n    with open(out_csv, "w", newline="", encoding="utf-8") as f:\n        w = csv.writer(f)\n        w.writerow(["station", "num1", "num2", "num3", "num4", "num5", "num6", "num7", "num8", "raw_line"])\n        w.writerows(rows)\n    print_success(f"Parsed velocity file to CSV: {out_csv}")\n    return out_csv\n\n\ndef run_sh_org2vel_velocity(project_dir: Path, combined_org: Optional[Path], log_dir: Path) -> Optional[Path]:\n    """Run sh_org2vel only when the user wants a velocity extraction attempt."""\n    if combined_org is None or not combined_org.is_file():\n        print_warning("sh_org2vel skipped: combined .org file not available.")\n        return None\n    if not command_exists("sh_org2vel"):\n        print_warning("sh_org2vel not found; velocity extraction skipped.")\n        return None\n    if not ask_yes_no("Run sh_org2vel velocity extraction? Use mainly for long-term/multi-year data", "no"):\n        return None\n    gsoln = project_dir / "gsoln"\n    out_vel = gsoln / f"velocity_{combined_org.stem}.vel"\n    cmd = ["sh_org2vel", "-f", combined_org.name, "-vel", out_vel.name]\n    append_command_log(log_dir, "sh_org2vel velocity extraction", cmd)\n    log_path = log_dir / "sh_org2vel_velocity.log"\n    print_progress("Running velocity extraction: " + " ".join(cmd))\n    if is_dry_run():\n        print_info("[DRY-RUN] sh_org2vel command preview only; not executed.")\n        return out_vel\n    try:\n        with open(log_path, "w", encoding="utf-8", errors="ignore") as f:\n            proc = subprocess.run(cmd, cwd=str(gsoln), stdout=f, stderr=subprocess.STDOUT, text=True, timeout=300)\n        if proc.returncode == 0 and out_vel.is_file():\n            print_success(f"Velocity file created: {out_vel}")\n            csv_path = project_dir / "gsoln" / "final_outputs" / f"{out_vel.stem}.csv"\n            parse_vel_file_to_csv(out_vel, csv_path)\n            return out_vel\n        print_warning(f"sh_org2vel returned {proc.returncode}; check {log_path}")\n        return None\n    except Exception as e:\n        print_warning(f"sh_org2vel failed: {e}")\n        return None\n\n\n# =============================================================================\n# DOC-51/DOC-76 PRODUCTIVE ADD-ONS\n# =============================================================================\ndef _safe_station_name_from_file(path: Path) -> str:\n    """Return a station-like name from a GAMIT/GLOBK product filename."""\n    name = path.name\n    # Common examples: psbase_neww.IC01, PRT_SOAM.vel, MEAN.HYD2.soi.orbit.res.ps\n    m = re.search(r"\\.([A-Za-z0-9]{4})(?:\\.|$)", name)\n    if m:\n        return m.group(1).upper()\n    m = re.search(r"([A-Za-z0-9]{4})", name)\n    return m.group(1).upper() if m else "UNKNOWN"\n\n\ndef collect_plate_frame_outputs(project_dir: Path, log_dir: Path) -> List[Path]:\n    """\n    Collect plate-frame products such as PRT_SOAM.apr, PRT_SOAM.vel,\n    PRT_SOAM_plate.apr and PRT_SOAM_plate.vel.\n\n    This follows the old lab workflow where SOAM/plate outputs are inspected\n    after sh_org2vel/sh_plotvel; APR-type files may contain Cartesian/UTM-style\n    coordinate records and VEL files contain geographic velocity records.\n    """\n    print_header("PLATE-FRAME / SOAM OUTPUT COLLECTION")\n    roots = [project_dir / "vsoln", project_dir / "gsoln"]\n    patterns = ["PRT_*.apr", "PRT_*.vel", "*_plate.apr", "*_plate.vel", "*SOAM*.apr", "*SOAM*.vel"]\n    found: List[Path] = []\n    for root in roots:\n        if not root.is_dir():\n            continue\n        for pat in patterns:\n            found.extend(sorted(root.glob(pat)))\n    # de-duplicate while preserving order\n    unique: List[Path] = []\n    seen = set()\n    for p in found:\n        rp = str(p.resolve())\n        if rp not in seen:\n            unique.append(p)\n            seen.add(rp)\n\n    out_dir = project_dir / "gsoln" / "final_outputs"\n    out_dir.mkdir(parents=True, exist_ok=True)\n    list_file = out_dir / "plate_frame_output_files.txt"\n    with open(list_file, "w", encoding="utf-8") as f:\n        f.write("# Plate-frame / SOAM / PRT output files found\\n")\n        for p in unique:\n            f.write(str(p) + "\\n")\n\n    if not unique:\n        print_info("No PRT_SOAM / plate-frame APR/VEL files found yet. This is normal unless a plate-frame velocity workflow was run.")\n        print_info(f"Saved empty plate-frame list: {list_file}")\n        return []\n\n    print_success(f"Found {len(unique)} plate-frame output file(s).")\n    for p in unique:\n        rel = p.relative_to(project_dir) if str(p).startswith(str(project_dir)) else p\n        print(f"  {rel}")\n        if p.suffix.lower() == ".vel":\n            csv_path = out_dir / f"{p.stem}_parsed_velocity.csv"\n            try:\n                parse_vel_file_to_csv(p, csv_path)\n            except Exception as e:\n                print_warning(f"Could not parse velocity file {p.name}: {e}")\n    print_success(f"Saved plate-frame output list: {list_file}")\n    return unique\n\n\ndef collect_psbase_position_error_outputs(project_dir: Path, log_dir: Path) -> Optional[Path]:\n    """\n    Scan psbase_* files produced by the old GLOBK lab workflow. These files show\n    the magnitude of North/East/Up position errors for stations.\n    """\n    print_header("PSBASE POSITION-ERROR OUTPUTS")\n    gsoln = project_dir / "gsoln"\n    out_dir = gsoln / "final_outputs"\n    out_dir.mkdir(parents=True, exist_ok=True)\n    files = []\n    if gsoln.is_dir():\n        for pat in ["psbase_*", "psbase.*", "*psbase*"]:\n            files.extend(sorted(gsoln.glob(pat)))\n    unique = []\n    seen = set()\n    for p in files:\n        if p.is_file() and str(p.resolve()) not in seen:\n            unique.append(p)\n            seen.add(str(p.resolve()))\n    csv_path = out_dir / "psbase_position_error_summary.csv"\n    with open(csv_path, "w", encoding="utf-8") as f:\n        f.write("file,station,size_bytes,note\\n")\n        for p in unique:\n            station = _safe_station_name_from_file(p)\n            note = "position-error plot/statistics file; view with gs/gv or convert with ps2pdf if PostScript"\n            f.write(f"{p.name},{station},{p.stat().st_size},{note}\\n")\n    if unique:\n        print_success(f"Found {len(unique)} psbase position-error file(s).")\n        for p in unique[:20]:\n            print(f"  {p.relative_to(project_dir) if str(p).startswith(str(project_dir)) else p}")\n        print_success(f"Saved psbase summary: {csv_path}")\n    else:\n        print_info("No psbase_* position-error files found. This is normal unless legacy sh_glred/sh_oneway products were created.")\n        print_success(f"Saved empty psbase summary: {csv_path}")\n    return csv_path\n\n\ndef run_optional_sh_plotvel_map(project_dir: Path, combined_org: Optional[Path], vel_file: Optional[Path], log_dir: Path) -> None:\n    """\n    Optional old-lab velocity-map plotting step.\n    It does not replace CSV velocity extraction. It only runs if user agrees and\n    if sh_plotvel is available.\n    """\n    print_header("OPTIONAL sh_plotvel VELOCITY MAP")\n    if not command_exists("sh_plotvel"):\n        print_info("sh_plotvel not found; velocity-map plotting skipped.")\n        return\n    gsoln = project_dir / "gsoln"\n    candidate_orgs: List[Path] = []\n    if combined_org and combined_org.is_file():\n        candidate_orgs.append(combined_org)\n    # Plate-frame orgs such as PRT_SOAM.org are usually in vsoln.\n    for root in [project_dir / "vsoln", gsoln]:\n        if root.is_dir():\n            candidate_orgs.extend(sorted(root.glob("PRT_*.org")))\n            candidate_orgs.extend(sorted(root.glob("*SOAM*.org")))\n    # de-duplicate\n    orgs=[]; seen=set()\n    for p in candidate_orgs:\n        if str(p.resolve()) not in seen:\n            orgs.append(p); seen.add(str(p.resolve()))\n    if not orgs:\n        print_info("No .org file available for sh_plotvel.")\n        return\n    if not ask_yes_no("Run optional sh_plotvel velocity map? Use only when a velocity/plate-frame .org is meaningful", "no"):\n        return\n    print("Available .org files:")\n    for i,p in enumerate(orgs,1):\n        print(f"  {i}. {p}")\n    idx = ask_choice_index("Choose .org for sh_plotvel", [str(p.name) for p in orgs], 0)\n    org = orgs[idx]\n    region = ask_input("GMT region -R for sh_plotvel", "-R65/100/5/40")\n    ps_name = ask_input("Output PS base name", f"velocity_map_{org.stem}")\n    cmd = ["sh_plotvel", "-f", org.name, "-ps", ps_name, region]\n    append_command_log(log_dir, "optional sh_plotvel velocity map", cmd)\n    log_path = log_dir / f"sh_plotvel_{org.stem}.log"\n    print_progress("Running: " + " ".join(cmd))\n    if is_dry_run():\n        print_info("[DRY-RUN] sh_plotvel command preview only; not executed.")\n        return\n    try:\n        with open(log_path, "w", encoding="utf-8", errors="ignore") as f:\n            proc = subprocess.run(cmd, cwd=str(org.parent), stdout=f, stderr=subprocess.STDOUT, text=True, timeout=300)\n        if proc.returncode == 0:\n            print_success(f"sh_plotvel completed. Log: {log_path}")\n            ps_file = org.parent / f"{ps_name}.ps"\n            if ps_file.is_file():\n                print_success(f"Velocity map created: {ps_file}")\n                print_info(f"Open with: gs {ps_file}")\n        else:\n            print_warning(f"sh_plotvel returned {proc.returncode}; check {log_path}")\n    except Exception as e:\n        print_warning(f"sh_plotvel failed: {e}")\n\n\ndef write_doc51_doc76_notes(project_dir: Path, log_dir: Path) -> Path:\n    """Save office notes from uploaded Doc-51 and Doc-76 PDFs."""\n    out_dir = project_dir / "gsoln" / "final_outputs"\n    out_dir.mkdir(parents=True, exist_ok=True)\n    note = out_dir / "doc51_doc76_doc101_doc126_doc151_doc176_practical_notes.txt"\n    note.write_text("""DOC-51 / DOC-76 / DOC-101 / DOC-126 / DOC-151 / DOC-176 PRACTICAL NOTES ADDED\\n\\n1. Plate-frame/SOAM outputs:\\n   - PRT_SOAM.apr may be inspected for plate-frame coordinate output.\\n   - PRT_SOAM.vel may be inspected for geographic coordinate/velocity output.\\n   - *_plate.apr and *_plate.vel outputs are collected when present.\\n\\n2. Position-error plots:\\n   - psbase_* files in gsoln show magnitude of position errors in North/East/Up.\\n   - These are listed in psbase_position_error_summary.csv when present.\\n\\n3. GLOBK/GLORG frame realization:\\n   - GAMIT daily h-files are loose/floating quasi-observations.\\n   - GLOBK/GLORG realizes the final frame by Helmert transformation/generalized constraints using APR and stabilization sites.\\n\\n4. Q-file and H-file explanation:\\n   - q-file: constrained GAMIT solution record.\\n   - h-file: loose solution and covariance for GLOBK combination.\\n\\n5. Velocity caution:\\n   - Short runs are not valid for geodetic velocity estimation.\\n   - The lab note says velocity estimation requires about 3 years or more of data.\\n\\n6. OTL/EOP/product safety:\\n   - otl_FES2004.grid must be checked and downloaded/replaced if missing or corrupted.\\n   - pole.usno and ut1.usno should be present for productive noftp runs.\\n\n\n7. Doc-101/Doc-126 GLOBK workflow confirmation:\n   - htoglb converts ASCII h-files to binary .glx/.glr files in glbf/.\n   - sh_glred -cmd prepares globk.cmd and glorg.cmd.\n   - sh_glred -opt G T or H G T creates daily .org, POS/time-series and plots.\n   - COMB + -ncomb creates a combined survey .org.\n   - sh_exglk extracts a final regional APR from the combined .org.\n\n8. Frame/APR/EQ/hierarchy reminder:\n   - For IGS20 realization, globk.cmd/glorg.cmd should use IGS20 APR/EQ and IGS20 hierarchy/stabilization lines.\n   - Old defaults such as igb14_comb.apr must not remain active if the selected frame is IGS20.\n\n9. Final APR/velocity caution:\n   - A regional APR extracted using sh_exglk after a short survey gives coordinate estimates.\n   - It does not provide real station velocities unless long-term velocity processing is performed.\n   - Lab notes warn that proper velocity estimation requires long-term data, about 3 years or more.\n\n10. Position-error and output checking:\n   - Inspect psbase_* position-error files where present.\n   - Inspect .org, .apr, .vel, POS, WRMS/NRMS and plot/PDF outputs before reporting.\n\n\n11. Doc-151/Doc-176 GLOBK/GLORG constraints:\n   - globk.cmd must specify a-priori sigmas/constraints for estimated parameter groups; otherwise those parameters may be ignored by the Kalman filter.\n   - apr_site all 10 10 10 0 0 0 is a site-coordinate sigma/constraint line, not a station-velocity line.\n   - glorg.cmd realizes the reference frame using generalized constraints and Helmert parameters.\n   - pos_org xtran ytran ztran xrot yrot zrot allows translation and rotation frame realization.\n   - stab_it 4 0.8 3.0 and a well-distributed stab_site list help identify and reduce unstable stabilization sites.\n\n12. Generalized-constraint explanation for reports:\n   - GLORG minimizes coordinate adjustments of good frame-defining stations while estimating translation and rotation, and sometimes scale if selected.\n   - Use as many good, well-distributed stabilization sites as practical, all from the selected frame family.\n   - Too few or poorly distributed stabilization sites weaken the reference-frame realization.\n\n13. Global H-file option:\n   - sh_glred can include external/global H-files using an F option and network source when intentionally selected, for example a MIT/SOPAC global H-file workflow.\n   - This launcher keeps that as an advanced optional workflow; it should not be mixed silently with a local-only CORS demonstration.\n\n14. Model/QC interpretation:\n   - GAMIT produces covariance matrices from daily solutions; GLOBK combines them to estimate positions, velocities, and/or frame parameters.\n   - Daily RMS/NRMS and psbase/POS repeatability should be interpreted together before accepting final coordinates.\n""", encoding="utf-8")\n    print_success(f"Saved Doc-51/Doc-76 practical notes: {note}")\n    return note\n\n\ndef diagnose_globk_chisquare_and_outputs(\n    project_dir: Path,\n    log_dir: Path,\n    combined_orgs: List[Path],\n    expt: str,\n    yy: str,\n    start_doy: str,\n    end_doy: str,\n) -> Path:\n    """Diagnose GLOBK/GLORG rejection even when sh_glred returns 0.\n\n    This specifically detects the practical case:\n    GAMIT and htoglb create GLX/GLR files, but GLOBK rejects one or more daily\n    solutions due to high chi-square increment or similar solution-consistency\n    problems.\n    """\n    gsoln = project_dir / "gsoln"\n    report = log_dir / "globk_chisquare_rejection_diagnosis.txt"\n    files: List[Path] = []\n    for root in [gsoln, log_dir]:\n        if root.is_dir():\n            for pat in ["GLOBK.status", "GLOBK.warning", "globk_*.log", "globk_*.prt", "*.prt", "*.log", "*.org"]:\n                files.extend(root.rglob(pat))\n    files = sorted(set(p for p in files if p.is_file()))\n\n    patterns = {\n        "chi-square increment rejection": r"Not used chi\\*\\*2 increment too large|chi\\*\\*2 increment too large",\n        "not including data": r"Not including this data|not including this data",\n        "max_chii/max_chii_inc": r"max_chii|max_chii_inc",\n        "globk no stations/baselines": r"0\\s+stations|zero\\s+stations|0\\s+baselines|zero\\s+baseline",\n        "empty or missing pos": r"POS STATISTICS",\n    }\n\n    hits: List[str] = []\n    for f in files:\n        txt = read_text_safe(f, max_bytes=8_000_000)\n        if not txt:\n            continue\n        for label, pat in patterns.items():\n            if re.search(pat, txt, re.I):\n                hits.append(f"{label}: {f}")\n\n    expected_combined = gsoln / f"globk_{expt}_{yy}{start_doy}_{yy}{end_doy}.org"\n    if not combined_orgs and not expected_combined.is_file():\n        hits.append(f"missing combined .org file: expected {expected_combined}")\n\n    pos_files = sorted(gsoln.rglob("*.pos")) if gsoln.is_dir() else []\n    empty_pos = [p for p in pos_files if p.stat().st_size == 0]\n    if not pos_files:\n        hits.append("missing POS/time-series .pos outputs under gsoln")\n    if empty_pos:\n        hits.append("empty POS file(s): " + ", ".join(str(p) for p in empty_pos[:10]))\n\n    lines = []\n    lines.append("GLOBK CHI-SQUARE / OUTPUT DIAGNOSIS")\n    lines.append("=" * 72)\n    lines.append(f"Project: {project_dir}")\n    lines.append(f"Scanned files: {len(files)}")\n    lines.append(f"Combined .org found: {\'YES\' if combined_orgs else \'NO\'}")\n    lines.append("")\n    if hits:\n        lines.append("Detected warning/failure clues:")\n        lines.extend("  - " + h for h in hits)\n        lines.append("")\n        lines.append("Interpretation:")\n        lines.append("  GAMIT and/or htoglb may have succeeded, but GLOBK/GLORG may not have produced a fully usable combined solution.")\n        lines.append("  This is usually a GLOBK solution-consistency/control-file/data-quality issue, not a Python failure.")\n        lines.append("")\n        lines.append("Safe diagnosis steps:")\n        lines.append("  1. Run single-day GLOBK tests.")\n        lines.append("  2. Run two-day combinations such as 091-092 and 092-093.")\n        lines.append("  3. Compare station availability in each daily h-file/GLX/GLR.")\n        lines.append("  4. Check that GAMIT and GLOBK/GLORG use the same APR/frame family.")\n        lines.append("  5. Review max_chii / max_chii_inc, but do not blindly loosen them.")\n        lines.append("  6. Check coordinate jumps, antenna/receiver changes, missing stations, and bad daily GAMIT NRMS.")\n        lines.append("  7. Use project custom APR first before switching to a generic global APR.")\n        print_warning("GLOBK/GLORG diagnosis found possible rejection/output problems. See report.")\n    else:\n        lines.append("No obvious chi-square rejection or output-missing clue detected in scanned files.")\n        print_success("No obvious GLOBK chi-square rejection clue detected.")\n    report.write_text("\\n".join(lines) + "\\n", encoding="utf-8")\n    print_success(f"Saved GLOBK diagnosis report: {report}")\n    return report\n\n\n# =============================================================================\n# MAIN\n# =============================================================================\n\ndef main() -> int:\n    print_header("AUTOM-GLOBK / GLORG DASHBOARD")\n\n    default_project = os.environ.get("INTEGRATED_PROJECT_DIR", str(Path.cwd()))\n    project_dir = normalize_path(ask_input("Project folder", default_project))\n\n    if not project_dir.is_dir():\n        print_error(f"Not a directory: {project_dir}")\n        return 1\n\n    print_success(f"Project: {project_dir}")\n\n    globk_stage_gate("scan")\n    scan_results = scan_hfiles(project_dir)\n    if not scan_results:\n        print_error("No h-files found. Run GAMIT first.")\n        return 1\n\n    selected = select_processing_range(scan_results)\n\n    if not check_scan_consistency(selected):\n        return 1\n\n    year, start_doy, end_doy, ndays_str, expt, netext, doys = detect_settings(selected)\n    ndays = int(ndays_str)\n    yy = selected[doys[0]]["yy"]\n\n    show_detected_settings(year, start_doy, end_doy, ndays_str, expt, netext, doys)\n\n    if not ask_yes_no("Proceed?", "yes"):\n        return 0\n\n    log_dir = project_dir / "globk_glorg_logs"\n    log_dir.mkdir(exist_ok=True)\n\n    preflight_environment_report(project_dir, log_dir)\n\n    print_header("TOOL CHECK")\n    required = ["sh_glred", "globk", "glorg", "htoglb"]\n    missing = False\n\n    for cmd in required:\n        if not command_exists(cmd):\n            print_error(f"{cmd} not found")\n            missing = True\n        else:\n            print_success(f"{cmd} found at {shutil.which(cmd)}")\n\n    if missing:\n        print_error("Missing required tools. Source GAMIT/GLOBK environment.")\n        return 1\n\n    print_header("COMMAND FILE VERSION CHECK")\n    glorg_cmd = project_dir / "tables" / "glorg.cmd"\n    need_regenerate = False\n\n    if glorg_cmd.is_file():\n        header = read_text_safe(glorg_cmd, max_bytes=300)\n        if not re.search(r"version\\s+[0-9.]+", header, re.I):\n            need_regenerate = True\n            print_warning("glorg.cmd has no clear version header.")\n    else:\n        need_regenerate = True\n\n    if need_regenerate:\n        if not regenerate_command_files(project_dir):\n            print_error("Could not regenerate command files. Exiting.")\n            return 1\n    else:\n        print_success("Command files appear to have a version header.")\n\n    print_header("LOCAL STATION DETECTION")\n    local_stations: List[str] = []\n    sites_defaults = project_dir / "tables" / "sites.defaults"\n\n    if sites_defaults.is_file():\n        for line in read_text_safe(sites_defaults).splitlines():\n            if "localrx" in line.lower():\n                parts = line.split()\n                if parts:\n                    site = parts[0].lower().replace("_gps", "")\n                    if re.match(r"^[a-z0-9]{4}$", site) and site not in local_stations:\n                        local_stations.append(site)\n\n    if not local_stations:\n        user_input = ask_input(\n            "Enter local station names (space-separated, 4-char codes)",\n            "hyd2 indo jaba jaip mndi rai3 roo3",\n        )\n        local_stations = [s.lower() for s in user_input.split() if re.match(r"^[a-z0-9]{4}$", s.lower())]\n\n    print_success("Local stations: " + " ".join(local_stations))\n\n    globk_stage_gate("frame")\n    print_header("APR SELECTION / CHECK / REPAIR")\n    if not ensure_custom_apr_exists(project_dir):\n        return 1\n\n    apr_path, eq_path, frame_name = select_frame(project_dir)\n\n    print_success(f"Selected APR for GLOBK: {apr_path}")\n    print_success(f"Detected APR family   : {frame_name}")\n\n    if not ensure_local_stations_in_apr(apr_path, project_dir, local_stations):\n        print_error("APR repair failed.")\n        return 1\n\n    fix_zero_sigmas_in_apr(apr_path, local_stations)\n\n    check_sites_exist_in_apr(apr_path, local_stations, "local stations")\n\n    stab_sites = detect_stab_sites(project_dir, doys)\n\n    if len(stab_sites) < 3:\n        print_error("Need at least 3 stabilization sites.")\n        return 1\n\n    print_success(f"Stabilization sites: {\' \'.join(stab_sites)}")\n\n    if len(stab_sites) < 8:\n        print_warning("Only a few stabilization sites; 8-10 recommended for robustness.")\n\n    globk_project_health_check(\n        project_dir=project_dir,\n        selected=selected,\n        year=year,\n        start_doy=start_doy,\n        end_doy=end_doy,\n        expt=expt,\n        netext=netext,\n        local_stations=local_stations,\n        apr_path=apr_path,\n        eq_path=eq_path,\n        frame_name=frame_name,\n        stab_sites=stab_sites,\n        log_dir=log_dir,\n    )\n\n    globk_stage_gate("patch")\n    print_header("PATCHING COMMAND FILES")\n    print_info("Will patch globk.cmd and glorg.cmd with:")\n    print(f"  APR: {apr_path}")\n    if eq_path:\n        print(f"  EQ:  {eq_path}")\n    print(f"  Stabilization: {\' \'.join(stab_sites)}")\n\n    if ask_yes_no("Proceed with patching?", "yes"):\n        patch_globk_glorg(project_dir, apr_path, eq_path, stab_sites)\n    else:\n        print_warning("Skipping patching. Using existing command files.")\n        if not ask_yes_no("Continue with existing command files?", "no"):\n            return 0\n\n    report_effective_command_settings(project_dir, log_dir, frame_name)\n    audit_globk_glorg_constraint_commands(project_dir, log_dir)\n\n    globk_stage_gate("run")\n    print_header("RUNNING sh_glred (NORMAL H G T)")\n    if ask_yes_no("Run htoglb (H) as well? Choose yes for fresh processing", "yes"):\n        options = "H G T"\n    else:\n        options = "G T"\n\n    save_globk_run_settings(\n        project_dir=project_dir,\n        log_dir=log_dir,\n        year=year,\n        start_doy=start_doy,\n        end_doy=end_doy,\n        ndays=ndays,\n        expt=expt,\n        netext=netext,\n        doys=doys,\n        local_stations=local_stations,\n        apr_path=apr_path,\n        eq_path=eq_path,\n        frame_name=frame_name,\n        stab_sites=stab_sites,\n        options=options,\n    )\n\n    rc = run_sh_glred(project_dir, year, start_doy, end_doy, expt, netext, options, log_dir)\n    if rc != 0:\n        print_warning(f"sh_glred returned code {rc}. Check logs.")\n\n    print_header("VERIFYING DAILY .org FILES")\n    org_files = verify_org_files(project_dir, expt, yy, doys)\n\n    if org_files:\n        print_success(f"Found {len(org_files)} daily .org files.")\n        for f in org_files:\n            print(f"  {f.name}")\n    else:\n        print_warning("No daily .org files found.")\n        print_info("Check sh_glred log and gsoln/*.prt/*.log files.")\n        if not ask_yes_no("Continue anyway?", "no"):\n            return 1\n\n    globk_stage_gate("combine")\n    print_header("OPTIONAL COMBINED SURVEY")\n    # FIX 1: initialize comb_org before use\n    comb_org: List[Path] = find_combined_org(project_dir, expt, yy, start_doy, end_doy)\n\n    if comb_org:\n        print_info(f"Existing combined .org found: {comb_org[0].name}")\n\n    if ndays > 1 and org_files:\n        if ask_yes_no("Run/re-run combined survey with COMB + -ncomb?", "yes"):\n            rc_comb = run_combined_survey(project_dir, year, start_doy, end_doy, expt, netext, ndays, log_dir)\n            if rc_comb == 0:\n                print_success("Combined survey completed.")\n                comb_org = find_combined_org(project_dir, expt, yy, start_doy, end_doy)\n                if comb_org:\n                    print_success(f"Combined .org file created: {comb_org[0].name}")\n                else:\n                    print_warning("Combined .org file not found.")\n            else:\n                print_warning(f"Combined survey returned {rc_comb}.")\n\n    diagnose_globk_chisquare_and_outputs(project_dir, log_dir, comb_org, expt, yy, start_doy, end_doy)\n    combined_main = comb_org[0] if comb_org else None\n    extracted_apr = run_sh_exglk_apr_extraction(project_dir, combined_main, log_dir)\n    vel_file = run_sh_org2vel_velocity(project_dir, combined_main, log_dir)\n    plate_outputs = collect_plate_frame_outputs(project_dir, log_dir)\n    psbase_summary = collect_psbase_position_error_outputs(project_dir, log_dir)\n    run_optional_sh_plotvel_map(project_dir, combined_main, vel_file, log_dir)\n    write_doc51_doc76_notes(project_dir, log_dir)\n\n    globk_stage_gate("outputs")\n    print_final_results_dashboard(\n        project_dir=project_dir,\n        year=year,\n        start_doy=start_doy,\n        end_doy=end_doy,\n        expt=expt,\n        yy=yy,\n        local_stations=local_stations,\n        daily_org_files=org_files,\n        comb_org=comb_org,\n        log_dir=log_dir,\n        apr_path=apr_path,\n        frame_name=frame_name,\n    )\n\n    write_final_processing_report(\n        project_dir=project_dir,\n        log_dir=log_dir,\n        year=year,\n        start_doy=start_doy,\n        end_doy=end_doy,\n        expt=expt,\n        yy=yy,\n        local_stations=local_stations,\n        daily_org_files=org_files,\n        comb_org=comb_org,\n        apr_path=apr_path,\n        eq_path=eq_path,\n        frame_name=frame_name,\n    )\n\n    print_header("FINISHED")\n    print_info("Important results were printed above.")\n    print_info("Final coordinates are in the combined .org file and CSV if extraction succeeded.")\n    print_info("Do NOT run glorg manually on the .org file.")\n    print_info("Frame note: GAMIT h-files are loose/floating daily solutions; GLORG realizes the final frame using APR + stabilization/generalized constraints.")\n    print_success(f"Logs saved in: {log_dir}")\n    return 0\n\n\nif __name__ == "__main__":\n    try:\n        sys.exit(main())\n    except KeyboardInterrupt:\n        print("\\nUser stopped.")\n        sys.exit(130)'

class Colors:
    RED = "\033[91m"
    GREEN = "\033[92m"
    YELLOW = "\033[93m"
    BLUE = "\033[94m"
    CYAN = "\033[96m"
    BOLD = "\033[1m"
    END = "\033[0m"


def ctext(text: str, color: str) -> str:
    return f"{color}{text}{Colors.END}"


def print_header(text: str) -> None:
    print()
    print(ctext("=" * 90, Colors.CYAN))
    print(ctext(f"{text:^90}", Colors.CYAN + Colors.BOLD))
    print(ctext("=" * 90, Colors.CYAN))


def ask_yes_no(question: str, default: str = "yes") -> bool:
    default = default.lower().strip()
    prompt = "[Y/n]" if default == "yes" else "[y/N]"
    while True:
        ans = input(ctext(f"{question} {prompt}: ", Colors.CYAN)).strip().lower()
        if ans == "":
            return default == "yes"
        if ans in ("y", "yes"):
            return True
        if ans in ("n", "no"):
            return False
        print("Please answer yes or no.")


def ask_choice() -> int:
    print_header("AUTOM-GAMIT + GLOBK/GLORG INTEGRATED MENU")
    print("1. Run GAMIT only")
    print("2. Run GLOBK/GLORG only")
    print("3. Run full GAMIT first, then GLOBK/GLORG dashboard")
    while True:
        ans = input(ctext("\nEnter choice (1-3) [3]: ", Colors.CYAN)).strip()
        if ans == "":
            return 3
        if ans in ("1", "2", "3"):
            return int(ans)
        print("Please enter 1, 2, or 3.")


def _load_part(source: str, module_name: str, file_label: str) -> dict:
    compile(source, file_label, "exec")
    ns = {"__name__": module_name, "__file__": file_label}
    exec(source, ns)
    return ns


def _run_part(source: str, module_name: str, file_label: str) -> int:
    try:
        ns = _load_part(source, module_name, file_label)
        main_func = ns.get("main")
        if main_func is None:
            print(ctext(f"ERROR: main() not found in {file_label}", Colors.RED))
            return 1
        result = main_func()
        return 0 if result is None else int(result)
    except SystemExit as e:
        if e.code is None:
            return 0
        try:
            return int(e.code)
        except Exception:
            return 1
    except KeyboardInterrupt:
        print("\nUser stopped the program.")
        return 130
    except Exception:
        print(ctext("ERROR: Unexpected error while running integrated part.", Colors.RED))
        traceback.print_exc()
        return 1


def verify_final_code() -> int:
    checks = []
    def add(label: str, ok: bool, detail: str = "") -> None:
        checks.append((label, bool(ok), detail))
    try:
        compile(GAMIT_SOURCE, "integrated_gamit_part.py", "exec")
        add("embedded GAMIT syntax", True)
    except Exception as e:
        add("embedded GAMIT syntax", False, str(e))
    try:
        compile(GLOBK_SOURCE, "integrated_globk_part.py", "exec")
        add("embedded GLOBK syntax", True)
    except Exception as e:
        add("embedded GLOBK syntax", False, str(e))
    add("manual/CSV antenna height apply", "apply_manual_antenna_heights_to_station_info" in GAMIT_SOURCE and "CSV heights were applied" in GAMIT_SOURCE)
    add("netrc multi-host check", "gdc.cddis.eosdis.nasa.gov" in GAMIT_SOURCE and "cddis.nasa.gov" in GAMIT_SOURCE)
    add("CDDIS mirror fallback", "alternate CDDIS host/mirror" in GAMIT_SOURCE and "--http1.1 --ipv4" in GAMIT_SOURCE)
    add("fallback IGS references", "try_fallback_reference_sites" in GAMIT_SOURCE and "FALLBACK_IGS_SITES" in GAMIT_SOURCE)
    add("JSON config support", "load_runtime_config_from_argv" in GAMIT_SOURCE and "--write-template-config" in GAMIT_SOURCE)
    add("stage pause menu", "Pause before/after every processing stage" in GAMIT_SOURCE)
    add("recommended noftp mode", "PREFETCH_IGSF_NOFTP" in GAMIT_SOURCE and "-orbit igsf -noftp -pres ELEV" in GAMIT_SOURCE)
    add("GLOBK dashboard", "make_persistent_pos_files" in GLOBK_SOURCE and "sh_exglk" in GLOBK_SOURCE and "sh_org2vel" in GLOBK_SOURCE)
    print_header("FINAL CODE SELF-VERIFICATION")
    failed = 0
    for label, ok, detail in checks:
        print(ctext(f"{label}: {ok}", Colors.GREEN if ok else Colors.RED) + (f"  {detail}" if detail else ""))
        if not ok:
            failed += 1
    if failed:
        print(ctext(f"FINAL CODE VERIFICATION FAILED: {failed} check(s)", Colors.RED))
        return 1
    print(ctext("FINAL CODE INSTALLED AND VERIFIED", Colors.GREEN + Colors.BOLD))
    return 0


def run_gamit() -> int:
    print_header("STARTING PART 1: GAMIT")
    return _run_part(GAMIT_SOURCE, "__integrated_gamit_part__", "integrated_gamit_part.py")


def run_globk() -> int:
    print_header("STARTING PART 2: GLOBK/GLORG DASHBOARD")
    return _run_part(GLOBK_SOURCE, "__integrated_globk_part__", "integrated_globk_part.py")


def main() -> int:
    if any(arg in ("--verify", "--self-check", "--self-test") for arg in sys.argv[1:]):
        return verify_final_code()
    if any(arg == "--dry-run" for arg in sys.argv[1:]):
        os.environ["AUTOM_GAMIT_DRY_RUN"] = "1"
        print(ctext("DRY-RUN / COMMAND-PREVIEW MODE ENABLED.", Colors.YELLOW))
    choice = ask_choice()
    if choice == 1:
        return run_gamit()
    if choice == 2:
        return run_globk()
    gamit_rc = run_gamit()
    if gamit_rc != 0:
        print(ctext(f"GAMIT part ended with return code {gamit_rc}.", Colors.YELLOW))
        if not ask_yes_no("Run GLOBK/GLORG anyway?", "no"):
            return gamit_rc
    print()
    print(ctext("GAMIT part finished. Now starting GLOBK/GLORG dashboard.", Colors.GREEN))
    return run_globk()


if __name__ == "__main__":
    sys.exit(main())
